                        const newConfig = [...template.config];
                        newConfig[catIdx].name = e.target.value;
                        setTemplate({ ...template, config: newConfig });
                      }}
                    />
                  </div>
                  <div className="space-y-2">
                    {cat.fields.map((field, fieldIdx) => (
                      <div key={fieldIdx} className="flex gap-2">
