export const uploadOrderAttachment = async (file: File): Promise<string | null> => {
    const fileExt = file.name.split('.').pop();
    const fileName = `${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;
    const { error } = await supabase.storage.from('order-attachments').upload(fileName, file);
    if (error) return null;
    const { data } = supabase.storage.from('order-attachments').getPublicUrl(fileName);
    return data.publicUrl;
};

import React, { useState, useEffect } from 'react';
import { X, Plus, PlusCircle, ArrowLeftRight, Trash2, Upload, ImageIcon, Send, Loader2, BookOpen } from 'lucide-react';
import { Unit, SizeBreakdown, Attachment, Style } from '../../types';
import { createOrder, uploadOrderAttachment, triggerOrderEmail, fetchStyles } from '../../services/db';

interface LaunchOrderModalProps {
  isOpen: boolean;
  onClose: () => void;
  units: Unit[];
  onSuccess: () => void;
}

export const LaunchOrderModal: React.FC<LaunchOrderModalProps> = ({ isOpen, onClose, units, onSuccess }) => {
  const [isUploading, setIsUploading] = useState(false);
  const [useNumericSizes, setUseNumericSizes] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [availableStyles, setAvailableStyles] = useState<Style[]>([]);
  const [newOrder, setNewOrder] = useState({ style_number: '', style_id: '', unit_id: 1, target_delivery_date: '', description: '', box_count: 0 });
  const [breakdown, setBreakdown] = useState<SizeBreakdown[]>([{ color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }]);

  useEffect(() => {
    if (isOpen) {
      fetchStyles().then(setAvailableStyles);
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleStyleSelect = (styleId: string) => {
    const style = availableStyles.find(s => s.id === styleId);
    if (!style) {
      setNewOrder({ ...newOrder, style_id: '', style_number: '' });
      return;
    }

    // Autofill Logic
    setNewOrder({
      ...newOrder,
      style_id: style.id,
      style_number: `${style.style_number} - ${style.style_text}`
    });

    setUseNumericSizes(style.size_type === 'number');

    if (style.available_colors && style.available_colors.length > 0) {
      const newBreakdown = style.available_colors
        .filter(c => c.trim() !== '')
        .map(color => ({
          color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0
        }));
      if (newBreakdown.length > 0) setBreakdown(newBreakdown);
    }
  };

  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getRowTotal(row), 0);
  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const quantity = getTotalQuantity(breakdown);
    if (quantity === 0) return alert("Total quantity cannot be zero");

    setIsUploading(true);
    try {
      const attachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) attachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }

      const { data, error } = await createOrder({ ...newOrder, quantity, size_breakdown: breakdown, attachments, size_format: useNumericSizes ? 'numeric' : 'standard' });
      if (data) {
        await triggerOrderEmail(data.id, false);
        onSuccess();
        onClose();
      } else {
        alert(`Error: ${error}`);
      }
    } catch (err: any) {
      alert(`Failed: ${err.message}`);
    } finally {
      setIsUploading(false);
    }
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <h3 className="text-2xl font-black text-slate-800 tracking-tight flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-lg shadow-lg"><Plus size={24}/></div>
            Launch Production Order
          </h3>
          <button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={32}/></button>
        </div>
        <form onSubmit={handleSubmit} className="flex-1 overflow-y-auto p-8 space-y-8">

          {/* Style Selection Top Dropdown */}
          <div className="bg-indigo-50/50 p-6 rounded-2xl border border-indigo-100 flex flex-col md:flex-row items-center gap-6">
            <div className="flex items-center gap-3 shrink-0">
               <div className="p-3 bg-white rounded-xl text-indigo-600 shadow-sm border border-indigo-50">
                 <BookOpen size={24}/>
               </div>
               <div>
                 <h4 className="font-black text-indigo-900 text-sm uppercase tracking-tight leading-none">Auto-Fill from Database</h4>
                 <p className="text-indigo-400 text-[10px] font-bold uppercase tracking-widest mt-1">Link this order to a technical style</p>
               </div>
            </div>
            <div className="flex-1 w-full">
              <select 
                className="w-full bg-white border-2 border-indigo-200 rounded-xl px-5 py-4 text-sm font-black text-indigo-700 outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-sm"
                value={newOrder.style_id}
                onChange={e => handleStyleSelect(e.target.value)}
              >
                <option value="">-- [OPTIONAL] Select Style from Technical DB --</option>
                {availableStyles.map(s => (
                  <option key={s.id} value={s.id}>{s.style_number} - {s.style_text}</option>
                ))}
              </select>
            </div>
          </div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Style Reference</label><input required className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.style_number} onChange={e => setNewOrder({...newOrder, style_number: e.target.value})}/></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Assign Facility</label><select className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.unit_id} onChange={e => setNewOrder({...newOrder, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Planned Box Count</label><input required type="number" min="1" className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-black focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.box_count} onChange={e => setNewOrder({...newOrder, box_count: parseInt(e.target.value) || 0})}/></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Delivery Due</label><input required type="date" className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none" value={newOrder.target_delivery_date} onChange={e => setNewOrder({...newOrder, target_delivery_date: e.target.value})}/></div>
          </div>
          <div>
            <div className="flex justify-between items-center mb-4"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Color & Size Matrix</label><button type="button" onClick={() => setUseNumericSizes(!useNumericSizes)} className="text-[10px] font-black bg-indigo-50 text-indigo-600 px-5 py-2 rounded-xl border border-indigo-100 uppercase tracking-widest transition-all"><ArrowLeftRight size={14} className="inline mr-2"/> Format: {useNumericSizes ? '65-90' : 'S-3XL'}</button></div>
            <div className="border border-slate-200 rounded-2xl overflow-hidden bg-white shadow-lg">
              <table className="w-full text-center text-sm border-collapse">
                <thead className="bg-slate-50 text-slate-400 font-black uppercase text-[10px] tracking-widest border-b"><tr><th className="p-4 text-left border-r">Color Variant</th>{getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}<th className="p-4 bg-slate-100">Row Sum</th><th className="p-4 w-12"></th></tr></thead>
                <tbody className="divide-y divide-slate-100">{breakdown.map((row, idx) => (
                  <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                    <td className="p-3 border-r"><input placeholder="e.g. Navy" className="w-full border-2 border-slate-50 rounded-xl px-4 py-3 bg-white focus:ring-2 focus:ring-indigo-500 font-bold outline-none" value={row.color} onChange={e => { const nb = [...breakdown]; nb[idx].color = e.target.value; setBreakdown(nb); }}/></td>
                    {['s','m','l','xl','xxl','xxxl'].map(sz => (<td key={sz} className="p-3 border-r"><input type="number" className="w-full border-2 border-slate-50 rounded-xl px-2 py-3 text-center bg-white focus:ring-2 focus:ring-indigo-500 font-black outline-none" value={(row as any)[sz] || ''} onChange={e => { const nb = [...breakdown]; (nb[idx] as any)[sz] = parseInt(e.target.value) || 0; setBreakdown(nb); }}/></td>))}
                    <td className="p-3 font-black text-indigo-700 bg-slate-50/50 tabular-nums text-lg">{getRowTotal(row)}</td>
                    <td className="p-3">{breakdown.length > 1 && <button type="button" onClick={() => setBreakdown(breakdown.filter((_, i) => i !== idx))} className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20}/></button>}</td>
                  </tr>))}
                </tbody></table>
              <button type="button" onClick={() => setBreakdown([...breakdown, { color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }])} className="w-full py-5 text-[10px] font-black text-indigo-600 hover:bg-indigo-50 border-t border-slate-100 transition-colors bg-slate-50/20 uppercase tracking-widest flex items-center justify-center gap-2"><PlusCircle size={16}/> Add New Color Variant</button>
            </div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Production Notes</label><textarea className="w-full border-2 border-slate-100 rounded-3xl p-6 h-48 focus:ring-2 focus:ring-indigo-500 outline-none transition-all" value={newOrder.description} onChange={e => setNewOrder({...newOrder, description: e.target.value})}></textarea></div>
            <div><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-3 ml-1">Technical Attachments</label>
              <div className="border-4 border-dashed border-slate-100 rounded-3xl p-8 bg-slate-50 hover:bg-indigo-50/30 hover:border-indigo-200 relative h-48 flex flex-col items-center justify-center cursor-pointer transition-all">
                <input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/>
                <Upload size={48} className="text-slate-300 mb-3" /><p className="text-base font-black text-slate-700 uppercase">Drop Techpacks</p>
              </div>
              <div className="mt-4 flex flex-wrap gap-2">{selectedFiles.map((f, i) => (<div key={i} className="flex items-center gap-2 bg-indigo-600 text-white px-3 py-1.5 rounded-lg text-xs font-black shadow-md"><ImageIcon size={14}/> {f.name} <button type="button" onClick={() => setSelectedFiles(prev => prev.filter((_, idx) => idx !== i))}><X size={14}/></button></div>))}</div>
            </div>
          </div>
          <div className="flex justify-end gap-4 pt-8 border-t">
            <button type="button" onClick={onClose} className="px-10 py-4 font-black text-slate-400 hover:bg-slate-100 rounded-2xl uppercase tracking-widest text-xs">Discard</button>
            <button type="submit" disabled={isUploading} className="px-12 py-4 bg-indigo-600 text-white rounded-2xl font-black shadow-2xl shadow-indigo-200 flex items-center gap-3 transition-all active:scale-95 disabled:opacity-50 uppercase tracking-widest text-xs">
              {isUploading ? <Loader2 size={20} className="animate-spin" /> : <Send size={18}/>} Launch Order
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Pencil, Trash2, Printer, Save, Loader2, Clock, Paperclip, Box, Image as ImageIcon, FileText, Download, ArrowLeftRight, Upload, BookOpen } from 'lucide-react';
import { Order, Unit, OrderLog, SizeBreakdown, Attachment, OrderStatus, formatOrderNumber, Style, StyleTemplate } from '../../types';
import { fetchOrderLogs, updateOrderDetails, deleteOrder, triggerOrderEmail, uploadOrderAttachment, fetchStyleById, fetchStyleTemplate } from '../../services/db';

interface AdminOrderDetailsModalProps {
  order: Order;
  units: Unit[];
  onClose: () => void;
  onRefresh: () => void;
}

export const AdminOrderDetailsModal: React.FC<AdminOrderDetailsModalProps> = ({ order, units, onClose, onRefresh }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [editFormData, setEditFormData] = useState<Partial<Order>>({ ...order });
  const [modalLogs, setModalLogs] = useState<OrderLog[]>([]);
  const [useNumericSizes, setUseNumericSizes] = useState(order.size_format === 'numeric');
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);

  useEffect(() => {
    fetchOrderLogs(order.id).then(setModalLogs);
  }, [order.id]);

  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getRowTotal(row), 0);
  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

  const handleSave = async () => {
    setIsUploading(true);
    try {
      const newAttachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) newAttachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }
      const finalAttachments = [...(editFormData.attachments || []), ...newAttachments];
      const finalQty = getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]);
      const result = await updateOrderDetails(order.id, { ...editFormData, quantity: finalQty, attachments: finalAttachments, size_format: useNumericSizes ? 'numeric' : 'standard' });
      if (result.success) {
        await triggerOrderEmail(order.id, true);
        onRefresh();
        onClose();
      }
    } finally {
      setIsUploading(false);
    }
  };

  const handlePrint = async () => {
    let techPackHtml = '';

    if (order.style_id) {
        const [style, template] = await Promise.all([
            fetchStyleById(order.style_id),
            fetchStyleTemplate()
        ]);

        if (style && template) {
            techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                const isPreProd = cat.name.toLowerCase().includes('pre production');
                const variantMetaHtml = isPreProd ? `
                    <div style="background:#f9f9f9; border:1px solid #eee; padding:15px; border-radius:4px; margin-bottom:20px; display:grid; grid-template-columns:1fr 1fr; gap:20px;">
                       <div><span style="font-size:10px; font-weight:bold; color:#888; text-transform:uppercase;">Blueprint Colours</span><br/><strong>${style.available_colors?.join(', ') || '---'}</strong></div>
                       <div><span style="font-size:10px; font-weight:bold; color:#888; text-transform:uppercase;">Size Breakdown</span><br/><strong>${style.available_sizes?.join(', ') || '---'} (${style.size_type})</strong></div>
                    </div>
                ` : '';

                const fields = cat.fields.map(f => {
                    const data = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                    const imagesHtml = data.attachments.filter(a => a.type === 'image').map(img => `
                        <div style="border:1px solid #ddd; padding:10px; text-align:center; break-inside:avoid;">
                            <img src="${img.url}" style="max-width:100%; max-height:400px; border-radius:4px;" />
                            <div style="font-size:10px; margin-top:5px; font-weight:bold;">${img.name}</div>
                        </div>
                    `).join('');
                    return `<div style="margin-bottom:20px; border-bottom:1px solid #eee; padding-bottom:10px; break-inside:avoid;"><div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:4px;">${f}</div><div style="font-size:14px; font-weight:500;">${data.text || '---'}</div>${imagesHtml ? `<div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:10px;">${imagesHtml}</div>` : ''}</div>`;
                }).join('');

                return `<div style="margin-top:40px; page-break-before:always;"><h3 style="background:#000; color:#fff; padding:10px; font-size:14px; text-transform:uppercase; letter-spacing:1px;">${cat.name} (Style DB)</h3><div style="padding:10px;">${variantMetaHtml}${fields}</div></div>`;
            }).join('');
        }
    }

    const formattedNo = formatOrderNumber(order);
    const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
    const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold;">${getRowTotal(row)}</td></tr>`).join('');

    const win = window.open('', 'OrderPrint', 'width=1000,height=800');
    if (win) {
        win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title><style>body { font-family: sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 5px solid #000; padding-bottom: 20px; margin-bottom: 30px; } .brand { font-size: 32px; font-weight: 900; } .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; } .box { padding: 15px; border: 2px solid #333; } .label { font-size: 10px; font-weight: bold; color: #666; text-transform: uppercase; } .value { font-size: 18px; font-weight: bold; } table { width: 100%; border-collapse: collapse; margin-top: 20px; } th, td { border: 1px solid #333; padding: 12px; text-align: center; } th { background: #f0f0f0; } .section-title { font-size: 18px; font-weight: 900; border-bottom: 3px solid #333; margin-top: 40px; margin-bottom: 15px; text-transform: uppercase; }</style></head><body><div class="header"><div class="brand">TINTURA SST</div><div>Manufacturing Job Sheet</div></div><div class="grid"><div class="box"><span class="label">Order</span><div class="value">${formattedNo}</div></div><div class="box"><span class="label">Style</span><div class="value">${order.style_number}</div></div><div class="box"><span class="label">Qty</span><div class="value">${order.quantity} PCS</div></div></div><div class="section-title">Size Matrix</div><table><thead><tr><th style="text-align:left;">Color</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Total</th></tr></thead><tbody>${breakdownRows}</tbody></table><div class="section-title">Production Notes</div><div style="padding:15px; border:2px solid #333;">${order.description || 'N/A'}</div>${techPackHtml}<script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script></body></html>`);
        win.document.close();
    }
  };

  const renderDetailCell = (rowIdx: number, sizeKey: keyof SizeBreakdown) => {
    const plannedVal = order.size_breakdown?.[rowIdx]?.[sizeKey] || 0;
    const actualVal = order.completion_breakdown?.[rowIdx]?.[sizeKey] || 0;
    if (order.status !== OrderStatus.COMPLETED || !order.completion_breakdown) return <span className="text-slate-600">{plannedVal}</span>;
    return (
      <div className="flex flex-col items-center p-1 bg-slate-50 rounded border">
        <span className={`text-lg font-black ${actualVal !== plannedVal ? 'text-indigo-700' : ''}`}>{actualVal}</span>
        <span className="text-[9px] text-slate-400 font-bold">Plan: {plannedVal}</span>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-start bg-white">
          <div><h3 className="text-3xl font-black text-slate-800 tracking-tight">{formatOrderNumber(order)}</h3></div>
          <div className="flex items-center gap-3">
            {!isEditing && <button onClick={() => setIsEditing(true)} className="bg-indigo-50 text-indigo-700 border border-indigo-100 px-5 py-2.5 rounded-xl text-sm font-black hover:bg-indigo-600 hover:text-white transition-all"><Pencil size={18} /> Modify Order</button>}
            <button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full"><X size={32}/></button>
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8">

          {/* Linked Style Indicator */}
          {order.style_id && (
            <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 flex items-center gap-3">
                <BookOpen size={20} className="text-indigo-600"/>
                <div>
                  <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest leading-none">Linked Style DB Asset</p>
                  <p className="text-sm font-bold text-indigo-900 mt-1">This order is connected to the Technical Blueprint. Printing will include the master Tech Pack.</p>
                </div>
            </div>
          )}

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
            <div className="p-5 bg-slate-50 rounded-2xl border">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Volume</span>
              <div className="text-2xl font-black text-slate-800">{isEditing ? getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]) : order.quantity} PCS</div>
            </div>
            <div className="p-5 bg-slate-50 rounded-2xl border">
              <span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Delivery</span>
              {isEditing ? <input type="date" className="w-full border rounded p-2" value={editFormData.target_delivery_date} onChange={e => setEditFormData({...editFormData, target_delivery_date: e.target.value})}/> : <div className="text-lg font-black">{order.target_delivery_date}</div>}
            </div>
            <div className="p-5 bg-slate-50 rounded-2xl border"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2"><Box size={10}/> Planned Boxes</span>{isEditing ? <input type="number" className="w-full border rounded p-2" value={editFormData.box_count} onChange={e => setEditFormData({...editFormData, box_count: parseInt(e.target.value) || 0})}/> : <div className="text-lg font-black">{order.box_count}</div>}</div>
            <div className="p-5 bg-indigo-50 rounded-2xl border"><span className="block text-[10px] text-indigo-400 uppercase font-black mb-2">Unit</span>{isEditing ? <select className="w-full border rounded p-2 bg-white" value={editFormData.unit_id} onChange={e => setEditFormData({...editFormData, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select> : <div className="text-lg font-black text-indigo-900">{units.find(u => u.id === order.unit_id)?.name}</div>}</div>
          </div>

          <div>
            <div className="flex justify-between items-center mb-4"><h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product Breakdown Matrix</h4>{isEditing && <button type="button" onClick={() => setUseNumericSizes(!useNumericSizes)} className="text-[10px] bg-slate-100 px-4 py-2 rounded-xl border font-black uppercase"><ArrowLeftRight size={14} className="inline mr-2"/> Format Toggle</button>}</div>
            <div className="border rounded-2xl overflow-hidden shadow-lg"><table className="w-full text-center text-sm border-collapse"><thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b"><tr><th className="p-4 text-left border-r">Color Variant</th>{getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}<th className="p-4 bg-slate-100">Sum</th>{isEditing && <th className="p-4 w-12"></th>}</tr></thead><tbody className="divide-y divide-slate-100">
              {(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (
                <tr key={idx} className="hover:bg-slate-50/50">
                  <td className="p-4 text-left font-black text-slate-700 border-r">{isEditing ? <input className="w-full border rounded p-1" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : row.color}</td>
                  {['s','m','l','xl','xxl','xxxl'].map(key => (<td key={key} className="p-4 border-r">{isEditing ? <input type="number" className="w-16 border rounded p-1 text-center" value={(row as any)[key]} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; (bd[idx] as any)[key] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : renderDetailCell(idx, key as keyof SizeBreakdown)}</td>))}
                  <td className="p-4 font-black text-slate-900 bg-slate-50/50">{getRowTotal(row)}</td>
                  {isEditing && <td className="p-4"><button onClick={() => setEditFormData({...editFormData, size_breakdown: (editFormData.size_breakdown || []).filter((_, i) => i !== idx)})} className="text-red-400 hover:text-red-600"><Trash2 size={20}/></button></td>}
                </tr>))}
            </tbody></table>{isEditing && <button onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }]})} className="w-full py-4 bg-slate-50 text-indigo-600 text-xs font-black uppercase border-t">+ Add Variant</button>}</div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="p-6 bg-slate-50/50 rounded-2xl border shadow-inner">
              <span className="block text-[11px] text-slate-400 uppercase font-black mb-3">Instructions</span>
              {isEditing ? <textarea className="w-full border rounded-2xl p-4 h-48" value={editFormData.description} onChange={e => setEditFormData({...editFormData, description: e.target.value})}/> : <p className="text-base text-slate-600 whitespace-pre-wrap">{order.description}</p>}
            </div>
            <div className="p-6 bg-indigo-50/30 rounded-2xl border shadow-inner">
              <h4 className="font-black text-indigo-400 uppercase text-[10px] flex items-center gap-2 mb-4"><Paperclip size={14}/> Documentation</h4>
              <div className="space-y-3">
                {(isEditing ? editFormData.attachments : order.attachments)?.map((att, i) => (
                  <div key={i} className="flex items-center justify-between p-4 bg-white rounded-xl border group">
                    <a href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-4 flex-1">{att.type === 'image' ? <ImageIcon size={20} /> : <FileText size={20} />}<span className="text-sm font-bold truncate">{att.name}</span></a>
                    {isEditing && <button onClick={() => setEditFormData({...editFormData, attachments: (editFormData.attachments || []).filter((_, idx) => idx !== i)})} className="text-slate-300 hover:text-red-500"><Trash2 size={20}/></button>}
                  </div>
                ))}
                {isEditing && <div className="mt-4 border-2 border-dashed rounded-2xl p-6 text-center relative hover:bg-white transition-all cursor-pointer"><input type="file" multiple className="absolute inset-0 opacity-0" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/><Upload size={32} className="mx-auto text-indigo-400"/><p className="text-xs font-black text-indigo-600 uppercase">Add Files</p></div>}
              </div>
            </div>
          </div>

          <div className="p-6 bg-indigo-50/30 rounded-3xl border shadow-inner flex flex-col">
            <h4 className="font-black text-indigo-900 uppercase text-[10px] flex items-center gap-2 mb-6"><Clock size={16}/> Lifecycle Log</h4>
            <div className="space-y-6 max-h-[400px] overflow-y-auto pr-4">
              {modalLogs.map(log => (<div key={log.id} className="flex gap-4 border-l-4 border-indigo-100 pl-6 pb-2 transition-all hover:border-indigo-400"><div className="font-black text-[10px] text-slate-400 uppercase leading-none pt-1">{new Date(log.created_at).toLocaleDateString()}<br/><span className="text-indigo-400 opacity-60">{new Date(log.created_at).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></div><div className="flex-1 bg-white p-4 rounded-2xl shadow-sm border"><p className="text-slate-700 font-bold leading-snug">{log.message}</p></div></div>))}
            </div>
          </div>
        </div>
        <div className="p-6 border-t bg-slate-50 flex justify-between items-center">
          <button onClick={() => { if(confirm("Delete?")) deleteOrder(order.id).then(() => {onRefresh(); onClose();}); }} className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all"><Trash2 size={24}/></button>
          <div className="flex items-center gap-4">
            <button onClick={handlePrint} className="px-8 py-3 bg-white text-indigo-600 border-2 border-indigo-600 rounded-xl font-black uppercase text-xs flex items-center gap-2">
              <Printer size={16}/> Print Job Sheet
            </button>
            <button onClick={onClose} className="px-10 py-3 bg-slate-800 text-white rounded-xl font-black uppercase text-xs">Close</button>
            {isEditing && <button onClick={handleSave} disabled={isUploading} className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black uppercase text-xs">{isUploading ? 'Saving...' : 'Save Job'}</button>}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleById, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC && order.status !== OrderStatus.QC_APPROVED) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }))
                : [{ color: 'Standard', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actualBoxCount });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  const handleDeleteRequest = async (id: string) => {
      if (!confirm("Are you sure?")) return;
      await deleteMaterialRequest(id);
      handleOpenMaterialHistory();
  };

  const handleEditRequest = (req: MaterialRequest) => {
      setIsEditingRequest({ id: req.id, originalData: req });
      setMaterialModal(req.order_id);
      setShowMaterialHistory(false);
  };

  const handleGenerateAndPrintBarcodes = async (qty: number, size: string) => {
    if (!barcodeModal) return;
    const newBarcodes = await generateBarcodes(barcodeModal.orderId, qty, barcodeModal.style, size);
    setBarcodeModal(null);
    const win = window.open('', 'PrintBarcodes', 'width=1000,height=800');
    if (win) {
        const labelsHtml = newBarcodes.map(b => `<div class="label"><div class="header">TINTURA SST</div><div class="meta"><strong>Style:</strong> ${b.style_number} &nbsp; <strong>Size:</strong> ${b.size}</div><svg class="barcode" jsbarcode-format="CODE128" jsbarcode-value="${b.barcode_serial}" jsbarcode-textmargin="0" jsbarcode-fontoptions="bold" jsbarcode-height="40" jsbarcode-width="2" jsbarcode-displayValue="true" jsbarcode-fontSize="11"></svg></div>`).join('');
        win.document.write(`<html><head><title>Print Labels</title><script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script><style>@page { size: A4; margin: 10mm; } body { margin: 0; font-family: sans-serif; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-auto-rows: 35mm; column-gap: 5mm; row-gap: 2mm; } .label { border: 1px dashed #ddd; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 5px; overflow: hidden; text-align: center; background: white; } .header { font-size: 10px; font-weight: bold; text-transform: uppercase; margin: 2px; } .meta { font-size: 10px; margin-bottom: 2px; color: #333; } svg { max-width: 95%; height: auto; display: block; }</style></head><body><div class="grid">${labelsHtml}</div><script>window.onload = function() { JsBarcode(".barcode").init(); setTimeout(() => { window.print(); }, 500); }</script></body></html>`); 
        win.document.close();
    }
  };

  const handlePrintOrderSheet = async (order: Order) => {
      let techPackHtml = '';

      // Fetch Tech Pack if style_id is available
      if (order.style_id) {
          const [style, template] = await Promise.all([
              fetchStyleById(order.style_id),
              fetchStyleTemplate()
          ]);

          if (style && template) {
              techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                  const fields = cat.fields.map(f => {
                      const data = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                      const imagesHtml = data.attachments.filter(a => a.type === 'image').map(img => `
                        <div style="border:1px solid #ddd; padding:10px; text-align:center; break-inside:avoid;">
                          <img src="${img.url}" style="max-width:100%; max-height:400px; border-radius:4px;" />
                          <div style="font-size:10px; margin-top:5px; font-weight:bold;">${img.name}</div>
                        </div>
                      `).join('');

                      return `
                        <div style="margin-bottom:20px; border-bottom:1px solid #eee; padding-bottom:10px; break-inside:avoid;">
                          <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:4px;">${f}</div>
                          <div style="font-size:14px; font-weight:500;">${data.text || '---'}</div>
                          ${imagesHtml ? `<div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:10px;">${imagesHtml}</div>` : ''}
                        </div>
                      `;
                  }).join('');

                  return `
                    <div style="margin-top:40px; page-break-before:always;">
                      <h3 style="background:#000; color:#fff; padding:10px; font-size:14px; text-transform:uppercase; letter-spacing:1px;">${cat.name} (Style Database Reference)</h3>
                      <div style="padding:10px;">${fields}</div>
                    </div>
                  `;
              }).join('');
          }
      }

      const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
      const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
      const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
      const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold;">${getRowTotal(row)}</td></tr>`).join('');
      const formattedNo = formatOrderNumber(order);

      let attachmentHtml = '';
      if (order.attachments && order.attachments.length > 0) {
          attachmentHtml = `<div class="section-title">Technical Documents & References</div><div style="display:flex; flex-direction:column; gap:25px;">`;
          order.attachments.forEach(att => {
              if (att.type === 'image') {
                  attachmentHtml += `<div style="border:1px solid #ccc; padding:15px; width:100%; text-align:center;"><img src="${att.url}" style="max-width:100%; max-height:800px; border-radius:8px;" /><div style="font-size:12px; margin-top:10px; font-weight:bold; text-transform:uppercase; color:#666;">REF: ${att.name}</div></div>`;
              } else if (att.url.toLowerCase().endsWith('.pdf')) {
                  attachmentHtml += `<div style="border:2px solid #333; border-radius:8px; overflow:hidden; page-break-before:always;"><div style="background:#333; color:white; padding:10px; font-weight:bold; text-align:center; font-size:14px;">PDF DOCUMENT: ${att.name}</div><iframe src="${att.url}" style="width:100%; height:1000px; border:none;"></iframe></div>`;
              } else {
                  attachmentHtml += `<div style="border:1px dashed #ccc; padding:20px; background:#f9f9f9; text-align:center; border-radius:8px;"><strong>DOCUMENT:</strong> ${att.name}</div>`;
              }
          });
          attachmentHtml += `</div>`;
      }

      const win = window.open('', 'PrintOrderSheet', 'width=1000,height=800');
      if (win) {
          win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title><style>body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; } .header { text-align: center; border-bottom: 5px solid #000; padding-bottom: 20px; margin-bottom: 30px; } .brand { font-size: 42px; font-weight: 900; text-transform: uppercase; margin: 0; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #444; } .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; } .box { padding: 15px; border: 2px solid #333; border-radius: 6px; } .label { font-size: 11px; text-transform: uppercase; color: #666; font-weight: bold; } .value { font-size: 18px; font-weight: bold; } table { width: 100%; border-collapse: collapse; margin-top: 20px; } th, td { border: 1px solid #333; padding: 12px; text-align: center; } th { background: #f0f0f0; font-weight: 800; text-transform: uppercase; } .section-title { font-size: 18px; font-weight: 900; border-bottom: 3px solid #333; padding-bottom: 5px; margin-top: 40px; margin-bottom: 15px; text-transform: uppercase; }</style></head><body><div class="header"><div class="brand">TINTURA SST</div><div class="title">Manufacturing Job Sheet</div></div><div class="grid"><div class="box"><span class="label">Order Number</span><div class="value">${formattedNo}</div></div><div class="box"><span class="label">Style Number</span><div class="value">${order.style_number}</div></div><div class="box"><span class="label">Total Quantity</span><div class="value">${order.quantity} PCS</div></div><div class="box"><span class="label">Planned Boxes</span><div class="value">${order.box_count || '---'}</div></div><div class="box"><span class="label">Delivery Deadline</span><div class="value">${order.target_delivery_date}</div></div></div><div class="section-title">Size Matrix Breakdown</div><table><thead><tr><th style="text-align:left;">Color</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Total</th></tr></thead><tbody>${breakdownRows}</tbody></table><div class="section-title">Production Requirements</div><div style="padding: 20px; border: 2px solid #333; min-height: 80px; background:#fcfcfc; border-radius:6px; font-size:16px;">${order.description || "No specific manufacturing notes provided."}</div>${attachmentHtml}${techPackHtml}<script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script></body></html>`);
          win.document.close();
      }
  };

  const handlePrintAccessoriesReceipt = (order: Order, reqs: MaterialRequest[]) => {
      const formattedNo = formatOrderNumber(order);
      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `
            <tr>
                <td style="text-align:center;">${idx + 1}</td>
                <td>${req.material_content}</td>
                <td style="text-align:center;">${req.unit || 'Nos'}</td>
                <td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td>
            </tr>
          `).join('');

          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `
                <tr>
                    <td style="text-align:center;">${idx + 1}</td>
                    <td>${req.material_content}</td>
                    <td style="text-align:right;">${req.quantity_requested}</td>
                    <td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td>
                    <td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td>
                    <td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td>
                </tr>
              `;
          }).join('');

          const headerHTML = `
            <div class="header">
                <div class="brand">TINTURA SST</div>
                <div class="title">ACCESSORIES REQUIREMENT RECEIPT</div>
                <div class="meta">
                    ORDER NO: ${formattedNo} &nbsp;|&nbsp; 
                    STYLE: ${order.style_number} &nbsp;|&nbsp; 
                    DATE: ${new Date().toLocaleDateString()}
                </div>
            </div>
          `;

          win.document.write(`
            <html>
            <head>
                <title>Accessories Receipt - ${formattedNo}</title>
                <style>
                    @media print { 
                        .page-break { page-break-before: always; } 
                        body { -webkit-print-color-adjust: exact; }
                    }
                    body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; }
                    .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; }
                    .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; }
                    .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; }
                    .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; }
                    .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; }
                    table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; }
                    th, td { border: 1px solid #ccc; padding: 8px; }
                    th { background: #f4f4f4; text-transform: uppercase; }
                </style>
            </head>
            <body>
                <!-- PAGE 1 -->
                ${headerHTML}
                <div class="page-title">Page 1: Request Sheet</div>
                <table>
                    <thead>
                        <tr>
                            <th width="50">S.No</th>
                            <th>Material Description</th>
                            <th width="80">Unit</th>
                            <th width="100" style="text-align:right">Total Requested</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${page1Rows}
                    </tbody>
                </table>
                <div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div>

                <div class="page-break"></div>

                <!-- PAGE 2 -->
                ${headerHTML}
                <div class="page-title">Page 2: Approval & Balance Sheet</div>
                <table>
                    <thead>
                        <tr>
                            <th width="50">S.No</th>
                            <th>Material Description</th>
                            <th width="80" style="text-align:right">Req</th>
                            <th width="80" style="text-align:right">Approved</th>
                            <th width="80" style="text-align:right">Balance</th>
                            <th width="100">Status</th>
                        </tr>
                    </thead>
                    <tbody>
                        ${page2Rows}
                    </tbody>
                </table>
                <div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div>

                <script>
                    window.onload = () => { setTimeout(() => window.print(), 500); };
                </script>
            </body>
            </html>
          `);
          win.document.close();
      }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200">
                <Box size={28}/> 
              </div>
              Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100 uppercase tracking-widest">
                Unit ID: {CURRENT_UNIT_ID}
              </div>
              <div className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">
                Sewing Section A
              </div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input 
                  type="text" 
                  placeholder="Search by Order # or Style..." 
                  className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full bg-white text-slate-900 shadow-sm transition-all" 
                  value={searchTerm} 
                  onChange={(e) => setSearchTerm(e.target.value)} 
                />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50 shadow-sm transition-all active:scale-95"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5">
                              <AlertTriangle size={12}/> QC Feedback
                            </div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => handlePrintOrderSheet(detailsModal)} 
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

