                  </button>
                </div>
              </div>

              <div className="flex-1 flex flex-wrap content-start gap-2 p-3 bg-white rounded-xl border border-slate-200 min-h-[100px]">
                {isEditing.available_sizes?.map((sz, idx) => (
                  <div key={idx} className="bg-indigo-600 text-white px-3 py-1.5 rounded-lg text-xs font-black flex items-center gap-2 shadow-sm">
                    {sz}
                    <button type="button" onClick={() => {
                      const newSizes = isEditing.available_sizes?.filter((_, i) => i !== idx);
                      setIsEditing({...isEditing, available_sizes: newSizes});
                    }} className="text-white/50 hover:text-white transition-colors">
                      <X size={12}/>
                    </button>
                  </div>
                ))}
              </div>

              <button 
                type="button" 
                onClick={() => {
                  const newVal = prompt(`Enter new ${isEditing.size_type === 'letter' ? 'Letter' : 'Number'} size:`);
                  if (newVal) setIsEditing({...isEditing, available_sizes: [...(isEditing.available_sizes || []), newVal]});
                }} 
                className="w-full mt-4 py-2.5 border-2 border-dashed border-indigo-200 text-indigo-600 font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-white hover:border-indigo-300 transition-all flex items-center justify-center gap-2"
              >
                <Plus size={14}/> Add custom size
              </button>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-12">
          {/* Inject Packing Type and Pcs/Box if this is the Packing category */}
          {isPackingReq && (
            <>
              <div className="space-y-3">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Type of Packing</label>
                <select 
                  className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm cursor-pointer" 
                  value={isEditing.packing_type} 
                  onChange={e => setIsEditing({...isEditing, packing_type: e.target.value})}
                >
                  <option value="pouch">Pouch</option>
                  <option value="cover">Cover</option>
                  <option value="box">Box</option>
                </select>
              </div>
              <div className="space-y-3">
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">No of pieces / Box</label>
                <input 
                  type="number" 
                  className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-black focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm" 
                  value={isEditing.pcs_per_box} 
                  onChange={e => setIsEditing({...isEditing, pcs_per_box: parseInt(e.target.value) || 0})}
                />
              </div>
            </>
          )}

          {category.fields.map(field => {
            const item = isEditing.tech_pack[category.name]?.[field] || { text: '', attachments: [] };
            const isSplit = !!item.variants;

            return (
              <div key={field} className="space-y-4 col-span-full xl:col-span-1 bg-slate-50/30 p-4 rounded-2xl border border-slate-100">
                <div className="flex justify-between items-center px-1">
                  <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">{field}</label>
                  {!isSplit ? (
                    <button 
                      type="button" 
                      onClick={() => handleSplit(field)}
                      className="text-[9px] font-black text-indigo-600 bg-indigo-50 hover:bg-indigo-100 px-3 py-1.5 rounded-full flex items-center gap-2 border border-indigo-100 transition-all"
                    >
                      <Split size={12}/> Split Color-wise
                    </button>
                  ) : (
                    <button 
                      type="button" 
                      onClick={() => handleUnsplit(field)}
                      className="text-[9px] font-black text-slate-500 bg-white hover:bg-slate-100 px-3 py-1.5 rounded-full flex items-center gap-2 border border-slate-200 transition-all"
                    >
                      <X size={12}/> Merge Global
                    </button>
                  )}
                </div>

                {!isSplit ? (
                  /* GLOBAL VIEW */
                  <div className="space-y-3 animate-fade-in">
                    <textarea 
                      className="w-full border-2 border-slate-100 rounded-xl p-4 text-sm font-medium focus:border-indigo-500 outline-none min-h-[80px] bg-white transition-all text-black"
                      value={item.text}
                      placeholder={`Global instructions for ${field.toLowerCase()}...`}
                      onChange={e => {
                        const updated = { ...isEditing };
                        if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {};
                        updated.tech_pack[category.name][field] = { ...item, text: e.target.value };
                        setIsEditing(updated);
                      }}
                    />
                    <div className="flex flex-wrap gap-2">
                      {item.attachments.map((att, idx) => (
                        <div key={idx} className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-lg text-xs font-bold text-indigo-700">
                          {att.type === 'image' ? <ImageIcon size={14}/> : <FileText size={14}/>}
                          <span className="truncate max-w-[100px]">{att.name}</span>
                          <button type="button" onClick={() => {
                            const updated = { ...isEditing };
                            updated.tech_pack[category.name][field].attachments.splice(idx, 1);
                            setIsEditing(updated);
                          }} className="hover:text-red-500"><X size={14}/></button>
                        </div>
                      ))}
                      <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 hover:bg-indigo-50 text-slate-400 hover:text-indigo-600 px-3 py-1.5 rounded-lg text-xs font-bold transition-all cursor-pointer flex items-center gap-2">
                        <Plus size={14}/> Add File
                        <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files)}/>
                      </label>
                    </div>
                  </div>
                ) : (
                  /* SPLIT VIEW */
                  <div className="space-y-6 animate-fade-in">
                    {item.variants?.map((variant, vIdx) => (
                      <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-2xl p-4 shadow-sm relative group">
                        <button 
                          type="button" 
                          onClick={() => {
                            const updated = { ...isEditing };
                            updated.tech_pack[category.name][field].variants?.splice(vIdx, 1);
                            setIsEditing(updated);
                          }}
                          className="absolute -top-2 -right-2 bg-white text-red-500 p-1.5 rounded-full border-2 border-red-100 shadow-md opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <X size={14}/>
                        </button>

                        <div className="mb-4">
                          <label className="block text-[9px] font-black text-indigo-400 uppercase mb-2 tracking-widest">Apply to Colors</label>
                          <div className="flex flex-wrap gap-1.5">
                            {availableColors.map(color => {
                              const isSelected = variant.colors.includes(color);
                              return (
                                <button
                                  type="button"
                                  key={color}
                                  onClick={() => {
                                    const updated = { ...isEditing };
                                    const v = updated.tech_pack[category.name][field].variants![vIdx];
                                    if (isSelected) v.colors = v.colors.filter(c => c !== color);
                                    else v.colors.push(color);
                                    setIsEditing(updated);
                                  }}
                                  className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}
                                >
                                  {color}
                                </button>
                              );
                            })}
                            {availableColors.length === 0 && <span className="text-[9px] text-slate-300 italic">Add blueprint colors first</span>}
                          </div>
                        </div>

                        <textarea 
                          className="w-full border border-slate-100 rounded-xl p-3 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none min-h-[60px] bg-slate-50 transition-all text-black"
                          value={variant.text}
                          placeholder="Instructions for this color group..."
                          onChange={e => {
                            const updated = { ...isEditing };
                            updated.tech_pack[category.name][field].variants![vIdx].text = e.target.value;
                            setIsEditing(updated);
                          }}
                        />

                        <div className="mt-3 flex flex-wrap gap-2">
                           {variant.attachments.map((att, attIdx) => (
                            <div key={attIdx} className="flex items-center gap-2 bg-indigo-50 border border-indigo-50 px-2 py-1 rounded-lg text-[10px] font-bold text-indigo-700">
                              <span className="truncate max-w-[80px]">{att.name}</span>
                              <button type="button" onClick={() => {
                                const updated = { ...isEditing };
                                updated.tech_pack[category.name][field].variants![vIdx].attachments.splice(attIdx, 1);
                                setIsEditing(updated);
                              }} className="hover:text-red-500"><X size={12}/></button>
                            </div>
                          ))}
                          <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 hover:bg-indigo-50 text-slate-400 hover:text-indigo-600 px-3 py-1 rounded-lg text-[9px] font-black transition-all cursor-pointer flex items-center gap-2">
                            <Plus size={12}/> Attach
                            <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files, vIdx)}/>
                          </label>
                        </div>
                      </div>
                    ))}
                    <button 
                      type="button" 
                      onClick={() => handleSplit(field)}
                      className="w-full py-2.5 border-2 border-dashed border-slate-200 text-slate-400 text-[10px] font-black uppercase tracking-widest rounded-xl hover:border-indigo-300 hover:text-indigo-600 transition-all"
                    >
                      + Add Variant Group
                    </button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

