import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, SizeBreakdown, Style, ConsumptionType } from '../../types';
import { X, ImageIcon, FileText, Download, Paperclip, Printer, Box, Calculator } from 'lucide-react';
import { fetchStyleByNumber } from '../../services/db';

interface OrderDetailsModalProps {
  order: Order;
  useNumericSizes: boolean;
  onToggleSizeFormat: () => void;
  onClose: () => void;
  onPrint: () => void;
}

export const OrderDetailsModal: React.FC<OrderDetailsModalProps> = ({
  order,
  useNumericSizes,
  onClose,
  onPrint
}) => {
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);

  useEffect(() => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
      fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.style_number]);

  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);

  const calculateRequirement = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getEstimatedRequirements = () => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const estimates: Record<string, { name: string, total: number }> = {};
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        let fieldTotal = 0;

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => {
                    return sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0);
                }, 0);
                const ratioType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                const ratioVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                fieldTotal += calculateRequirement(qty, ratioType, ratioVal);
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              fieldTotal += calculateRequirement(qty, variant.consumption_type, variant.consumption_val || 0);
            }
          }
        } else if (item.consumption_type) {
          fieldTotal += calculateRequirement(order.quantity, item.consumption_type, item.consumption_val || 0);
        }

        if (fieldTotal > 0) {
          estimates[fieldName] = { name: fieldName, total: Math.ceil(fieldTotal * 100) / 100 };
        }
      }
    }
    return Object.values(estimates);
  };

  const renderDetailCell = (rowIdx: number, sizeKey: keyof SizeBreakdown) => {
    const plannedRow = order.size_breakdown?.[rowIdx];
    const actualRow = order.completion_breakdown?.[rowIdx];
    const plannedVal = plannedRow ? (plannedRow[sizeKey] as number) : 0;

    if (order.status !== OrderStatus.COMPLETED || !actualRow) {
      return <span className="text-slate-600 font-medium">{plannedVal}</span>;
    }

    const actualVal = actualRow[sizeKey] as number;
    const isMismatch = actualVal !== plannedVal;

    return (
      <div className="flex flex-col items-center justify-center p-1 bg-slate-50 rounded border border-slate-100">
        <span className={`text-lg font-black ${isMismatch ? 'text-indigo-700' : 'text-slate-900'}`}>
          {actualVal}
        </span>
        <span className="text-[10px] font-bold text-slate-400 border-t border-slate-200 w-full text-center mt-0.5 pt-0.5">
          Plan: {plannedVal}
        </span>
      </div>
    );
  };

  const estimatedReqs = getEstimatedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden max-h-[95vh] flex flex-col animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <div>
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{order.order_no}</h3>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Production Execution Details</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={28} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Style Number</span>
              <span className="text-lg font-black text-slate-800">{order.style_number}</span>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Delivery Date</span>
              <span className="text-lg font-black text-slate-800">{order.target_delivery_date}</span>
            </div>
            <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 shadow-sm">
              <span className="block text-indigo-400 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Planned Boxes</span>
              <span className="text-xl font-black text-indigo-800">{order.box_count || '---'}</span>
            </div>
            {order.status === OrderStatus.COMPLETED && (
               <div className="p-4 bg-green-50 rounded-xl border border-green-100 shadow-sm animate-fade-in">
                <span className="block text-green-500 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Actual Packed</span>
                <span className="text-xl font-black text-green-800">{order.actual_box_count}</span>
              </div>
            )}
          </div>

          {/* REQUIREMENTS SECTION */}
          {estimatedReqs.length > 0 && (
            <div className="bg-indigo-50/50 rounded-3xl border border-indigo-100 overflow-hidden shadow-sm">
              <div className="p-4 bg-indigo-600 text-white flex items-center justify-between">
                <h4 className="font-black uppercase tracking-[0.1em] text-xs flex items-center gap-2"><Calculator size={16}/> Estimated Job Requirements</h4>
              </div>
              <div className="p-5">
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-3">
                  {estimatedReqs.map((req, i) => (
                    <div key={i} className="p-3 bg-white rounded-xl border border-indigo-100 flex flex-col items-center text-center">
                       <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest mb-1">{req.name}</span>
                       <div className="text-2xl font-black text-indigo-600">{req.total}</div>
                    </div>
                  ))}
                </div>
                <p className="text-[9px] font-bold text-indigo-400 uppercase mt-4 italic text-center">Quantities synced from technical database blueprint</p>
              </div>
            </div>
          )}

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">
                Production Matrix
                {order.status === OrderStatus.COMPLETED && <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full ml-3 border border-indigo-100 uppercase tracking-widest">Actual / Planned</span>}
              </h4>
            </div>
            <div className="border border-slate-200 rounded-2xl overflow-hidden shadow-md">
              <table className="w-full text-center text-sm border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-4 text-left border-r">Color Variant</th>
                    {getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}
                    <th className="p-4 font-black bg-slate-100">Row Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {order.size_breakdown?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="p-4 text-left font-black text-slate-700 border-r">{row.color}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 's')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'm')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'l')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxxl')}</td>
                      <td className="p-4 font-black bg-slate-50/50 text-slate-800 tabular-nums">{getRowTotal(row)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="p-6 bg-slate-50/50 rounded-2xl border border-slate-200 shadow-inner">
              <h4 className="font-black text-slate-400 mb-4 uppercase tracking-widest text-[10px]">Production Instructions</h4>
              <p className="text-base text-slate-600 font-medium whitespace-pre-wrap leading-relaxed">{order.description || "No specific instructions provided."}</p>
            </div>
            <div className="p-6 bg-indigo-50/30 rounded-2xl border border-indigo-100 shadow-inner">
              <h4 className="font-black text-indigo-400 mb-4 uppercase tracking-widest text-[10px] flex items-center gap-2">
                <Paperclip size={14}/> Technical Reference Files
              </h4>
              <div className="space-y-3">
                {order.attachments && order.attachments.length > 0 ? (
                  order.attachments.map((att, i) => (
                    <a key={i} href={att.url} target="_blank" rel="noreferrer" className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-200 hover:shadow-lg transition-all group">
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-100 rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                          {att.type === 'image' ? <ImageIcon size={20} /> : <FileText size={20} />}
                        </div>
                        <span className="text-sm font-bold text-slate-700 truncate max-w-[200px]">{att.name}</span>
                      </div>
                      <Download size={18} className="text-slate-300 group-hover:text-indigo-600 transition-colors" />
                    </a>
                  ))
                ) : (
                  <div className="text-center py-10 text-slate-300">
                    <Paperclip size={32} className="mx-auto opacity-20 mb-2" />
                    <p className="text-[10px] uppercase font-black tracking-widest opacity-60">No documents attached</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
        <div className="p-6 border-t bg-slate-50 text-right flex justify-end gap-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.03)]">
          <button onClick={onPrint} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest text-xs">
            <Printer size={18} /> Print Full Job Sheet
          </button>
          <button onClick={onClose} className="bg-slate-800 text-white px-10 py-3 rounded-xl font-black hover:bg-slate-700 transition-all active:scale-95 uppercase tracking-widest text-xs">Close</button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleByNumber, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber, Style, ConsumptionType } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC && order.status !== OrderStatus.QC_APPROVED) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }))
                : [{ color: 'Standard', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actual_box_count });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  const handleDeleteRequest = async (id: string) => {
      if (!confirm("Are you sure?")) return;
      await deleteMaterialRequest(id);
      handleOpenMaterialHistory();
  };

  const handleEditRequest = (req: MaterialRequest) => {
      setIsEditingRequest({ id: req.id, originalData: req });
      setMaterialModal(req.order_id);
      setShowMaterialHistory(false);
  };

  const handleGenerateAndPrintBarcodes = async (qty: number, size: string) => {
    if (!barcodeModal) return;
    const newBarcodes = await generateBarcodes(barcodeModal.orderId, qty, barcodeModal.style, size);
    setBarcodeModal(null);
    const win = window.open('', 'PrintBarcodes', 'width=1000,height=800');
    if (win) {
        const labelsHtml = newBarcodes.map(b => `<div class="label"><div class="header">TINTURA SST</div><div class="meta"><strong>Style:</strong> ${b.style_number} &nbsp; <strong>Size:</strong> ${b.size}</div><svg class="barcode" jsbarcode-format="CODE128" jsbarcode-value="${b.barcode_serial}" jsbarcode-textmargin="0" jsbarcode-fontoptions="bold" jsbarcode-height="40" jsbarcode-width="2" jsbarcode-displayValue="true" jsbarcode-fontSize="11"></svg></div>`).join('');
        win.document.write(`<html><head><title>Print Labels</title><script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script><style>@page { size: A4; margin: 10mm; } body { margin: 0; font-family: sans-serif; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-auto-rows: 35mm; column-gap: 5mm; row-gap: 2mm; } .label { border: 1px dashed #ddd; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 5px; overflow: hidden; text-align: center; background: white; } .header { font-size: 10px; font-weight: bold; text-transform: uppercase; margin: 2px; } .meta { font-size: 10px; margin-bottom: 2px; color: #333; } svg { max-width: 95%; height: auto; display: block; }</style></head><body><div class="grid">${labelsHtml}</div><script>window.onload = function() { JsBarcode(".barcode").init(); setTimeout(() => { window.print(); }, 500); }</script></body></html>`); 
        win.document.close();
    }
  };

  const calculateRequirement = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getEstimatedRequirements = (order: Order, linkedStyle: Style) => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const estimates: Record<string, { name: string, total: number }> = {};
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        let fieldTotal = 0;

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => {
                    return sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0);
                }, 0);
                const ratioType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                const ratioVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                fieldTotal += calculateRequirement(qty, ratioType, ratioVal);
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + ( (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0) ), 0);
              fieldTotal += calculateRequirement(qty, variant.consumption_type, variant.consumption_val || 0);
            }
          }
        } else if (item.consumption_type) {
          fieldTotal += calculateRequirement(order.quantity, item.consumption_type, item.consumption_val || 0);
        }

        if (fieldTotal > 0) {
          estimates[fieldName] = { name: fieldName, total: Math.ceil(fieldTotal * 100) / 100 };
        }
      }
    }
    return Object.values(estimates);
  };

  const handlePrintOrderSheet = async (order: Order) => {
      let techPackHtml = '';
      let reqSheetHtml = '';

      const styleRefPart = order.style_number.split(' - ')[0].trim();
      if (styleRefPart) {
          const [style, template] = await Promise.all([
              fetchStyleByNumber(styleRefPart),
              fetchStyleTemplate()
          ]);

          if (style && template) {
              const estReqs = getEstimatedRequirements(order, style);
              if (estReqs.length > 0) {
                reqSheetHtml = `
                  <div style="margin-top:40px; page-break-before:always;">
                    <h3 style="background:#4f46e5; color:#fff; padding:15px 25px; font-size:18px; text-transform:uppercase; letter-spacing:3px; border-radius:12px; font-weight:900;">Estimated material Requirements</h3>
                    <table style="width:100%; border-collapse:collapse; margin-top:20px;">
                      <thead>
                        <tr style="background:#f1f5f9;">
                          <th style="border:1px solid #cbd5e1; padding:12px; text-align:left;">Component</th>
                          <th style="border:1px solid #cbd5e1; padding:12px; text-align:right;">Approx Quantity</th>
                        </tr>
                      </thead>
                      <tbody>
                        ${estReqs.map(r => `
                          <tr>
                            <td style="border:1px solid #cbd5e1; padding:12px; font-weight:bold;">${r.name}</td>
                            <td style="border:1px solid #cbd5e1; padding:12px; text-align:right; font-weight:900; color:#4f46e5; font-size:18px;">${r.total}</td>
                          </tr>
                        `).join('')}
                      </tbody>
                    </table>
                  </div>
                `;
              }

              techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                  const fields = cat.fields.map(f => {
                      const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                      let contentHtml = '';
                      if (item.variants) {
                        contentHtml = item.variants.map(v => {
                          let sizeHtml = '';
                          if (v.sizeVariants) {
                            sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                              <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px;">
                                <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                  ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:18px;">SIZE: ${sz}</span>`).join('')}
                                </div>
                                <div style="font-size:20px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                              </div>
                            `).join('')}</div>`;
                          }
                          return `<div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;"><div style="margin-bottom:10px;">${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div><div style="font-size:22px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div>${sizeHtml}</div>`;
                        }).join('');
                      } else {
                        contentHtml = `<div style="font-size:24px; font-weight:900; color:#1e293b; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0; line-height:1.3;">${item.text || '---'}</div>`;
                      }

                      return `
                        <div style="margin-bottom:20px; border-bottom:1px solid #eee; padding-bottom:10px; break-inside:avoid;">
                          <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:4px;">${f}</div>
                          ${contentHtml}
                        </div>
                      `;
                  }).join('');

                  return `
                    <div style="margin-top:40px; page-break-before:always;">
                      <h3 style="background:#000; color:#fff; padding:10px; font-size:14px; text-transform:uppercase; letter-spacing:1px;">${cat.name} (Style DB Reference)</h3>
                      <div style="padding:10px;">${fields}</div>
                    </div>
                  `;
              }).join('');
          }
      }

      const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
      const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
      const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
      const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold;">${getRowTotal(row)}</td></tr>`).join('');
      const formattedNo = formatOrderNumber(order);

      let attachmentHtml = '';
      if (order.attachments && order.attachments.length > 0) {
          attachmentHtml = `<div class="section-title">Technical Documents & References</div><div style="display:flex; flex-direction:column; gap:25px;">`;
          order.attachments.forEach(att => {
              if (att.type === 'image') {
                  attachmentHtml += `<div style="border:1px solid #ccc; padding:15px; width:100%; text-align:center;"><img src="${att.url}" style="max-width:100%; max-height:800px; border-radius:8px;" /><div style="font-size:12px; margin-top:10px; font-weight:bold; text-transform:uppercase; color:#666;">REF: ${att.name}</div></div>`;
              } else if (att.url.toLowerCase().endsWith('.pdf')) {
                  attachmentHtml += `<div style="border:2px solid #333; border-radius:8px; overflow:hidden; page-break-before:always;"><div style="background:#333; color:white; padding:10px; font-weight:bold; text-align:center; font-size:14px;">PDF DOCUMENT: ${att.name}</div><iframe src="${att.url}" style="width:100%; height:1000px; border:none;"></iframe></div>`;
              } else {
                  attachmentHtml += `<div style="border:1px dashed #ccc; padding:20px; background:#f9f9f9; text-align:center; border-radius:8px;"><strong>DOCUMENT:</strong> ${att.name}</div>`;
              }
          });
          attachmentHtml += `</div>`;
      }

      const win = window.open('', 'PrintOrderSheet', 'width=1000,height=800');
      if (win) {
          win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title><style>body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; } .header { text-align: center; border-bottom: 5px solid #000; padding-bottom: 20px; margin-bottom: 30px; } .brand { font-size: 42px; font-weight: 900; text-transform: uppercase; margin: 0; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #444; } .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; } .box { padding: 15px; border: 2px solid #333; border-radius: 6px; } .label { font-size: 11px; text-transform: uppercase; color: #666; font-weight: bold; } .value { font-size: 18px; font-weight: bold; } table { width: 100%; border-collapse: collapse; margin-top: 20px; } th, td { border: 1px solid #333; padding: 12px; text-align: center; } th { background: #f0f0f0; font-weight: 800; text-transform: uppercase; } .section-title { font-size: 18px; font-weight: 900; border-bottom: 3px solid #333; padding-bottom: 5px; margin-top: 40px; margin-bottom: 15px; text-transform: uppercase; }</style></head><body><div class="header"><div class="brand">TINTURA SST</div><div class="title">Manufacturing Job Sheet</div></div><div class="grid"><div class="box"><span class="label">Order Number</span><div class="value">${formattedNo}</div></div><div class="box"><span class="label">Style Reference</span><div class="value">${order.style_number}</div></div><div class="box"><span class="label">Total Quantity</span><div class="value">${order.quantity} PCS</div></div><div class="box"><span class="label">Planned Boxes</span><div class="value">${order.box_count || '---'}</div></div><div class="box"><span class="label">Delivery Deadline</span><div class="value">${order.target_delivery_date}</div></div></div><div class="section-title">Size Matrix Breakdown</div><table><thead><tr><th style="text-align:left;">Color</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Total</th></tr></thead><tbody>${breakdownRows}</tbody></table><div class="section-title">Production Requirements</div><div style="padding: 20px; border: 2px solid #333; min-height: 80px; background:#fcfcfc; border-radius:6px; font-size:16px;">${order.description || "No specific manufacturing notes provided."}</div>${reqSheetHtml}${attachmentHtml}${techPackHtml}<script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script></body></html>`);
          win.document.close();
      }
  };

  const handlePrintAccessoriesReceipt = (order: Order, reqs: MaterialRequest[]) => {
      const formattedNo = formatOrderNumber(order);
      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:center;">${req.unit || 'Nos'}</td><td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td></tr>`).join('');
          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:right;">${req.quantity_requested}</td><td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td><td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td><td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td></tr>`;
          }).join('');
          const headerHTML = `<div class="header"><div class="brand">TINTURA SST</div><div class="title">ACCESSORIES REQUIREMENT RECEIPT</div><div class="meta">ORDER NO: ${formattedNo} &nbsp;|&nbsp; STYLE: ${order.style_number} &nbsp;|&nbsp; DATE: ${new Date().toLocaleDateString()}</div></div>`;
          win.document.write(`<html><head><title>Accessories Receipt - ${formattedNo}</title><style>@media print { .page-break { page-break-before: always; } body { -webkit-print-color-adjust: exact; } } body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; } .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; } .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; } .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; } table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; } th, td { border: 1px solid #ccc; padding: 8px; } th { background: #f4f4f4; text-transform: uppercase; }</style></head><body>${headerHTML}<div class="page-title">Page 1: Request Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80">Unit</th><th width="100" style="text-align:right">Total Requested</th></tr></thead><tbody>${page1Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div><div class="page-break"></div>${headerHTML}<div class="page-title">Page 2: Approval & Balance Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80" style="text-align:right">Req</th><th width="80" style="text-align:right">Approved</th><th width="80" style="text-align:right">Balance</th><th width="100">Status</th></tr></thead><tbody>${page2Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div><script>window.onload = () => { setTimeout(() => window.print(), 500); };</script></body></html>`);
          win.document.close();
      }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200">
                <Box size={28}/> 
              </div>
              Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100 uppercase tracking-widest">
                Unit ID: {CURRENT_UNIT_ID}
              </div>
              <div className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">
                Sewing Section A
              </div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input type="text" placeholder="Search by Order # or Style..." className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full bg-white text-slate-900 shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50 shadow-sm transition-all active:scale-95"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5"><AlertTriangle size={12}/> QC Feedback</div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => handlePrintOrderSheet(detailsModal)} 
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleByNumber, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber, Style, ConsumptionType } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC && order.status !== OrderStatus.QC_APPROVED) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }))
                : [{ color: 'Standard', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      // Fix: changed completionForm.actual_box_count to completionForm.actualBoxCount to match state definition
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actualBoxCount });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  const handleDeleteRequest = async (id: string) => {
      if (!confirm("Are you sure?")) return;
      await deleteMaterialRequest(id);
      handleOpenMaterialHistory();
  };

  const handleEditRequest = (req: MaterialRequest) => {
      setIsEditingRequest({ id: req.id, originalData: req });
      setMaterialModal(req.order_id);
      setShowMaterialHistory(false);
  };

  const handleGenerateAndPrintBarcodes = async (qty: number, size: string) => {
    if (!barcodeModal) return;
    const newBarcodes = await generateBarcodes(barcodeModal.orderId, qty, barcodeModal.style, size);
    setBarcodeModal(null);
    const win = window.open('', 'PrintBarcodes', 'width=1000,height=800');
    if (win) {
        const labelsHtml = newBarcodes.map(b => `<div class="label"><div class="header">TINTURA SST</div><div class="meta"><strong>Style:</strong> ${b.style_number} &nbsp; <strong>Size:</strong> ${b.size}</div><svg class="barcode" jsbarcode-format="CODE128" jsbarcode-value="${b.barcode_serial}" jsbarcode-textmargin="0" jsbarcode-fontoptions="bold" jsbarcode-height="40" jsbarcode-width="2" jsbarcode-displayValue="true" jsbarcode-fontSize="11"></svg></div>`).join('');
        win.document.write(`<html><head><title>Print Labels</title><script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script><style>@page { size: A4; margin: 10mm; } body { margin: 0; font-family: sans-serif; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-auto-rows: 35mm; column-gap: 5mm; row-gap: 2mm; } .label { border: 1px dashed #ddd; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 5px; overflow: hidden; text-align: center; background: white; } .header { font-size: 10px; font-weight: bold; text-transform: uppercase; margin: 2px; } .meta { font-size: 10px; margin-bottom: 2px; color: #333; } svg { max-width: 95%; height: auto; display: block; }</style></head><body><div class="grid">${labelsHtml}</div><script>window.onload = function() { JsBarcode(".barcode").init(); setTimeout(() => { window.print(); }, 500); }</script></body></html>`); 
        win.document.close();
    }
  };

  const calculateRequirement = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getEstimatedRequirements = (order: Order, linkedStyle: Style) => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const estimates: Record<string, { name: string, total: number }> = {};
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        let fieldTotal = 0;

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => {
                    return sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0);
                }, 0);
                const ratioType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                const ratioVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                fieldTotal += calculateRequirement(qty, ratioType, ratioVal);
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + ( (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0) ), 0);
              fieldTotal += calculateRequirement(qty, variant.consumption_type, variant.consumption_val || 0);
            }
          }
        } else if (item.consumption_type) {
          fieldTotal += calculateRequirement(order.quantity, item.consumption_type, item.consumption_val || 0);
        }

        if (fieldTotal > 0) {
          estimates[fieldName] = { name: fieldName, total: Math.ceil(fieldTotal * 100) / 100 };
        }
      }
    }
    return Object.values(estimates);
  };

  const handlePrintOrderSheet = async (order: Order) => {
      let techPackHtml = '';
      let reqSheetHtml = '';

      const styleRefPart = order.style_number.split(' - ')[0].trim();
      if (styleRefPart) {
          const [style, template] = await Promise.all([
              fetchStyleByNumber(styleRefPart),
              fetchStyleTemplate()
          ]);

          if (style && template) {
              const estReqs = getEstimatedRequirements(order, style);
              if (estReqs.length > 0) {
                reqSheetHtml = `
                  <div style="margin-top:40px; page-break-before:always;">
                    <h3 style="background:#4f46e5; color:#fff; padding:15px 25px; font-size:18px; text-transform:uppercase; letter-spacing:3px; border-radius:12px; font-weight:900;">Estimated material Requirements</h3>
                    <table style="width:100%; border-collapse:collapse; margin-top:20px;">
                      <thead>
                        <tr style="background:#f1f5f9;">
                          <th style="border:1px solid #cbd5e1; padding:12px; text-align:left;">Component</th>
                          <th style="border:1px solid #cbd5e1; padding:12px; text-align:right;">Approx Quantity</th>
                        </tr>
                      </thead>
                      <tbody>
                        ${estReqs.map(r => `
                          <tr>
                            <td style="border:1px solid #cbd5e1; padding:12px; font-weight:bold;">${r.name}</td>
                            <td style="border:1px solid #cbd5e1; padding:12px; text-align:right; font-weight:900; color:#4f46e5; font-size:18px;">${r.total}</td>
                          </tr>
                        `).join('')}
                      </tbody>
                    </table>
                  </div>
                `;
              }

              techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                  const fields = cat.fields.map(f => {
                      const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                      let contentHtml = '';
                      if (item.variants) {
                        contentHtml = item.variants.map(v => {
                          let sizeHtml = '';
                          if (v.sizeVariants) {
                            sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                              <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px;">
                                <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                  ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:18px;">SIZE: ${sz}</span>`).join('')}
                                </div>
                                <div style="font-size:20px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                              </div>
                            `).join('')}</div>`;
                          }
                          return `<div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;"><div style="margin-bottom:10px;">${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div><div style="font-size:22px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div>${sizeHtml}</div>`;
                        }).join('');
                      } else {
                        contentHtml = `<div style="font-size:24px; font-weight:900; color:#1e293b; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0; line-height:1.3;">${item.text || '---'}</div>`;
                      }

                      return `
                        <div style="margin-bottom:20px; border-bottom:1px solid #eee; padding-bottom:10px; break-inside:avoid;">
                          <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:4px;">${f}</div>
                          ${contentHtml}
                        </div>
                      `;
                  }).join('');

                  return `
                    <div style="margin-top:40px; page-break-before:always;">
                      <h3 style="background:#000; color:#fff; padding:10px; font-size:14px; text-transform:uppercase; letter-spacing:1px;">${cat.name} (Style DB Reference)</h3>
                      <div style="padding:10px;">${fields}</div>
                    </div>
                  `;
              }).join('');
          }
      }

      const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
      const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
      const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
      const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold;">${getRowTotal(row)}</td></tr>`).join('');
      const formattedNo = formatOrderNumber(order);

      let attachmentHtml = '';
      if (order.attachments && order.attachments.length > 0) {
          attachmentHtml = `<div class="section-title">Technical Documents & References</div><div style="display:flex; flex-direction:column; gap:25px;">`;
          order.attachments.forEach(att => {
              if (att.type === 'image') {
                  attachmentHtml += `<div style="border:1px solid #ccc; padding:15px; width:100%; text-align:center;"><img src="${att.url}" style="max-width:100%; max-height:800px; border-radius:8px;" /><div style="font-size:12px; margin-top:10px; font-weight:bold; text-transform:uppercase; color:#666;">REF: ${att.name}</div></div>`;
              } else if (att.url.toLowerCase().endsWith('.pdf')) {
                  attachmentHtml += `<div style="border:2px solid #333; border-radius:8px; overflow:hidden; page-break-before:always;"><div style="background:#333; color:white; padding:10px; font-weight:bold; text-align:center; font-size:14px;">PDF DOCUMENT: ${att.name}</div><iframe src="${att.url}" style="width:100%; height:1000px; border:none;"></iframe></div>`;
              } else {
                  attachmentHtml += `<div style="border:1px dashed #ccc; padding:20px; background:#f9f9f9; text-align:center; border-radius:8px;"><strong>DOCUMENT:</strong> ${att.name}</div>`;
              }
          });
          attachmentHtml += `</div>`;
      }

      const win = window.open('', 'PrintOrderSheet', 'width=1000,height=800');
      if (win) {
          win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title><style>body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; } .header { text-align: center; border-bottom: 5px solid #000; padding-bottom: 20px; margin-bottom: 30px; } .brand { font-size: 42px; font-weight: 900; text-transform: uppercase; margin: 0; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #444; } .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; } .box { padding: 15px; border: 2px solid #333; border-radius: 6px; } .label { font-size: 11px; text-transform: uppercase; color: #666; font-weight: bold; } .value { font-size: 18px; font-weight: bold; } table { width: 100%; border-collapse: collapse; margin-top: 20px; } th, td { border: 1px solid #333; padding: 12px; text-align: center; } th { background: #f0f0f0; font-weight: 800; text-transform: uppercase; } .section-title { font-size: 18px; font-weight: 900; border-bottom: 3px solid #333; padding-bottom: 5px; margin-top: 40px; margin-bottom: 15px; text-transform: uppercase; }</style></head><body><div class="header"><div class="brand">TINTURA SST</div><div class="title">Manufacturing Job Sheet</div></div><div class="grid"><div class="box"><span class="label">Order Number</span><div class="value">${formattedNo}</div></div><div class="box"><span class="label">Style Reference</span><div class="value">${order.style_number}</div></div><div class="box"><span class="label">Total Quantity</span><div class="value">${order.quantity} PCS</div></div><div class="box"><span class="label">Planned Boxes</span><div class="value">${order.box_count || '---'}</div></div><div class="box"><span class="label">Delivery Deadline</span><div class="value">${order.target_delivery_date}</div></div></div><div class="section-title">Size Matrix Breakdown</div><table><thead><tr><th style="text-align:left;">Color</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Total</th></tr></thead><tbody>${breakdownRows}</tbody></table><div class="section-title">Production Requirements</div><div style="padding: 20px; border: 2px solid #333; min-height: 80px; background:#fcfcfc; border-radius:6px; font-size:16px;">${order.description || "No specific manufacturing notes provided."}</div>${reqSheetHtml}${attachmentHtml}${techPackHtml}<script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script></body></html>`);
          win.document.close();
      }
  };

  const handlePrintAccessoriesReceipt = (order: Order, reqs: MaterialRequest[]) => {
      const formattedNo = formatOrderNumber(order);
      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:center;">${req.unit || 'Nos'}</td><td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td></tr>`).join('');
          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:right;">${req.quantity_requested}</td><td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td><td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td><td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td></tr>`;
          }).join('');
          const headerHTML = `<div class="header"><div class="brand">TINTURA SST</div><div class="title">ACCESSORIES REQUIREMENT RECEIPT</div><div class="meta">ORDER NO: ${formattedNo} &nbsp;|&nbsp; STYLE: ${order.style_number} &nbsp;|&nbsp; DATE: ${new Date().toLocaleDateString()}</div></div>`;
          win.document.write(`<html><head><title>Accessories Receipt - ${formattedNo}</title><style>@media print { .page-break { page-break-before: always; } body { -webkit-print-color-adjust: exact; } } body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; } .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; } .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; } .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; } table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; } th, td { border: 1px solid #ccc; padding: 8px; } th { background: #f4f4f4; text-transform: uppercase; }</style></head><body>${headerHTML}<div class="page-title">Page 1: Request Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80">Unit</th><th width="100" style="text-align:right">Total Requested</th></tr></thead><tbody>${page1Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div><div class="page-break"></div>${headerHTML}<div class="page-title">Page 2: Approval & Balance Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80" style="text-align:right">Req</th><th width="80" style="text-align:right">Approved</th><th width="80" style="text-align:right">Balance</th><th width="100">Status</th></tr></thead><tbody>${page2Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div><script>window.onload = () => { setTimeout(() => window.print(), 500); };</script></body></html>`);
          win.document.close();
      }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200">
                <Box size={28}/> 
              </div>
              Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100 uppercase tracking-widest">
                Unit ID: {CURRENT_UNIT_ID}
              </div>
              <div className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">
                Sewing Section A
              </div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input type="text" placeholder="Search by Order # or Style..." className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full bg-white text-slate-900 shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50 shadow-sm transition-all active:scale-95"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5"><AlertTriangle size={12}/> QC Feedback</div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => handlePrintOrderSheet(detailsModal)} 
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Pencil, Trash2, Printer, Save, Loader2, Clock, Paperclip, Box, Image as ImageIcon, FileText, Download, ArrowLeftRight, Upload, BookOpen, Calculator, ExternalLink } from 'lucide-react';
import { Order, Unit, OrderLog, SizeBreakdown, Attachment, OrderStatus, formatOrderNumber, Style, StyleTemplate, ConsumptionType } from '../../types';
import { fetchOrderLogs, updateOrderDetails, deleteOrder, triggerOrderEmail, uploadOrderAttachment, fetchStyleByNumber, fetchStyleTemplate } from '../../services/db';

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

interface AdminOrderDetailsModalProps {
  order: Order;
  units: Unit[];
  onClose: () => void;
  onRefresh: () => void;
}

export const AdminOrderDetailsModal: React.FC<AdminOrderDetailsModalProps> = ({ order, units, onClose, onRefresh }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [editFormData, setEditFormData] = useState<Partial<Order>>({ ...order });
  const [modalLogs, setModalLogs] = useState<OrderLog[]>([]);
  const [useNumericSizes, setUseNumericSizes] = useState(order.size_format === 'numeric');
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);

  useEffect(() => {
    fetchOrderLogs(order.id).then(setModalLogs);
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
        fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.id, order.style_number]);

  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getRowTotal(row), 0);
  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global (All Colors/Sizes)",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const handleSave = async () => {
    setIsUploading(true);
    try {
      const newAttachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) newAttachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }
      const finalAttachments = [...(editFormData.attachments || []), ...newAttachments];
      const finalQty = getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]);
      const result = await updateOrderDetails(order.id, { ...editFormData, quantity: finalQty, attachments: finalAttachments, size_format: useNumericSizes ? 'numeric' : 'standard' });
      if (result.success) {
        await triggerOrderEmail(order.id, true);
        onRefresh();
        onClose();
      }
    } finally {
      setIsUploading(false);
    }
  };

  const handlePrint = async () => {
    let techPackHtml = '';
    let reqSheetHtml = '';

    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
        const [style, template] = await Promise.all([ fetchStyleByNumber(styleRefPart), fetchStyleTemplate() ]);
        if (style && template) {
            const detailedReqs = getDetailedRequirements();
            if (detailedReqs.length > 0) {
              reqSheetHtml = `
                <div style="margin-top:50px; page-break-before:always;">
                  <h2 style="background:#1e293b; color:#fff; padding:20px 30px; font-size:24px; text-transform:uppercase; letter-spacing:4px; border-radius:12px; font-weight:900;">Detailed Material Forecast</h2>
                  <div style="margin-top:20px;">
                    ${detailedReqs.map(req => `
                      <div style="margin-bottom:40px; border:2px solid #e2e8f0; border-radius:20px; overflow:hidden; background:#fff;">
                        <div style="background:#f8fafc; padding:15px 25px; border-bottom:2px solid #e2e8f0; display:flex; justify-content:space-between; align-items:center;">
                          <span style="font-size:20px; font-weight:900; text-transform:uppercase; color:#1e293b;">${req.name}</span>
                          <span style="font-size:22px; font-weight:900; color:#4f46e5;">TOTAL: ${req.total}</span>
                        </div>
                        <div style="padding:20px;">
                          <table style="width:100%; border-collapse:collapse;">
                            <thead>
                              <tr style="background:#f1f5f9;">
                                <th style="padding:10px; border:1px solid #cbd5e1; text-align:left; font-size:12px;">Segment</th>
                                <th style="padding:10px; border:1px solid #cbd5e1; text-align:center; font-size:12px;">Job Qty</th>
                                <th style="padding:10px; border:1px solid #cbd5e1; text-align:right; font-size:12px;">Required</th>
                                <th style="padding:10px; border:1px solid #cbd5e1; text-align:left; font-size:12px;">Technical Specs</th>
                              </tr>
                            </thead>
                            <tbody>
                              ${req.breakdown.map(b => `
                                <tr>
                                  <td style="padding:12px; border:1px solid #cbd5e1; font-weight:bold; font-size:14px;">${b.label}</td>
                                  <td style="padding:12px; border:1px solid #cbd5e1; text-align:center; font-size:14px;">${b.count}</td>
                                  <td style="padding:12px; border:1px solid #cbd5e1; text-align:right; font-weight:900; color:#4f46e5; font-size:16px;">${b.calc}</td>
                                  <td style="padding:12px; border:1px solid #cbd5e1; font-size:13px; color:#475569;">
                                    <div>${b.text || '---'}</div>
                                    <div style="margin-top:10px; display:grid; grid-template-columns:1fr 1fr; gap:10px;">
                                      ${b.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}" style="width:100%; border-radius:8px;" />`).join('')}
                                    </div>
                                  </td>
                                </tr>
                              `).join('')}
                            </tbody>
                          </table>
                        </div>
                      </div>
                    `).join('')}
                  </div>
                </div>
              `;
            }

            techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                const isPreProd = cat.name.toLowerCase().includes('pre production');
                const variantMetaHtml = isPreProd ? `<div style="background:#f1f5f9; padding:20px; border-radius:8px; margin-bottom:20px; display:grid; grid-template-columns:1fr 1fr; gap:20px; border:1px solid #cbd5e1;"><div><span style="font-size:10px; font-weight:900; color:#64748b; text-transform:uppercase;">Blueprint Colours</span><br/><strong style="font-size:16px;">${style.available_colors?.join(', ') || '---'}</strong></div><div><span style="font-size:10px; font-weight:900; color:#64748b; text-transform:uppercase;">Size Range</span><br/><strong style="font-size:16px;">${style.available_sizes?.join(', ') || '---'}</strong></div></div>` : '';
                const fields = cat.fields.map(f => {
                    const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                    let contentHtml = '';
                    if (item.variants) {
                      contentHtml = item.variants.map(v => {
                        let sizeHtml = '';
                        if (v.sizeVariants) {
                          sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                            <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px;">
                              <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:18px;">SIZE: ${sz}</span>`).join('')}
                              </div>
                              <div style="font-size:20px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                              <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:15px;">
                                ${sv.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}" style="width:100%; border-radius:10px; border:1px solid #eee;" />`).join('')}
                              </div>
                            </div>
                          `).join('')}</div>`;
                        }
                        return `<div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;"><div style="margin-bottom:10px; display:flex; justify-content:space-between; align-items:center;"><div>${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div> ${!v.sizeVariants && v.consumption_type ? `<div style="font-weight:900; color:#1e293b; border:1px solid #1e293b; padding:4px 10px; border-radius:6px;">${v.consumption_val} ${v.consumption_type === 'items_per_pc' ? 'Items / PC' : 'PCS / Item'}</div>` : ''}</div><div style="font-size:22px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div><div style="display:grid; grid-template-columns:1fr 1fr; gap:10px; margin-top:15px;">${v.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}" style="width:100%; border-radius:10px; border:1px solid #eee;" />`).join('')}</div>${sizeHtml}</div>`;
                      }).join('');
                    } else {
                      contentHtml = `<div style="display:flex; justify-content:space-between; align-items:center; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0;"><div style="font-size:24px; font-weight:900; color:#1e293b; line-height:1.3;">${item.text || '---'}</div> ${item.consumption_type ? `<div style="background:#1e293b; color:#fff; padding:10px 20px; border-radius:8px; font-weight:900; font-size:20px; text-align:center;">${item.consumption_val}<br/><small style="font-size:10px; opacity:0.8; letter-spacing:1px;">${item.consumption_type === 'items_per_pc' ? 'ITEMS / PC' : 'PCS / ITEM'}</small></div>` : ''}</div>`;
                    }
                    return `<div style="margin-bottom:40px; border-bottom:1px solid #e2e8f0; padding-bottom:30px; break-inside:avoid;"><div style="font-size:12px; font-weight:900; color:#64748b; text-transform:uppercase; margin-bottom:12px; letter-spacing:1px; display:flex; align-items:center; gap:8px;"><div style="width:8px; height:8px; background:#4f46e5; border-radius:50%;"></div>${f}</div>${contentHtml}</div>`;
                }).join('');
                return `<div style="margin-top:40px; page-break-before:always;"><h3 style="background:#1e293b; color:#fff; padding:15px 25px; font-size:18px; text-transform:uppercase; letter-spacing:3px; border-radius:12px;">${cat.name}</h3><div style="padding:15px 5px;">${variantMetaHtml}${fields}</div></div>`;
            }).join('');
        }
    }

    const formattedNo = formatOrderNumber(order);
    const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
    const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold;">${getRowTotal(row)}</td></tr>`).join('');

    const win = window.open('', 'OrderPrint', 'width=1100,height=850');
    if (win) {
        win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title><style>body { font-family: sans-serif; padding: 50px; color: #1e293b; } .header { text-align: center; border-bottom: 8px solid #000; padding-bottom: 25px; margin-bottom: 35px; } .brand { font-size: 42px; font-weight: 900; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 25px; margin-bottom: 40px; } .box { padding: 20px; border: 3px solid #1e293b; border-radius:12px; } .label { font-size: 11px; font-weight: 900; color: #64748b; text-transform: uppercase; letter-spacing:1px; } .value { font-size: 22px; font-weight: 900; } table { width: 100%; border-collapse: collapse; margin-top: 25px; } th, td { border: 2px solid #1e293b; padding: 15px; text-align: center; } th { background: #f1f5f9; font-weight:900; } .section-title { font-size: 20px; font-weight: 900; border-bottom: 4px solid #1e293b; margin-top: 50px; margin-bottom: 20px; text-transform: uppercase; letter-spacing:2px; }</style></head><body><div class="header"><div class="brand">TINTURA SST</div><div style="font-size:18px; font-weight:700; color:#64748b; text-transform:uppercase; letter-spacing:4px; margin-top:5px;">Manufacturing Execution Document</div></div><div class="grid"><div class="box"><span class="label">Job ID</span><div class="value">${formattedNo}</div></div><div class="box"><span class="label">Technical Reference</span><div class="value">${order.style_number}</div></div><div class="box"><span class="label">Job Volume</span><div class="value">${order.quantity} PCS</div></div></div><div class="section-title">Job Matrix Breakdown</div><table><thead><tr><th style="text-align:left;">Color Group</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Sum</th></tr></thead><tbody>${breakdownRows}</tbody></table><div class="section-title">Master Production Instructions</div><div style="padding:25px; border:3px solid #1e293b; font-size:24px; font-weight:900; border-radius:16px; background:#f8fafc; line-height:1.3;">${order.description || 'N/A'}</div>${reqSheetHtml}${techPackHtml}<script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script></body></html>`);
        win.document.close();
    }
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-start bg-white"><div><h3 className="text-3xl font-black text-slate-800 tracking-tight">{formatOrderNumber(order)}</h3></div><div className="flex items-center gap-3">{!isEditing && <button onClick={() => setIsEditing(true)} className="bg-indigo-50 text-indigo-700 border border-indigo-100 px-5 py-2.5 rounded-xl text-sm font-black hover:bg-indigo-600 hover:text-white transition-all"><Pencil size={18} /> Modify Order</button>}<button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full"><X size={32}/></button></div></div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/20">
          <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 flex items-center gap-3"><BookOpen size={20} className="text-indigo-600"/><div><p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest leading-none">Style DB Synchronized</p><p className="text-sm font-bold text-indigo-900 mt-1">Granular material forecasts calculated based on color and size specific ratios.</p></div></div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6"><div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Volume</span><div className="text-2xl font-black text-slate-800">{isEditing ? getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]) : order.quantity} PCS</div></div><div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Delivery</span>{isEditing ? <input type="date" className="w-full border rounded p-2" value={editFormData.target_delivery_date} onChange={e => setEditFormData({...editFormData, target_delivery_date: e.target.value})}/> : <div className="text-lg font-black">{order.target_delivery_date}</div>}</div><div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2"><Box size={10}/> Planned Boxes</span>{isEditing ? <input type="number" className="w-full border rounded p-2" value={editFormData.box_count} onChange={e => setEditFormData({...editFormData, box_count: parseInt(e.target.value) || 0})}/> : <div className="text-lg font-black">{order.box_count}</div>}</div><div className="p-5 bg-indigo-50 rounded-2xl border border-indigo-100 shadow-sm"><span className="block text-[10px] text-indigo-400 uppercase font-black mb-2">Unit</span>{isEditing ? <select className="w-full border rounded p-2 bg-white font-bold" value={editFormData.unit_id} onChange={e => setEditFormData({...editFormData, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select> : <div className="text-lg font-black text-indigo-900">{units.find(u => u.id === order.unit_id)?.name}</div>}</div></div>

          {/* GRANULAR REQUIREMENTS FORECAST SECTION */}
          {detailedReqs.length > 0 && (
            <div className="space-y-4 animate-fade-in">
              <div className="flex items-center gap-3">
                <Calculator size={20} className="text-indigo-600"/>
                <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Granular Material Forecast</h4>
              </div>
              <div className="grid grid-cols-1 gap-6">
                {detailedReqs.map((req, i) => (
                  <div key={i} className="bg-white rounded-3xl border border-indigo-100 shadow-sm overflow-hidden group">
                    <div className="p-5 bg-indigo-600 text-white flex items-center justify-between">
                      <span className="font-black uppercase tracking-widest text-sm">{req.name}</span>
                      <div className="flex items-center gap-4">
                         <span className="text-[10px] font-bold opacity-60 uppercase">Calculated Job Total</span>
                         <span className="text-xl font-black">{req.total}</span>
                      </div>
                    </div>
                    <div className="p-6">
                      <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
                        {req.breakdown.map((b, idx) => (
                          <div key={idx} className="p-4 bg-slate-50 rounded-2xl border border-slate-200 space-y-3 hover:border-indigo-300 transition-colors">
                            <div className="flex justify-between items-start">
                              <div>
                                <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest block mb-1">{b.label}</span>
                                <span className="text-xs font-bold text-slate-500">Volume: {b.count} Pcs</span>
                              </div>
                              <div className="text-right">
                                <span className="text-xl font-black text-indigo-700">{b.calc}</span>
                                <span className="text-[8px] block font-black text-slate-400 uppercase">Estimated</span>
                              </div>
                            </div>

                            <div className="p-3 bg-white rounded-xl border border-slate-100">
                               <p className="text-xs font-bold text-slate-700 leading-relaxed italic">"{b.text || 'No specific notes.'}"</p>
                               {b.attachments.length > 0 && (
                                 <div className="mt-3 flex flex-wrap gap-2">
                                    {b.attachments.map((att, attIdx) => (
                                      <a key={attIdx} href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 px-2 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[9px] font-black border border-indigo-100 hover:bg-indigo-100 transition-all">
                                        {att.type === 'image' ? <ImageIcon size={10}/> : <FileText size={10}/>} {att.name}
                                      </a>
                                    ))}
                                 </div>
                               )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div><div className="flex justify-between items-center mb-4"><h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product breakdown matrix</h4>{isEditing && <button type="button" onClick={() => setUseNumericSizes(!useNumericSizes)} className="text-[10px] bg-slate-100 px-4 py-2 rounded-xl border border-slate-200 font-black uppercase"><ArrowLeftRight size={14} className="inline mr-2"/> Switch Size Format</button>}</div><div className="border border-slate-200 rounded-3xl overflow-hidden shadow-sm bg-white"><table className="w-full text-center text-sm border-collapse"><thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b"><tr><th className="p-4 text-left border-r">Color Variant</th>{getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}<th className="p-4 bg-slate-100">Sum</th>{isEditing && <th className="p-4 w-12"></th>}</tr></thead><tbody className="divide-y divide-slate-100">{(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (<tr key={idx} className="hover:bg-slate-50/50 transition-colors"><td className="p-4 text-left font-black text-slate-700 border-r">{isEditing ? <input className="w-full border rounded p-1 font-bold" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : row.color}</td>{['s','m','l','xl','xxl','xxxl'].map(key => (<td key={key} className="p-4 border-r">{isEditing ? <input type="number" className="w-16 border rounded p-1 text-center font-black" value={(row as any)[key]} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; (bd[idx] as any)[key] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : (order.size_breakdown?.[idx]?.[key as keyof SizeBreakdown] || 0)}</td>))}<td className="p-4 font-black text-slate-900 bg-slate-50/50 tabular-nums">{getRowTotal(row)}</td>{isEditing && <td className="p-4"><button onClick={() => setEditFormData({...editFormData, size_breakdown: (editFormData.size_breakdown || []).filter((_, i) => i !== idx)})} className="text-red-400 hover:text-red-600 transition-colors"><Trash2 size={20}/></button></td>}</tr>))}</tbody></table>{isEditing && <button onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }]})} className="w-full py-4 bg-slate-50 text-indigo-600 text-xs font-black uppercase border-t hover:bg-indigo-50 transition-colors">+ Add Color Variant</button>}</div></div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm"><span className="block text-[11px] text-slate-400 uppercase font-black mb-3">Master production notes</span>{isEditing ? <textarea className="w-full border border-slate-200 rounded-2xl p-4 h-48 font-medium" value={editFormData.description} onChange={e => setEditFormData({...editFormData, description: e.target.value})}/> : <p className="text-xl text-slate-800 font-black whitespace-pre-wrap leading-relaxed">{order.description || 'N/A'}</p>}</div><div className="p-6 bg-indigo-50/30 rounded-3xl border border-indigo-100 shadow-inner"><h4 className="font-black text-indigo-400 uppercase text-[10px] flex items-center gap-2 mb-4"><Paperclip size={14}/> Technical documents</h4><div className="space-y-3">{(isEditing ? editFormData.attachments : order.attachments)?.map((att, i) => (<div key={i} className="flex items-center justify-between p-4 bg-white rounded-xl border border-indigo-50 group hover:shadow-md transition-all"><a href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-4 flex-1">{att.type === 'image' ? <ImageIcon size={20} className="text-indigo-400" /> : <FileText size={20} className="text-indigo-400" />}<span className="text-sm font-black text-slate-700 truncate">{att.name}</span></a>{isEditing && <button onClick={() => setEditFormData({...editFormData, attachments: (editFormData.attachments || []).filter((_, idx) => idx !== i)})} className="text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={20}/></button>}</div>))}{isEditing && <div className="mt-4 border-2 border-dashed border-indigo-100 rounded-2xl p-6 text-center relative hover:bg-white transition-all cursor-pointer"><input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/><Upload size={32} className="mx-auto text-indigo-400"/><p className="text-[10px] font-black text-indigo-600 uppercase mt-2 tracking-widest">Add technical files</p></div>}</div></div></div>

          <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col"><h4 className="font-black text-indigo-900 uppercase text-[10px] flex items-center gap-2 mb-6"><Clock size={16}/> Lifecycle status log</h4><div className="space-y-6 max-h-[400px] overflow-y-auto pr-4">{modalLogs.map(log => (<div key={log.id} className="flex gap-4 border-l-4 border-indigo-100 pl-6 pb-2 transition-all hover:border-indigo-400"><div className="font-black text-[10px] text-slate-400 uppercase leading-none pt-1">{new Date(log.created_at).toLocaleDateString()}<br/><span className="text-indigo-400 opacity-60 font-bold">{new Date(log.created_at).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></div><div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-200"><p className="text-slate-700 font-bold leading-snug">{log.message}</p></div></div>))}</div></div>
        </div>
        <div className="p-6 border-t bg-slate-50 flex justify-between items-center"><button onClick={() => { if(confirm("Permanently delete this order?")) deleteOrder(order.id).then(() => {onRefresh(); onClose();}); }} className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all"><Trash2 size={24}/></button><div className="flex items-center gap-4"><button onClick={handlePrint} className="px-8 py-3 bg-white text-indigo-600 border-2 border-indigo-600 rounded-xl font-black uppercase text-xs flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all"><Printer size={16}/> Print Job Sheet</button><button onClick={onClose} className="px-10 py-3 bg-slate-800 text-white rounded-xl font-black uppercase text-xs hover:bg-slate-700 transition-all">Close</button>{isEditing && <button onClick={handleSave} disabled={isUploading} className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black uppercase text-xs shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all">{isUploading ? <Loader2 className="animate-spin inline mr-2" size={16}/> : null}{isUploading ? 'Saving...' : 'Save Job'}</button>}</div></div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, SizeBreakdown, Style, ConsumptionType, Attachment } from '../../types';
import { X, ImageIcon, FileText, Download, Paperclip, Printer, Box, Calculator } from 'lucide-react';
import { fetchStyleByNumber } from '../../services/db';

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

interface OrderDetailsModalProps {
  order: Order;
  useNumericSizes: boolean;
  onToggleSizeFormat: () => void;
  onClose: () => void;
  onPrint: () => void;
}

export const OrderDetailsModal: React.FC<OrderDetailsModalProps> = ({
  order,
  useNumericSizes,
  onClose,
  onPrint
}) => {
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);

  useEffect(() => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
      fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.style_number]);

  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global Requirement",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const renderDetailCell = (rowIdx: number, sizeKey: keyof SizeBreakdown) => {
    const plannedRow = order.size_breakdown?.[rowIdx];
    const actualRow = order.completion_breakdown?.[rowIdx];
    const plannedVal = plannedRow ? (plannedRow[sizeKey] as number) : 0;

    if (order.status !== OrderStatus.COMPLETED || !actualRow) {
      return <span className="text-slate-600 font-medium">{plannedVal}</span>;
    }

    const actualVal = actualRow[sizeKey] as number;
    const isMismatch = actualVal !== plannedVal;

    return (
      <div className="flex flex-col items-center justify-center p-1 bg-slate-50 rounded border border-slate-100">
        <span className={`text-lg font-black ${isMismatch ? 'text-indigo-700' : 'text-slate-900'}`}>
          {actualVal}
        </span>
        <span className="text-[10px] font-bold text-slate-400 border-t border-slate-200 w-full text-center mt-0.5 pt-0.5">
          Plan: {plannedVal}
        </span>
      </div>
    );
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden max-h-[95vh] flex flex-col animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <div>
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{order.order_no}</h3>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Production Execution Details</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={28} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Style Number</span>
              <span className="text-lg font-black text-slate-800">{order.style_number}</span>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Delivery Date</span>
              <span className="text-lg font-black text-slate-800">{order.target_delivery_date}</span>
            </div>
            <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 shadow-sm">
              <span className="block text-indigo-400 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Planned Boxes</span>
              <span className="text-xl font-black text-indigo-800">{order.box_count || '---'}</span>
            </div>
            {order.status === OrderStatus.COMPLETED && (
               <div className="p-4 bg-green-50 rounded-xl border border-green-100 shadow-sm animate-fade-in">
                <span className="block text-green-500 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Actual Packed</span>
                <span className="text-xl font-black text-green-800">{order.actual_box_count}</span>
              </div>
            )}
          </div>

          {/* DETAILED REQUIREMENTS SECTION */}
          {detailedReqs.length > 0 && (
            <div className="space-y-4 animate-fade-in">
              <div className="p-4 bg-indigo-600 text-white rounded-t-2xl flex items-center justify-between">
                <h4 className="font-black uppercase tracking-[0.1em] text-xs flex items-center gap-2"><Calculator size={16}/> Segmented Material Requirements</h4>
                <span className="text-[10px] font-bold opacity-70">SYNCED FROM MASTER TECH-PACK</span>
              </div>
              <div className="space-y-4">
                {detailedReqs.map((req, i) => (
                  <div key={i} className="bg-white rounded-2xl border border-indigo-100 overflow-hidden shadow-sm">
                    <div className="px-5 py-3 bg-indigo-50 border-b border-indigo-100 flex justify-between items-center">
                       <span className="font-black text-indigo-900 text-sm">{req.name}</span>
                       <span className="font-black text-indigo-700">Total: {req.total}</span>
                    </div>
                    <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                      {req.breakdown.map((b, idx) => (
                        <div key={idx} className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-2">
                           <div className="flex justify-between items-center">
                              <span className="text-[9px] font-black text-slate-500 uppercase">{b.label}</span>
                              <span className="text-sm font-black text-indigo-600">{b.calc} Req.</span>
                           </div>
                           <p className="text-xs text-slate-600 font-medium italic">"{b.text || 'No segments notes.'}"</p>
                           {b.attachments.length > 0 && (
                             <div className="flex flex-wrap gap-2 mt-2">
                                {b.attachments.map((att, attIdx) => (
                                  <a key={attIdx} href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 px-2 py-1 bg-white border rounded text-[9px] font-bold text-slate-500 hover:text-indigo-600 hover:border-indigo-200 transition-all">
                                    {att.type === 'image' ? <ImageIcon size={10}/> : <FileText size={10}/>} {att.name}
                                  </a>
                                ))}
                             </div>
                           )}
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">
                Production Matrix
                {order.status === OrderStatus.COMPLETED && <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full ml-3 border border-indigo-100 uppercase tracking-widest">Actual / Planned</span>}
              </h4>
            </div>
            <div className="border border-slate-200 rounded-2xl overflow-hidden shadow-md">
              <table className="w-full text-center text-sm border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-4 text-left border-r">Color Variant</th>
                    {getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}
                    <th className="p-4 font-black bg-slate-100">Row Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {order.size_breakdown?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="p-4 text-left font-black text-slate-700 border-r">{row.color}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 's')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'm')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'l')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxxl')}</td>
                      <td className="p-4 font-black bg-slate-50/50 text-slate-800 tabular-nums">{getRowTotal(row)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="p-6 bg-slate-50/50 rounded-2xl border border-slate-200 shadow-inner">
              <h4 className="font-black text-slate-400 mb-4 uppercase tracking-widest text-[10px]">Production Instructions</h4>
              <p className="text-base text-slate-600 font-medium whitespace-pre-wrap leading-relaxed">{order.description || "No specific instructions provided."}</p>
            </div>
            <div className="p-6 bg-indigo-50/30 rounded-2xl border border-indigo-100 shadow-inner">
              <h4 className="font-black text-indigo-400 mb-4 uppercase tracking-widest text-[10px] flex items-center gap-2">
                <Paperclip size={14}/> Technical Reference Files
              </h4>
              <div className="space-y-3">
                {order.attachments && order.attachments.length > 0 ? (
                  order.attachments.map((att, i) => (
                    <a key={i} href={att.url} target="_blank" rel="noreferrer" className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-200 hover:shadow-lg transition-all group">
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-100 rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                          {att.type === 'image' ? <ImageIcon size={20} /> : <FileText size={20} />}
                        </div>
                        <span className="text-sm font-bold text-slate-700 truncate max-w-[200px]">{att.name}</span>
                      </div>
                      <Download size={18} className="text-slate-300 group-hover:text-indigo-600 transition-colors" />
                    </a>
                  ))
                ) : (
                  <div className="text-center py-10 text-slate-300">
                    <Paperclip size={32} className="mx-auto opacity-20 mb-2" />
                    <p className="text-[10px] uppercase font-black tracking-widest opacity-60">No documents attached</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
        <div className="p-6 border-t bg-slate-50 text-right flex justify-end gap-4 shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.03)]">
          <button onClick={onPrint} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest text-xs">
            <Printer size={18} /> Print Full Job Sheet
          </button>
          <button onClick={onClose} className="bg-slate-800 text-white px-10 py-3 rounded-xl font-black hover:bg-slate-700 transition-all active:scale-95 uppercase tracking-widest text-xs">Close</button>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleByNumber, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber, Style, ConsumptionType, Attachment } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC && order.status !== OrderStatus.QC_APPROVED) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }))
                : [{ color: 'Standard', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actualBoxCount });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  const handleDeleteRequest = async (id: string) => {
      if (!confirm("Are you sure?")) return;
      await deleteMaterialRequest(id);
      handleOpenMaterialHistory();
  };

  const handleEditRequest = (req: MaterialRequest) => {
      setIsEditingRequest({ id: req.id, originalData: req });
      setMaterialModal(req.order_id);
      setShowMaterialHistory(false);
  };

  const handleGenerateAndPrintBarcodes = async (qty: number, size: string) => {
    if (!barcodeModal) return;
    const newBarcodes = await generateBarcodes(barcodeModal.orderId, qty, barcodeModal.style, size);
    setBarcodeModal(null);
    const win = window.open('', 'PrintBarcodes', 'width=1000,height=800');
    if (win) {
        const labelsHtml = newBarcodes.map(b => `<div class="label"><div class="header">TINTURA SST</div><div class="meta"><strong>Style:</strong> ${b.style_number} &nbsp; <strong>Size:</strong> ${b.size}</div><svg class="barcode" jsbarcode-format="CODE128" jsbarcode-value="${b.barcode_serial}" jsbarcode-textmargin="0" jsbarcode-fontoptions="bold" jsbarcode-height="40" jsbarcode-width="2" jsbarcode-displayValue="true" jsbarcode-fontSize="11"></svg></div>`).join('');
        win.document.write(`<html><head><title>Print Labels</title><script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script><style>@page { size: A4; margin: 10mm; } body { margin: 0; font-family: sans-serif; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-auto-rows: 35mm; column-gap: 5mm; row-gap: 2mm; } .label { border: 1px dashed #ddd; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 5px; overflow: hidden; text-align: center; background: white; } .header { font-size: 10px; font-weight: bold; text-transform: uppercase; margin: 2px; } .meta { font-size: 10px; margin-bottom: 2px; color: #333; } svg { max-width: 95%; height: auto; display: block; }</style></head><body><div class="grid">${labelsHtml}</div><script>window.onload = function() { JsBarcode(".barcode").init(); setTimeout(() => { window.print(); }, 500); }</script></body></html>`); 
        win.document.close();
    }
  };

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (order: Order, linkedStyle: Style): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + ( (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0) ), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global Requirement",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const handlePrintOrderSheet = async (order: Order) => {
      let techPackHtml = '';
      let reqSheetHtml = '';

      const styleRefPart = order.style_number.split(' - ')[0].trim();
      if (styleRefPart) {
          const [style, template] = await Promise.all([
              fetchStyleByNumber(styleRefPart),
              fetchStyleTemplate()
          ]);

          if (style && template) {
              const detailedReqs = getDetailedRequirements(order, style);
              if (detailedReqs.length > 0) {
                reqSheetHtml = `
                  <div style="margin-top:50px; page-break-before:always;">
                    <h2 style="background:#4f46e5; color:#fff; padding:20px 30px; font-size:24px; text-transform:uppercase; letter-spacing:4px; border-radius:12px; font-weight:900;">Segmented Job Forecast</h2>
                    <div style="margin-top:20px;">
                      ${detailedReqs.map(req => `
                        <div style="margin-bottom:40px; border:2px solid #cbd5e1; border-radius:20px; overflow:hidden; background:#fff;">
                          <div style="background:#f1f5f9; padding:15px 25px; border-bottom:2px solid #cbd5e1; display:flex; justify-content:space-between; align-items:center;">
                            <span style="font-size:18px; font-weight:900; text-transform:uppercase; color:#1e293b;">${req.name}</span>
                            <span style="font-size:20px; font-weight:900; color:#4f46e5;">Job Total: ${req.total}</span>
                          </div>
                          <div style="padding:20px;">
                            <table style="width:100%; border-collapse:collapse;">
                              <thead>
                                <tr style="background:#f8fafc;">
                                  <th style="padding:10px; border:1px solid #cbd5e1; text-align:left; font-size:11px;">Job Segment</th>
                                  <th style="padding:10px; border:1px solid #cbd5e1; text-align:right; font-size:11px;">Needed</th>
                                  <th style="padding:10px; border:1px solid #cbd5e1; text-align:left; font-size:11px;">Technical Specifics</th>
                                </tr>
                              </thead>
                              <tbody>
                                ${req.breakdown.map(b => `
                                  <tr>
                                    <td style="padding:12px; border:1px solid #cbd5e1; font-weight:bold; font-size:13px; width:150px;">${b.label}</td>
                                    <td style="padding:12px; border:1px solid #cbd5e1; text-align:right; font-weight:900; color:#4f46e5; font-size:18px; width:100px;">${b.calc}</td>
                                    <td style="padding:12px; border:1px solid #cbd5e1; font-size:13px; color:#334155;">
                                      <div style="font-weight:700; font-size:15px; margin-bottom:8px;">${b.text || '---'}</div>
                                      <div style="display:grid; grid-template-columns:1fr 1fr; gap:10px;">
                                        ${b.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}" style="width:100%; border-radius:10px;" />`).join('')}
                                      </div>
                                    </td>
                                  </tr>
                                `).join('')}
                              </tbody>
                            </table>
                          </div>
                        </div>
                      `).join('')}
                    </div>
                  </div>
                `;
              }

              techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                  const fields = cat.fields.map(f => {
                      const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                      let contentHtml = '';
                      if (item.variants) {
                        contentHtml = item.variants.map(v => {
                          let sizeHtml = '';
                          if (v.sizeVariants) {
                            sizeHtml = `<div style="margin-top:15px; display:grid; grid-template-columns:1fr; gap:12px;">${v.sizeVariants.map(sv => `
                              <div style="background:#fff; border:1px solid #e2e8f0; border-left:10px solid #2563eb; padding:20px; border-radius:12px;">
                                <div style="margin-bottom:12px; display:flex; flex-wrap:wrap; gap:6px;">
                                  ${sv.sizes.map(sz => `<span style="background:#2563eb; color:#fff; display:inline-block; padding:4px 10px; border-radius:6px; font-weight:900; font-size:18px;">SIZE: ${sz}</span>`).join('')}
                                </div>
                                <div style="font-size:20px; font-weight:900; color:#1e293b; line-height:1.3;">${sv.text || '---'}</div>
                              </div>
                            `).join('')}</div>`;
                          }
                          return `<div style="border:2px solid #e2e8f0; padding:20px; border-radius:15px; margin-top:15px; background:#f8fafc; break-inside:avoid;"><div style="margin-bottom:10px;">${v.colors.map(c => `<span style="background:#1e293b; color:#fff; font-size:10px; font-weight:900; padding:4px 10px; border-radius:5px; text-transform:uppercase; margin-right:5px;">${c}</span>`).join('')}</div><div style="font-size:22px; color:#1e293b; font-weight:900; line-height:1.3;">${v.text || '---'}</div>${sizeHtml}</div>`;
                        }).join('');
                      } else {
                        contentHtml = `<div style="font-size:24px; font-weight:900; color:#1e293b; background:#f8fafc; padding:25px; border-radius:15px; border:2px solid #e2e8f0; line-height:1.3;">${item.text || '---'}</div>`;
                      }

                      return `
                        <div style="margin-bottom:20px; border-bottom:1px solid #eee; padding-bottom:10px; break-inside:avoid;">
                          <div style="font-size:11px; font-weight:bold; color:#666; text-transform:uppercase; margin-bottom:4px;">${f}</div>
                          ${contentHtml}
                        </div>
                      `;
                  }).join('');

                  return `
                    <div style="margin-top:40px; page-break-before:always;">
                      <h3 style="background:#000; color:#fff; padding:10px; font-size:14px; text-transform:uppercase; letter-spacing:1px;">${cat.name} (Style DB Reference)</h3>
                      <div style="padding:10px;">${fields}</div>
                    </div>
                  `;
              }).join('');
          }
      }

      const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
      const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
      const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
      const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold;">${getRowTotal(row)}</td></tr>`).join('');
      const formattedNo = formatOrderNumber(order);

      let attachmentHtml = '';
      if (order.attachments && order.attachments.length > 0) {
          attachmentHtml = `<div class="section-title">Technical Documents & References</div><div style="display:flex; flex-direction:column; gap:25px;">`;
          order.attachments.forEach(att => {
              if (att.type === 'image') {
                  attachmentHtml += `<div style="border:1px solid #ccc; padding:15px; width:100%; text-align:center;"><img src="${att.url}" style="max-width:100%; max-height:800px; border-radius:8px;" /><div style="font-size:12px; margin-top:10px; font-weight:bold; text-transform:uppercase; color:#666;">REF: ${att.name}</div></div>`;
              } else if (att.url.toLowerCase().endsWith('.pdf')) {
                  attachmentHtml += `<div style="border:2px solid #333; border-radius:8px; overflow:hidden; page-break-before:always;"><div style="background:#333; color:white; padding:10px; font-weight:bold; text-align:center; font-size:14px;">PDF DOCUMENT: ${att.name}</div><iframe src="${att.url}" style="width:100%; height:1000px; border:none;"></iframe></div>`;
              } else {
                  attachmentHtml += `<div style="border:1px dashed #ccc; padding:20px; background:#f9f9f9; text-align:center; border-radius:8px;"><strong>DOCUMENT:</strong> ${att.name}</div>`;
              }
          });
          attachmentHtml += `</div>`;
      }

      const win = window.open('', 'PrintOrderSheet', 'width=1000,height=800');
      if (win) {
          win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title><style>body { font-family: 'Segoe UI', Arial, sans-serif; padding: 40px; font-size: 14px; color: #333; } .header { text-align: center; border-bottom: 5px solid #000; padding-bottom: 20px; margin-bottom: 30px; } .brand { font-size: 42px; font-weight: 900; text-transform: uppercase; margin: 0; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin: 10px 0 0 0; color: #444; } .grid { display: grid; grid-template-columns: 1fr 1fr 1fr; gap: 20px; margin-bottom: 30px; } .box { padding: 15px; border: 2px solid #333; border-radius: 6px; } .label { font-size: 11px; text-transform: uppercase; color: #666; font-weight: bold; } .value { font-size: 18px; font-weight: bold; } table { width: 100%; border-collapse: collapse; margin-top: 20px; } th, td { border: 1px solid #333; padding: 12px; text-align: center; } th { background: #f0f0f0; font-weight: 800; text-transform: uppercase; } .section-title { font-size: 18px; font-weight: 900; border-bottom: 3px solid #333; padding-bottom: 5px; margin-top: 40px; margin-bottom: 15px; text-transform: uppercase; }</style></head><body><div class="header"><div class="brand">TINTURA SST</div><div class="title">Manufacturing Job Sheet</div></div><div class="grid"><div class="box"><span class="label">Order Number</span><div class="value">${formattedNo}</div></div><div class="box"><span class="label">Style Reference</span><div class="value">${order.style_number}</div></div><div class="box"><span class="label">Total Quantity</span><div class="value">${order.quantity} PCS</div></div><div class="box"><span class="label">Planned Boxes</span><div class="value">${order.box_count || '---'}</div></div><div class="box"><span class="label">Delivery Deadline</span><div class="value">${order.target_delivery_date}</div></div></div><div class="section-title">Size Matrix Breakdown</div><table><thead><tr><th style="text-align:left;">Color</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Total</th></tr></thead><tbody>${breakdownRows}</tbody></table><div class="section-title">Production Requirements</div><div style="padding: 20px; border: 2px solid #333; min-height: 80px; background:#fcfcfc; border-radius:6px; font-size:16px;">${order.description || "No specific manufacturing notes provided."}</div>${reqSheetHtml}${attachmentHtml}${techPackHtml}<script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script></body></html>`);
          win.document.close();
      }
  };

  const handlePrintAccessoriesReceipt = (order: Order, reqs: MaterialRequest[]) => {
      const formattedNo = formatOrderNumber(order);
      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:center;">${req.unit || 'Nos'}</td><td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td></tr>`).join('');
          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:right;">${req.quantity_requested}</td><td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td><td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td><td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td></tr>`;
          }).join('');
          const headerHTML = `<div class="header"><div class="brand">TINTURA SST</div><div class="title">ACCESSORIES REQUIREMENT RECEIPT</div><div class="meta">ORDER NO: ${formattedNo} &nbsp;|&nbsp; STYLE: ${order.style_number} &nbsp;|&nbsp; DATE: ${new Date().toLocaleDateString()}</div></div>`;
          win.document.write(`<html><head><title>Accessories Receipt - ${formattedNo}</title><style>@media print { .page-break { page-break-before: always; } body { -webkit-print-color-adjust: exact; } } body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; } .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; } .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; } .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; } table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; } th, td { border: 1px solid #ccc; padding: 8px; } th { background: #f4f4f4; text-transform: uppercase; }</style></head><body>${headerHTML}<div class="page-title">Page 1: Request Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80">Unit</th><th width="100" style="text-align:right">Total Requested</th></tr></thead><tbody>${page1Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div><div class="page-break"></div>${headerHTML}<div class="page-title">Page 2: Approval & Balance Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80" style="text-align:right">Req</th><th width="80" style="text-align:right">Approved</th><th width="80" style="text-align:right">Balance</th><th width="100">Status</th></tr></thead><tbody>${page2Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div><script>window.onload = () => { setTimeout(() => window.print(), 500); };</script></body></html>`);
          win.document.close();
      }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200">
                <Box size={28}/> 
              </div>
              Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100 uppercase tracking-widest">
                Unit ID: {CURRENT_UNIT_ID}
              </div>
              <div className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">
                Sewing Section A
              </div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input type="text" placeholder="Search by Order # or Style..." className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full bg-white text-slate-900 shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50 shadow-sm transition-all active:scale-95"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5"><AlertTriangle size={12}/> QC Feedback</div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => handlePrintOrderSheet(detailsModal)} 
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchStyles, upsertStyle, fetchStyleTemplate, updateStyleTemplate, deleteStyle, uploadOrderAttachment } from '../services/db';
import { Style, StyleTemplate, StyleCategory, TechPackItem, Attachment, TechPackVariant, TechPackSizeVariant, ConsumptionType } from '../types';
import { 
  Plus, Search, Grid, Copy, Trash2, Save, Printer, Edit3, X, Image as ImageIcon, FileText, Settings, ArrowLeftRight, Loader2, Download, Layers, BookOpen, Palette, Ruler, ChevronDown, ChevronUp, ChevronRight, Info, ArrowLeft, ExternalLink, Split, Scan, Calculator, CheckSquare, Square, Filter
} from 'lucide-react';

// --- Sub-components ---

interface ConsumptionInputProps {
  type?: ConsumptionType;
  value?: number;
  onChange: (type: ConsumptionType, val: number) => void;
  onClear: () => void;
}

const ConsumptionInput: React.FC<ConsumptionInputProps> = ({ type, value, onChange, onClear }) => {
  if (!type) {
    return (
      <button 
        type="button" 
        onClick={() => onChange('items_per_pc', 1)}
        className="text-[9px] font-black text-indigo-500 bg-indigo-50 px-3 py-1 rounded-lg border border-indigo-100 hover:bg-indigo-100 transition-all flex items-center gap-1.5"
      >
        <Calculator size={12}/> Set Ratio
      </button>
    );
  }

  return (
    <div className="flex items-center gap-2 animate-fade-in">
      <div className="flex bg-slate-200 p-0.5 rounded-lg border border-slate-300">
        <button 
          type="button" 
          onClick={() => onChange('items_per_pc', value || 0)}
          className={`px-2 py-1 rounded-md text-[8px] font-black uppercase transition-all ${type === 'items_per_pc' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          Items / PC
        </button>
        <button 
          type="button" 
          onClick={() => onChange('pcs_per_item', value || 0)}
          className={`px-2 py-1 rounded-md text-[8px] font-black uppercase transition-all ${type === 'pcs_per_item' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}
        >
          PCS / Item
        </button>
      </div>
      <input 
        type="number" 
        step="any"
        className="w-16 border border-slate-200 rounded-lg px-2 py-1 text-xs font-black text-indigo-700 bg-white focus:ring-1 focus:ring-indigo-500 outline-none"
        value={value || ''}
        onChange={e => onChange(type, parseFloat(e.target.value) || 0)}
        placeholder="Value"
      />
      <button type="button" onClick={onClear} className="text-slate-300 hover:text-red-500 transition-colors">
        <X size={14}/>
      </button>
    </div>
  );
};

interface CategoryEditorProps {
  category: StyleCategory;
  isEditing: Style | null;
  setIsEditing: (style: Style | null) => void;
  handleFileUpload: (category: string, field: string, files: FileList | null, variantIndex?: number, sizeIndex?: number) => void;
}

const CategoryEditor: React.FC<CategoryEditorProps> = ({ 
  category, 
  isEditing, 
  setIsEditing, 
  handleFileUpload 
}) => {
  if (!isEditing) return null;

  const isPackingReq = category.name.toLowerCase().includes('packing');
  const isPreProduction = category.name.toLowerCase().includes('pre production');
  const availableColors = (isEditing.available_colors || []).filter(c => c.trim() !== '');
  const availableSizes = (isEditing.available_sizes || []).filter(s => s.trim() !== '');

  const handleSplitColor = (fieldName: string) => {
    const updated = { ...isEditing };
    if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {};
    const current = updated.tech_pack[category.name][fieldName] || { text: '', attachments: [] };

    if (!current.variants) {
      current.variants = [{ colors: [], text: current.text, attachments: current.attachments, consumption_type: current.consumption_type, consumption_val: current.consumption_val }];
    } else {
      current.variants.push({ colors: [], text: '', attachments: [] });
    }

    updated.tech_pack[category.name][fieldName] = current;
    setIsEditing(updated);
  };

  const handleAddSizeGroup = (fieldName: string, vIdx: number) => {
    const updated = { ...isEditing };
    const variant = updated.tech_pack[category.name][fieldName].variants![vIdx];

    if (!variant.sizeVariants) {
      variant.sizeVariants = [{ sizes: [], text: '', attachments: [], consumption_type: variant.consumption_type, consumption_val: variant.consumption_val }];
    } else {
      variant.sizeVariants.push({ sizes: [], text: '', attachments: [] });
    }

    setIsEditing(updated);
  };

  const handleUnsplit = (fieldName: string) => {
    if (!confirm("Merge all variants into one global instruction?")) return;
    const updated = { ...isEditing };
    const current = updated.tech_pack[category.name][fieldName];
    if (current && current.variants) {
      current.text = current.variants[0].text;
      current.attachments = current.variants[0].attachments;
      current.consumption_type = current.variants[0].consumption_type;
      current.consumption_val = current.variants[0].consumption_val;
      delete current.variants;
    }
    setIsEditing(updated);
  };

  return (
    <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm mb-6">
      <div className="bg-slate-50 px-6 py-4 border-b border-slate-200 flex items-center justify-between">
        <div className="flex items-center gap-2">
          <Layers size={18} className="text-indigo-600"/>
          <h4 className="font-black text-slate-700 text-xs uppercase tracking-widest">{category.name}</h4>
        </div>
      </div>

      <div className="p-6 space-y-8">
        {isPreProduction && (
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 p-6 bg-slate-50/50 rounded-2xl border border-slate-100 shadow-inner mb-4">
            <div className="flex flex-col">
              <div className="flex items-center gap-2 mb-4">
                <Palette size={16} className="text-indigo-600"/>
                <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Blueprint Colours</label>
              </div>
              <div className="space-y-2 max-h-48 overflow-y-auto pr-2">
                {(isEditing.available_colors || ['']).map((color, idx) => (
                  <div key={idx} className="flex gap-2 group">
                    <input className="flex-1 border-2 border-slate-200 rounded-xl p-3 bg-white text-slate-900 font-bold focus:border-indigo-500 outline-none transition-all text-sm" placeholder="Type colour..." value={color} onChange={e => { const newCols = [...(isEditing.available_colors || [])]; newCols[idx] = e.target.value; setIsEditing({...isEditing, available_colors: newCols}); }} />
                    <button type="button" onClick={() => { const newCols = (isEditing.available_colors || []).filter((_, i) => i !== idx); setIsEditing({...isEditing, available_colors: newCols.length > 0 ? newCols : ['']}); }} className="p-3 text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={16}/></button>
                  </div>
                ))}
              </div>
              <button type="button" onClick={() => setIsEditing({...isEditing, available_colors: [...(isEditing.available_colors || []), '']})} className="w-full mt-4 py-2.5 border-2 border-dashed border-indigo-200 text-indigo-600 font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-white flex items-center justify-center gap-2"><Plus size={14}/> Add Colour Row</button>
            </div>
            <div className="flex flex-col">
              <div className="flex justify-between items-center mb-4"><div className="flex items-center gap-2"><Ruler size={16} className="text-indigo-600"/><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Size variants</label></div><div className="flex bg-slate-200 p-1 rounded-lg"><button type="button" onClick={() => setIsEditing({...isEditing, size_type: 'letter', available_sizes: ['S', 'M', 'L', 'XL', 'XXL', '3XL']})} className={`px-3 py-1 rounded-md text-[9px] font-black uppercase transition-all ${isEditing.size_type === 'letter' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>ABC</button><button type="button" onClick={() => setIsEditing({...isEditing, size_type: 'number', available_sizes: ['65', '70', '75', '80', '85', '90']})} className={`px-3 py-1 rounded-md text-[9px] font-black uppercase transition-all ${isEditing.size_type === 'number' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>123</button></div></div>
              <div className="flex-1 flex flex-wrap content-start gap-2 p-3 bg-white rounded-xl border border-slate-200 min-h-[100px]">{isEditing.available_sizes?.map((sz, idx) => (<div key={idx} className="bg-indigo-600 text-white px-3 py-1.5 rounded-lg text-xs font-black flex items-center gap-2 shadow-sm">{sz}<button type="button" onClick={() => { const newSizes = isEditing.available_sizes?.filter((_, i) => i !== idx); setIsEditing({...isEditing, available_sizes: newSizes}); }} className="text-white/50 hover:text-white transition-colors"><X size={12}/></button></div>))}</div>
              <button type="button" onClick={() => { const newVal = prompt(`Enter new size:`); if (newVal) setIsEditing({...isEditing, available_sizes: [...(isEditing.available_sizes || []), newVal]}); }} className="w-full mt-4 py-2.5 border-2 border-dashed border-indigo-200 text-indigo-600 font-black text-[10px] uppercase tracking-widest rounded-xl hover:bg-white flex items-center justify-center gap-2"><Plus size={14}/> Add custom size</button>
            </div>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-2 gap-x-12 gap-y-12">
          {isPackingReq && (
            <>
              <div className="space-y-3"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Type of Packing</label><select className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm cursor-pointer" value={isEditing.packing_type} onChange={e => setIsEditing({...isEditing, packing_type: e.target.value})}><option value="pouch">Pouch</option><option value="cover">Cover</option><option value="box">Box</option></select></div>
              <div className="space-y-3"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">No of pieces / Box</label><input type="number" className="w-full border-2 border-slate-100 rounded-xl p-4 bg-white text-slate-900 font-black focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm" value={isEditing.pcs_per_box} onChange={e => setIsEditing({...isEditing, pcs_per_box: parseInt(e.target.value) || 0})}/></div>
            </>
          )}

          {category.fields.map(field => {
            const item = isEditing.tech_pack[category.name]?.[field] || { text: '', attachments: [] };
            const isSplit = !!item.variants;

            return (
              <div key={field} className="space-y-4 col-span-full bg-slate-50/30 p-6 rounded-3xl border border-slate-100">
                <div className="flex justify-between items-center px-1">
                  <div className="flex items-center gap-3">
                    <label className="block text-[11px] font-black text-slate-500 uppercase tracking-widest">{field}</label>
                    {!isSplit && (
                      <ConsumptionInput 
                        type={item.consumption_type} 
                        value={item.consumption_val} 
                        onChange={(t, v) => {
                          const updated = { ...isEditing };
                          if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {};
                          updated.tech_pack[category.name][field] = { ...item, consumption_type: t, consumption_val: v };
                          setIsEditing(updated);
                        }}
                        onClear={() => {
                          const updated = { ...isEditing };
                          delete updated.tech_pack[category.name][field].consumption_type;
                          delete updated.tech_pack[category.name][field].consumption_val;
                          setIsEditing(updated);
                        }}
                      />
                    )}
                  </div>
                  {!isSplit ? (
                    <button type="button" onClick={() => handleSplitColor(field)} className="text-[10px] font-black text-indigo-600 bg-white hover:bg-indigo-50 px-4 py-2 rounded-full flex items-center gap-2 border border-indigo-100 transition-all shadow-sm"><Split size={14}/> Split Color-wise</button>
                  ) : (
                    <button type="button" onClick={() => handleUnsplit(field)} className="text-[10px] font-black text-slate-500 bg-white hover:bg-slate-100 px-4 py-2 rounded-full flex items-center gap-2 border border-slate-200 transition-all shadow-sm"><X size={14}/> Merge Global</button>
                  )}
                </div>

                {!isSplit ? (
                  <div className="space-y-3 animate-fade-in">
                    <textarea className="w-full border-2 border-slate-100 rounded-2xl p-5 text-sm font-medium focus:border-indigo-500 outline-none min-h-[100px] bg-white transition-all text-black" value={item.text} placeholder={`Global technical instructions for ${field.toLowerCase()}...`} onChange={e => { const updated = { ...isEditing }; if (!updated.tech_pack[category.name]) updated.tech_pack[category.name] = {}; updated.tech_pack[category.name][field] = { ...item, text: e.target.value }; setIsEditing(updated); }} />
                    <div className="flex flex-wrap gap-2">{item.attachments.map((att, idx) => (<div key={idx} className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-3 py-1.5 rounded-lg text-xs font-bold text-indigo-700"> {att.type === 'image' ? <ImageIcon size={14}/> : <FileText size={14}/>} <span className="truncate max-w-[100px]">{att.name}</span><button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].attachments.splice(idx, 1); setIsEditing(updated); }} className="hover:text-red-500"><X size={14}/></button></div>))} <label className="bg-white border-2 border-dashed border-slate-200 hover:border-indigo-400 hover:bg-indigo-50 text-slate-400 hover:text-indigo-600 px-4 py-2 rounded-xl text-xs font-bold transition-all cursor-pointer flex items-center gap-2"><Plus size={14}/> Add Attachment <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files)}/></label></div>
                  </div>
                ) : (
                  <div className="space-y-8 animate-fade-in">
                    {item.variants?.map((variant, vIdx) => (
                      <div key={vIdx} className="bg-white border-2 border-indigo-100 rounded-3xl p-6 shadow-sm relative group">
                        <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants?.splice(vIdx, 1); setIsEditing(updated); }} className="absolute -top-3 -right-3 bg-red-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"><X size={16}/></button>

                        <div className="mb-6 flex flex-col md:flex-row md:items-center justify-between gap-4">
                          <div className="flex-1">
                            <div className="flex items-center gap-3 mb-3">
                              <label className="block text-[10px] font-black text-indigo-400 uppercase tracking-widest">Target Color Group</label>
                              {!variant.sizeVariants && (
                                <ConsumptionInput 
                                  type={variant.consumption_type} 
                                  value={variant.consumption_val} 
                                  onChange={(t, v) => {
                                    const updated = { ...isEditing };
                                    updated.tech_pack[category.name][field].variants![vIdx] = { ...variant, consumption_type: t, consumption_val: v };
                                    setIsEditing(updated);
                                  }}
                                  onClear={() => {
                                    const updated = { ...isEditing };
                                    delete updated.tech_pack[category.name][field].variants![vIdx].consumption_type;
                                    delete updated.tech_pack[category.name][field].variants![vIdx].consumption_val;
                                    setIsEditing(updated);
                                  }}
                                />
                              )}
                            </div>
                            <div className="flex flex-wrap gap-2">{availableColors.map(color => { const isSelected = variant.colors.includes(color); return (<button type="button" key={color} onClick={() => { const updated = { ...isEditing }; const v = updated.tech_pack[category.name][field].variants![vIdx]; if (isSelected) v.colors = v.colors.filter(c => c !== color); else v.colors.push(color); setIsEditing(updated); }} className={`px-3 py-1.5 rounded-xl text-[10px] font-black uppercase transition-all ${isSelected ? 'bg-indigo-600 text-white shadow-md' : 'bg-slate-100 text-slate-400 hover:bg-slate-200'}`}>{color}</button>); })} {availableColors.length === 0 && <span className="text-[10px] text-slate-300 italic">No colors defined at top</span>}</div>
                          </div>
                          {!variant.sizeVariants && (
                            <button type="button" onClick={() => handleAddSizeGroup(field, vIdx)} className="text-[10px] font-black text-blue-600 bg-blue-50 px-4 py-2 rounded-full border border-blue-100 flex items-center gap-2 hover:bg-blue-100 transition-all shadow-sm"><Scan size={14}/> Split by Size Group</button>
                          )}
                        </div>

                        {!variant.sizeVariants ? (
                          <div className="space-y-4">
                            <textarea className="w-full border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none min-h-[80px] bg-slate-50/50 transition-all text-black" value={variant.text} placeholder="Instructions for these colors..." onChange={e => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].text = e.target.value; setIsEditing(updated); }} />
                            <div className="flex flex-wrap gap-2">{variant.attachments.map((att, attIdx) => (<div key={attIdx} className="flex items-center gap-2 bg-indigo-50 border border-indigo-100 px-2 py-1 rounded-lg text-[10px] font-bold text-indigo-700"><span>{att.name}</span><button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].attachments.splice(attIdx, 1); setIsEditing(updated); }} className="hover:text-red-500"><X size={12}/></button></div>))}<label className="bg-white border border-dashed border-slate-200 hover:border-indigo-400 text-slate-400 px-3 py-1.5 rounded-lg text-[10px] font-black transition-all cursor-pointer flex items-center gap-2"><Plus size={12}/> File <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files, vIdx)}/></label></div>
                          </div>
                        ) : (
                          <div className="space-y-6 border-l-4 border-blue-200 pl-6 py-2 animate-fade-in">
                             <div className="flex justify-between items-center mb-2"><h5 className="text-[11px] font-black text-blue-500 uppercase tracking-widest">Nested Size Groups</h5><button type="button" onClick={() => { if(confirm("Discard all size splits?")) { const updated = { ...isEditing }; delete updated.tech_pack[category.name][field].variants![vIdx].sizeVariants; setIsEditing(updated); } }} className="text-[9px] font-black text-slate-400 uppercase hover:text-red-500 transition-colors">Discard Splits</button></div>

                             {variant.sizeVariants.map((sv, svIdx) => (
                               <div key={svIdx} className="p-5 bg-blue-50/30 rounded-3xl border border-blue-100 space-y-4 relative group/size">
                                 <button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants?.splice(svIdx, 1); setIsEditing(updated); }} className="absolute -top-2 -right-2 bg-white text-red-400 p-1.5 rounded-full shadow border border-red-50 opacity-0 group-hover/size:opacity-100 transition-opacity"><Trash2 size={12}/></button>

                                 <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                                   <div>
                                     <label className="block text-[9px] font-black text-blue-400 uppercase mb-2 tracking-widest">Apply to Sizes</label>
                                     <div className="flex flex-wrap gap-1.5">
                                       {availableSizes.map(sz => {
                                         const isSzSelected = sv.sizes.includes(sz);
                                         return (
                                           <button
                                             type="button"
                                             key={sz}
                                             onClick={() => {
                                               const updated = { ...isEditing };
                                               const sVar = updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx];
                                               if (isSzSelected) sVar.sizes = sVar.sizes.filter(s => s !== sz);
                                               else sVar.sizes.push(sz);
                                               setIsEditing(updated);
                                             }}
                                             className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase transition-all ${isSzSelected ? 'bg-blue-600 text-white' : 'bg-white text-blue-300 border border-blue-50 hover:bg-blue-50'}`}
                                           >
                                             {sz}
                                           </button>
                                         );
                                       })}
                                     </div>
                                   </div>
                                   <ConsumptionInput 
                                    type={sv.consumption_type} 
                                    value={sv.consumption_val} 
                                    onChange={(t, v) => {
                                      const updated = { ...isEditing };
                                      updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx] = { ...sv, consumption_type: t, consumption_val: v };
                                      setIsEditing(updated);
                                    }}
                                    onClear={() => {
                                      const updated = { ...isEditing };
                                      delete updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].consumption_type;
                                      delete updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].consumption_val;
                                      setIsEditing(updated);
                                    }}
                                  />
                                 </div>

                                 <textarea className="w-full border-2 border-white rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-blue-500 outline-none bg-white min-h-[70px] text-black transition-all" value={sv.text} placeholder={`Specific instructions for the selected sizes...`} onChange={e => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].text = e.target.value; setIsEditing(updated); }}/>

                                 <div className="flex flex-wrap gap-2">
                                    {sv.attachments.map((att, attIdx) => (<div key={attIdx} className="flex items-center gap-2 bg-white border border-blue-50 px-2 py-1 rounded-lg text-[9px] font-bold text-blue-700"><span>{att.name}</span><button type="button" onClick={() => { const updated = { ...isEditing }; updated.tech_pack[category.name][field].variants![vIdx].sizeVariants![svIdx].attachments.splice(attIdx, 1); setIsEditing(updated); }} className="text-red-400"><X size={10}/></button></div>))}
                                    <label className="bg-white border-2 border-dashed border-blue-100 hover:border-blue-400 text-blue-300 px-3 py-1 rounded-xl text-[9px] font-black cursor-pointer flex items-center gap-2"><Plus size={12}/> File <input type="file" multiple className="hidden" onChange={e => handleFileUpload(category.name, field, e.target.files, vIdx, svIdx)}/></label>
                                 </div>
                               </div>
                             ))}

                             <button type="button" onClick={() => handleAddSizeGroup(field, vIdx)} className="w-full py-3 border-2 border-dashed border-blue-100 text-blue-300 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-blue-50 hover:text-blue-500 transition-all">+ Add Nested Size Group</button>
                          </div>
                        )}
                      </div>
                    ))}
                    <button type="button" onClick={() => handleSplitColor(field)} className="w-full py-5 border-4 border-dashed border-slate-100 text-slate-300 text-[11px] font-black uppercase tracking-[0.2em] rounded-3xl hover:border-indigo-200 hover:text-indigo-400 transition-all">+ Add Color Variant Group</button>
                  </div>
                )}
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
};

const StyleFullView: React.FC<{ style: Style, template: StyleTemplate | null, onBack: () => void, onPrint: () => void, onEdit: () => void }> = ({ style, template, onBack, onPrint, onEdit }) => {
