                            {template?.config.filter(c => !c.name.toLowerCase().includes('packing') && !c.name.toLowerCase().includes('pre production')).map(cat => (
                              <th key={cat.name} className="p-2 border-r border-slate-800" colSpan={cat.fields.length}>{cat.name}</th>
                            ))}
