                                      onClear={() => {
                                        const { consumption_type, consumption_val, ...rest } = fieldData;
                                        setBulkFieldValues(prev => ({ ...prev, [fieldKey]: rest as any }));
                                      }}
                                   />
                                )}
                             </div>

