};

import React, { useState, useRef } from 'react';
import { X, FileUp, CheckCircle2, AlertCircle, Loader2, Save, ChevronDown, Check } from 'lucide-react';
import { Style, StyleTemplate, TechPackItem } from '../../types';
import { upsertStyle } from '../../services/db';

interface BulkAttributeUpdateModalProps {
  styles: Style[];
  template: StyleTemplate | null;
  onClose: () => void;
  onRefresh: () => void;
}

interface UpdateSummary {
  updated: number;
  notFound: string[];
  total: number;
}

export const BulkAttributeUpdateModal: React.FC<BulkAttributeUpdateModalProps> = ({ styles, template, onClose, onRefresh }) => {
  const [isProcessing, setIsProcessing] = useState(false);
  const [selectedField, setSelectedField] = useState<string>('style_text');
  const [summary, setSummary] = useState<UpdateSummary | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Define available fields for the dropdown
  const fieldOptions = [
    { id: 'style_text', label: 'Short Description', type: 'basic' },
    { id: 'garment_type', label: 'Garment Type', type: 'basic' },
    { id: 'demographic', label: 'Demographic', type: 'basic' },
    { id: 'category', label: 'Category', type: 'basic' },
    { id: 'packing_type', label: 'Packing Type', type: 'basic' },
    { id: 'pcs_per_box', label: 'Pcs Per Box', type: 'basic' },
  ];

  // Add template-based technical fields
  if (template) {
    template.config.forEach(cat => {
      cat.fields.forEach(f => {
        fieldOptions.push({ id: `tech|${cat.name}|${f}`, label: `${cat.name} → ${f}`, type: 'tech' });
      });
    });
  }

  const processCSV = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsProcessing(true);
    setSummary(null);

    const reader = new FileReader();
    reader.onload = async (event) => {
      const text = event.target?.result as string;
      const lines = text.split(/\r?\n/).filter(line => line.trim() !== '');

      const splitCSV = (row: string) => {
        const regex = /,(?=(?:(?:[^"]*"){2})*[^"]*$)/;
        return row.split(regex).map(val => {
          let cleaned = val.trim();
          if (cleaned.startsWith('"') && cleaned.endsWith('"')) {
            cleaned = cleaned.substring(1, cleaned.length - 1);
          }
          return cleaned;
        });
      };

      const rows = lines.map(splitCSV);
      let updatedCount = 0;
      const notFoundStyles: string[] = [];

      // Start processing from row 0 or 1 depending on header detection (assuming simple 2 columns)
      // We check if the first row looks like a header (Style Number / StyleNo etc)
      const firstRowLabel = rows[0][0].toLowerCase();
      const startIndex = (firstRowLabel.includes('style') || firstRowLabel.includes('number')) ? 1 : 0;

      for (let i = startIndex; i < rows.length; i++) {
        const [styleNum, value] = rows[i];
        if (!styleNum) continue;

        const targetStyle = styles.find(s => s.style_number.trim().toLowerCase() === styleNum.trim().toLowerCase());

        if (targetStyle) {
          const updated = JSON.parse(JSON.stringify(targetStyle));

          if (selectedField.startsWith('tech|')) {
            const [, catName, fieldName] = selectedField.split('|');
            if (!updated.tech_pack[catName]) updated.tech_pack[catName] = {};
            if (!updated.tech_pack[catName][fieldName]) {
              updated.tech_pack[catName][fieldName] = { text: value, attachments: [] };
            } else {
              updated.tech_pack[catName][fieldName].text = value;
            }
          } else {
            // Basic field update
            if (selectedField === 'pcs_per_box') {
              updated[selectedField] = parseInt(value) || 0;
            } else {
              (updated as any)[selectedField] = value;
            }
          }

          const { error } = await upsertStyle(updated);
          if (!error) updatedCount++;
        } else {
          notFoundStyles.push(styleNum);
        }
      }

      setSummary({
        updated: updatedCount,
        notFound: notFoundStyles,
        total: rows.length - startIndex
      });
      setIsProcessing(false);
      onRefresh();
    };
    reader.readAsText(file);
    e.target.value = ''; // Reset
  };

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-[110] flex items-center justify-center p-4 backdrop-blur-md">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl overflow-hidden animate-scale-up border border-slate-200 flex flex-col">
        <div className="p-6 border-b bg-green-50 flex justify-between items-center shrink-0">
          <div>
            <h3 className="text-xl font-black text-green-900 uppercase tracking-tight flex items-center gap-2">
              <FileUp size={24}/> Attribute Value Synchronizer
            </h3>
            <p className="text-green-700 text-[10px] font-bold uppercase tracking-widest mt-1">Update specific fields across multiple styles using CSV</p>
          </div>
          <button onClick={onClose} className="text-green-400 hover:text-green-600 p-2"><X size={28}/></button>
        </div>

        <div className="p-8 flex-1 space-y-8 bg-white">
          <div className="space-y-4">
            <div className="flex items-center gap-3 mb-2">
              <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-black text-xs">1</div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest">Select Target Field</label>
            </div>
            <div className="relative group">
              <select 
                className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-5 py-4 text-sm font-black text-slate-700 outline-none focus:ring-4 focus:ring-indigo-100 cursor-pointer shadow-sm transition-all appearance-none"
                value={selectedField}
                onChange={e => setSelectedField(e.target.value)}
              >
                <optgroup label="Basic Style Fields">
                  {fieldOptions.filter(o => o.type === 'basic').map(opt => (
                    <option key={opt.id} value={opt.id}>{opt.label}</option>
                  ))}
                </optgroup>
                <optgroup label="Technical Blueprint Fields">
                  {fieldOptions.filter(o => o.type === 'tech').map(opt => (
                    <option key={opt.id} value={opt.id}>{opt.label}</option>
                  ))}
                </optgroup>
              </select>
              <ChevronDown className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 pointer-events-none group-hover:text-indigo-500 transition-colors" size={20}/>
            </div>
          </div>

          <div className="space-y-4">
            <div className="flex items-center gap-3 mb-2">
              <div className="w-8 h-8 rounded-full bg-indigo-100 text-indigo-600 flex items-center justify-center font-black text-xs">2</div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest">Upload 2-Column CSV</label>
            </div>

            <div 
              onClick={() => !isProcessing && fileInputRef.current?.click()}
              className={`border-4 border-dashed rounded-3xl p-10 text-center transition-all cursor-pointer group ${isProcessing ? 'border-slate-100 bg-slate-50' : 'border-indigo-100 bg-indigo-50/20 hover:border-indigo-400 hover:bg-white'}`}
            >
              <input type="file" accept=".csv" ref={fileInputRef} className="hidden" onChange={processCSV} />
              {isProcessing ? (
                <div className="flex flex-col items-center">
                  <Loader2 className="text-indigo-600 animate-spin mb-3" size={40}/>
                  <p className="font-black text-slate-600 uppercase tracking-widest text-sm">Processing Style Mapping...</p>
                </div>
              ) : (
                <div className="flex flex-col items-center">
                  <FileUp className="text-indigo-300 group-hover:text-indigo-600 mb-3 transition-colors" size={48}/>
                  <p className="font-black text-slate-700 uppercase tracking-widest text-sm">Drop .CSV File Here</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase mt-2">Col A: Style Number &nbsp;|&nbsp; Col B: New Value</p>
                </div>
              )}
            </div>
          </div>

          {summary && (
            <div className="animate-fade-in p-6 bg-slate-50 rounded-3xl border border-slate-200 space-y-4">
              <div className="flex items-center justify-between">
                 <h4 className="font-black text-slate-800 uppercase text-xs tracking-widest">Sync Complete</h4>
                 <div className="flex items-center gap-2 px-3 py-1 bg-green-100 text-green-700 rounded-full text-[10px] font-black uppercase">
                   <CheckCircle2 size={12}/> {summary.updated} / {summary.total} Styles Updated
                 </div>
              </div>

              {summary.notFound.length > 0 && (
                <div className="space-y-2">
                  <div className="flex items-center gap-2 text-red-600 text-[10px] font-black uppercase tracking-widest">
                    <AlertCircle size={14}/> Not Found in DB ({summary.notFound.length})
                  </div>
                  <div className="max-h-32 overflow-y-auto bg-white border border-red-100 rounded-xl p-3 font-mono text-[10px] text-slate-400 flex flex-wrap gap-2">
                    {summary.notFound.map((sn, idx) => (
                      <span key={idx} className="bg-red-50 px-2 py-1 rounded border border-red-100">{sn}</span>
                    ))}
                  </div>
                </div>
              )}

              <button 
                onClick={onClose}
                className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-[0.2em] text-xs hover:bg-black transition-all shadow-xl shadow-slate-200"
              >
                Close Summary
              </button>
            </div>
          )}
        </div>

        {!summary && (
          <div className="p-6 bg-slate-50 border-t flex justify-between items-center">
            <button onClick={onClose} className="px-8 py-3 font-black text-slate-400 hover:text-slate-600 uppercase text-xs">Cancel</button>
            <div className="flex items-center gap-2 text-[10px] font-bold text-slate-400 italic">
               * Updates are permanent in the style database.
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Order, OrderStatus, SizeBreakdown, Style, ConsumptionType, Attachment } from '../../types';
import { X, ImageIcon, FileText, Download, Paperclip, Printer, Box, Calculator } from 'lucide-react';
import { fetchStyleByNumber } from '../../services/db';

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

interface OrderDetailsModalProps {
  order: Order;
  useNumericSizes: boolean;
  onToggleSizeFormat: () => void;
  onClose: () => void;
  onPrint: () => void;
  onPrintMaterials: () => void;
}

export const OrderDetailsModal: React.FC<OrderDetailsModalProps> = ({
  order,
  useNumericSizes,
  onClose,
  onPrint,
  onPrintMaterials
}) => {
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);

  useEffect(() => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
      fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.style_number]);

  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global Requirement",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const renderDetailCell = (rowIdx: number, sizeKey: keyof SizeBreakdown) => {
    const plannedRow = order.size_breakdown?.[rowIdx];
    const actualRow = order.completion_breakdown?.[rowIdx];
    const plannedVal = plannedRow ? (plannedRow[sizeKey] as number) : 0;

    if (order.status !== OrderStatus.COMPLETED || !actualRow) {
      return <span className="text-slate-600 font-medium">{plannedVal}</span>;
    }

    const actualVal = actualRow[sizeKey] as number;
    const isMismatch = actualVal !== plannedVal;

    return (
      <div className="flex flex-col items-center justify-center p-1 bg-slate-50 rounded border border-slate-100">
        <span className={`text-lg font-black ${isMismatch ? 'text-indigo-700' : 'text-slate-900'}`}>
          {actualVal}
        </span>
        <span className="text-[10px] font-bold text-slate-400 border-t border-slate-200 w-full text-center mt-0.5 pt-0.5">
          Plan: {plannedVal}
        </span>
      </div>
    );
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-5xl overflow-hidden max-h-[95vh] flex flex-col animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-center bg-slate-50">
          <div>
            <h3 className="text-2xl font-black text-slate-800 tracking-tight">{order.order_no}</h3>
            <p className="text-slate-500 text-xs font-bold uppercase tracking-widest mt-1">Production Execution Details</p>
          </div>
          <button onClick={onClose} className="text-slate-400 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full transition-colors"><X size={28} /></button>
        </div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8">
          <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm">
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Style Number</span>
              <span className="text-lg font-black text-slate-800">{order.style_number}</span>
            </div>
            <div className="p-4 bg-slate-50 rounded-xl border border-slate-100 shadow-sm">
              <span className="block text-slate-400 text-[10px] uppercase font-black tracking-widest mb-1">Delivery Date</span>
              <span className="text-lg font-black text-slate-800">{order.target_delivery_date}</span>
            </div>
            <div className="p-4 bg-indigo-50 rounded-xl border border-indigo-100 shadow-sm">
              <span className="block text-indigo-400 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Planned Boxes</span>
              <span className="text-xl font-black text-indigo-800">{order.box_count || '---'}</span>
            </div>
            {order.status === OrderStatus.COMPLETED && (
               <div className="p-4 bg-green-50 rounded-xl border border-green-100 shadow-sm animate-fade-in">
                <span className="block text-green-500 text-[10px] uppercase font-black tracking-widest mb-1 flex items-center gap-1"><Box size={12}/> Actual Packed</span>
                <span className="text-xl font-black text-green-800">{order.actual_box_count}</span>
              </div>
            )}
          </div>

          {/* DETAILED REQUIREMENTS SECTION */}
          {detailedReqs.length > 0 && (
            <div className="space-y-4 animate-fade-in">
              <div className="p-4 bg-indigo-600 text-white rounded-t-2xl flex items-center justify-between">
                <h4 className="font-black uppercase tracking-[0.1em] text-xs flex items-center gap-2"><Calculator size={16}/> Segmented Material Requirements</h4>
                <span className="text-[10px] font-bold opacity-70">SYNCED FROM MASTER TECH-PACK</span>
              </div>
              <div className="space-y-4">
                {detailedReqs.map((req, i) => (
                  <div key={i} className="bg-white rounded-2xl border border-indigo-100 overflow-hidden shadow-sm">
                    <div className="px-5 py-3 bg-indigo-50 border-b border-indigo-100 flex justify-between items-center">
                       <span className="font-black text-indigo-900 text-sm">{req.name}</span>
                       <span className="font-black text-indigo-700">Total: {req.total}</span>
                    </div>
                    <div className="p-4 grid grid-cols-1 md:grid-cols-2 gap-4">
                      {req.breakdown.map((b, idx) => (
                        <div key={idx} className="p-4 bg-slate-50 rounded-xl border border-slate-100 space-y-2">
                           <div className="flex justify-between items-center">
                              <span className="text-[9px] font-black text-slate-500 uppercase">{b.label}</span>
                              <span className="text-sm font-black text-indigo-600">{b.calc} Req.</span>
                           </div>
                           <p className="text-xs text-slate-600 font-medium italic">"{b.text || 'No segments notes.'}"</p>
                           {b.attachments.length > 0 && (
                             <div className="flex flex-wrap gap-2 mt-2">
                                {b.attachments.map((att, attIdx) => (
                                  <a key={attIdx} href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 px-2 py-1 bg-white border rounded text-[9px] font-bold text-slate-500 hover:text-indigo-600 hover:border-indigo-200 transition-all">
                                    {att.type === 'image' ? <ImageIcon size={10}/> : <FileText size={10}/>} {att.name}
                                  </a>
                                ))}
                             </div>
                           )}
                        </div>
                      ))}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div>
            <div className="flex justify-between items-center mb-4">
              <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">
                Production Matrix
                {order.status === OrderStatus.COMPLETED && <span className="text-[10px] font-black text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full ml-3 border border-indigo-100 uppercase tracking-widest">Actual / Planned</span>}
              </h4>
            </div>
            <div className="border border-slate-200 rounded-2xl overflow-hidden shadow-md">
              <table className="w-full text-center text-sm border-collapse">
                <thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b">
                  <tr>
                    <th className="p-4 text-left border-r">Color Variant</th>
                    {getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}
                    <th className="p-4 font-black bg-slate-100">Row Total</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {order.size_breakdown?.map((row, idx) => (
                    <tr key={idx} className="hover:bg-slate-50/50 transition-colors">
                      <td className="p-4 text-left font-black text-slate-700 border-r">{row.color}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 's')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'm')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'l')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxl')}</td>
                      <td className="p-4 border-r">{renderDetailCell(idx, 'xxxl')}</td>
                      <td className="p-4 font-black bg-slate-50/50 text-slate-800 tabular-nums">{getRowTotal(row)}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div className="p-6 bg-slate-50/50 rounded-2xl border border-slate-200 shadow-inner">
              <h4 className="font-black text-slate-400 mb-4 uppercase tracking-widest text-[10px]">Production Instructions</h4>
              <p className="text-base text-slate-600 font-medium whitespace-pre-wrap leading-relaxed">{order.description || "No specific instructions provided."}</p>
            </div>
            <div className="p-6 bg-indigo-50/30 rounded-2xl border border-indigo-100 shadow-inner">
              <h4 className="font-black text-indigo-400 mb-4 uppercase tracking-widest text-[10px] flex items-center gap-2">
                <Paperclip size={14}/> Technical Reference Files
              </h4>
              <div className="space-y-3">
                {order.attachments && order.attachments.length > 0 ? (
                  order.attachments.map((att, i) => (
                    <a key={i} href={att.url} target="_blank" rel="noreferrer" className="flex items-center justify-between p-4 bg-white rounded-xl border border-slate-200 hover:shadow-lg transition-all group">
                      <div className="flex items-center gap-4">
                        <div className="p-2 bg-slate-100 rounded-lg group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                          {att.type === 'image' ? <ImageIcon size={20} /> : <FileText size={20} />}
                        </div>
                        <span className="text-sm font-bold text-slate-700 truncate max-w-[200px]">{att.name}</span>
                      </div>
                      <Download size={18} className="text-slate-300 group-hover:text-indigo-600 transition-colors" />
                    </a>
                  ))
                ) : (
                  <div className="text-center py-10 text-slate-300">
                    <Paperclip size={32} className="mx-auto opacity-20 mb-2" />
                    <p className="text-[10px] uppercase font-black tracking-widest opacity-60">No documents attached</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        </div>
        <div className="p-6 border-t bg-slate-50 text-right flex justify-between items-center shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.03)]">
          <button onClick={onPrintMaterials} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-200 rounded-xl font-bold hover:bg-indigo-50 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest text-[10px]">
            <Calculator size={16} /> Print Material Forecast
          </button>
          <div className="flex gap-4">
            <button onClick={onPrint} className="px-8 py-3 bg-indigo-600 text-white rounded-xl font-black hover:bg-indigo-700 shadow-xl shadow-indigo-200 flex items-center gap-2 transition-all active:scale-95 uppercase tracking-widest text-xs">
              <Printer size={18} /> Print Job Sheet
            </button>
            <button onClick={onClose} className="bg-slate-800 text-white px-10 py-3 rounded-xl font-black hover:bg-slate-700 transition-all active:scale-95 uppercase tracking-widest text-xs">Close</button>
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleByNumber, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber, Style, ConsumptionType, Attachment } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC && order.status !== OrderStatus.QC_APPROVED) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }))
                : [{ color: 'Standard', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actualBoxCount });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  const handleDeleteRequest = async (id: string) => {
      if (!confirm("Are you sure?")) return;
      await deleteMaterialRequest(id);
      handleOpenMaterialHistory();
  };

  const handleEditRequest = (req: MaterialRequest) => {
      setIsEditingRequest({ id: req.id, originalData: req });
      setMaterialModal(req.order_id);
      setShowMaterialHistory(false);
  };

  const handleGenerateAndPrintBarcodes = async (qty: number, size: string) => {
    if (!barcodeModal) return;
    const newBarcodes = await generateBarcodes(barcodeModal.orderId, qty, barcodeModal.style, size);
    setBarcodeModal(null);
    const win = window.open('', 'PrintBarcodes', 'width=1000,height=800');
    if (win) {
        const labelsHtml = newBarcodes.map(b => `<div class="label"><div class="header">TINTURA SST</div><div class="meta"><strong>Style:</strong> ${b.style_number} &nbsp; <strong>Size:</strong> ${b.size}</div><svg class="barcode" jsbarcode-format="CODE128" jsbarcode-value="${b.barcode_serial}" jsbarcode-textmargin="0" jsbarcode-fontoptions="bold" jsbarcode-height="40" jsbarcode-width="2" jsbarcode-displayValue="true" jsbarcode-fontSize="11"></svg></div>`).join('');
        win.document.write(`<html><head><title>Print Labels</title><script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script><style>@page { size: A4; margin: 10mm; } body { margin: 0; font-family: sans-serif; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-auto-rows: 35mm; column-gap: 5mm; row-gap: 2mm; } .label { border: 1px dashed #ddd; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 5px; overflow: hidden; text-align: center; background: white; } .header { font-size: 10px; font-weight: bold; text-transform: uppercase; margin: 2px; } .meta { font-size: 10px; margin-bottom: 2px; color: #333; } svg { max-width: 95%; height: auto; display: block; }</style></head><body><div class="grid">${labelsHtml}</div><script>window.onload = function() { JsBarcode(".barcode").init(); setTimeout(() => { window.print(); }, 500); }</script></body></html>`); 
        win.document.close();
    }
  };

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (order: Order, linkedStyle: Style): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + ( (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0) ), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global Requirement",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const handlePrintMaterialForecast = async (order: Order) => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (!styleRefPart) return;

    const style = await fetchStyleByNumber(styleRefPart);
    if (!style) return;

    const detailedReqs = getDetailedRequirements(order, style);
    if (detailedReqs.length === 0) return alert("No projected requirements found in linked Tech Pack.");

    const formattedNo = formatOrderNumber(order);
    const win = window.open('', 'MaterialForecast', 'width=1000,height=800');
    if (win) {
      win.document.write(`
        <html><head><title>Material Forecast - ${formattedNo}</title>
        <style>
          body { font-family: sans-serif; padding: 40px; font-size: 12px; color: #333; }
          .header { text-align: center; border-bottom: 2px solid #000; padding-bottom: 10px; margin-bottom: 20px; }
          .brand { font-size: 24px; font-weight: 900; }
          .title { font-size: 16px; font-weight: bold; text-transform: uppercase; margin-top: 5px; color: #555; }
          .meta { margin-bottom: 20px; display: grid; grid-template-columns: 1fr 1fr; gap: 10px; background: #f8fafc; padding: 15px; border-radius: 8px; }
          .meta-item { font-size: 13px; font-weight: bold; }
          .section { margin-bottom: 30px; border: 1px solid #e2e8f0; border-radius: 10px; overflow: hidden; page-break-inside: avoid; }
          .section-header { background: #4f46e5; color: #fff; padding: 10px 15px; font-weight: 900; font-size: 14px; display: flex; justify-content: space-between; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #e2e8f0; padding: 8px; text-align: left; }
          th { background: #f1f5f9; font-size: 10px; text-transform: uppercase; }
          .val { font-weight: 900; font-size: 14px; color: #4f46e5; }
          .img-grid { display: grid; grid-template-columns: repeat(3, 1fr); gap: 10px; margin-top: 5px; }
          .img-grid img { width: 100%; border-radius: 4px; border: 1px solid #ddd; }
        </style>
        </head><body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Projected Material Requirements Forecast</div>
          </div>
          <div class="meta">
            <div class="meta-item">Order No: ${formattedNo}</div>
            <div class="meta-item">Style: ${order.style_number}</div>
            <div class="meta-item">Batch Size: ${order.quantity} PCS</div>
            <div class="meta-item">Date: ${new Date().toLocaleDateString()}</div>
          </div>
          ${detailedReqs.map(req => `
            <div class="section">
              <div class="section-header">
                <span>${req.name}</span>
                <span>JOB TOTAL: ${req.total}</span>
              </div>
              <table>
                <thead>
                  <tr>
                    <th width="150">Segment Scope</th>
                    <th width="80" style="text-align:center">Segment Qty</th>
                    <th width="100" style="text-align:right">Req. Qty</th>
                    <th>Instructions & Visuals</th>
                  </tr>
                </thead>
                <tbody>
                  ${req.breakdown.map(b => `
                    <tr>
                      <td style="font-weight:bold;">${b.label}</td>
                      <td style="text-align:center">${b.count}</td>
                      <td style="text-align:right" class="val">${b.calc}</td>
                      <td>
                        <div style="margin-bottom:5px;">${b.text || '---'}</div>
                        <div class="img-grid">${b.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}"/>`).join('')}</div>
                      </td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          `).join('')}
          <script>window.onload = () => { window.print(); };</script>
        </body></html>
      `);
      win.document.close();
    }
  };

  const handlePrintOrderSheet = async (order: Order) => {
      let techPackHtml = '';

      const styleRefPart = order.style_number.split(' - ')[0].trim();
      if (styleRefPart) {
          const [style, template] = await Promise.all([
              fetchStyleByNumber(styleRefPart),
              fetchStyleTemplate()
          ]);

          if (style && template) {
              techPackHtml = template.config.filter(c => c.name !== "General Info").map(cat => {
                  const fields = cat.fields.map(f => {
                      const item = style.tech_pack[cat.name]?.[f] || { text: 'N/A', attachments: [] };
                      let contentHtml = '';
                      if (item.variants) {
                        contentHtml = item.variants.map(v => {
                          let sizeHtml = '';
                          if (v.sizeVariants) {
                            sizeHtml = `<div style="margin-top:10px; display:grid; grid-template-columns:1fr; gap:8px;">${v.sizeVariants.map(sv => `
                              <div style="background:#fff; border:1px solid #ddd; border-left:4px solid #4f46e5; padding:10px; border-radius:6px; page-break-inside:avoid;">
                                <div style="margin-bottom:5px; font-weight:bold; font-size:10px; color:#4f46e5;">SIZE GROUP: ${sv.sizes.join(', ')}</div>
                                <div style="font-size:12px; font-weight:bold;">${sv.text || '---'}</div>
                              </div>
                            `).join('')}</div>`;
                          }
                          return `<div style="border:1px solid #ddd; padding:12px; border-radius:8px; margin-top:10px; background:#f9fafb; page-break-inside:avoid;"><div style="margin-bottom:5px;">${v.colors.map(c => `<span style="background:#334155; color:#fff; font-size:9px; font-weight:bold; padding:2px 6px; border-radius:3px; margin-right:4px; text-transform:uppercase;">${c}</span>`).join('')}</div><div style="font-size:13px; font-weight:bold;">${v.text || '---'}</div>${sizeHtml}</div>`;
                        }).join('');
                      } else {
                        contentHtml = `<div style="font-size:14px; font-weight:bold; background:#f9fafb; padding:15px; border-radius:8px; border:1px solid #ddd;">${item.text || '---'}</div>`;
                      }

                      return `
                        <div style="margin-bottom:15px; border-bottom:1px solid #eee; padding-bottom:8px; page-break-inside:avoid;">
                          <div style="font-size:10px; font-weight:bold; color:#64748b; text-transform:uppercase; margin-bottom:4px;">${f}</div>
                          ${contentHtml}
                        </div>
                      `;
                  }).join('');

                  return `
                    <div style="margin-top:25px; page-break-before:auto;">
                      <h3 style="background:#334155; color:#fff; padding:8px 12px; font-size:12px; text-transform:uppercase; letter-spacing:1px; border-radius:4px;">${cat.name} Reference</h3>
                      <div style="padding:10px 0;">${fields}</div>
                    </div>
                  `;
              }).join('');
          }
      }

      const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
      const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
      const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
      const breakdownRows = (order.size_breakdown || []).map(row => `<tr><td style="text-align:left; font-weight:bold;">${row.color}</td>${keys.map(k => `<td>${(row as any)[k]}</td>`).join('')}<td style="font-weight:bold; background:#f1f5f9;">${getRowTotal(row)}</td></tr>`).join('');
      const formattedNo = formatOrderNumber(order);

      let attachmentHtml = '';
      if (order.attachments && order.attachments.length > 0) {
          attachmentHtml = `<div class="section-title">Technical Reference Documents</div><div style="display:flex; flex-direction:column; gap:15px;">`;
          order.attachments.forEach(att => {
              if (att.type === 'image') {
                  attachmentHtml += `<div style="border:1px solid #ccc; padding:10px; text-align:center; page-break-inside:avoid;"><img src="${att.url}" style="max-width:100%; max-height:600px; border-radius:4px;" /><div style="font-size:10px; margin-top:5px; font-weight:bold; color:#666;">REF: ${att.name}</div></div>`;
              } else if (att.url.toLowerCase().endsWith('.pdf')) {
                  attachmentHtml += `<div style="border:1px solid #333; border-radius:4px; overflow:hidden; page-break-before:always;"><div style="background:#333; color:white; padding:8px; font-weight:bold; text-align:center; font-size:12px;">PDF DOC: ${att.name}</div><iframe src="${att.url}" style="width:100%; height:800px; border:none;"></iframe></div>`;
              }
          });
          attachmentHtml += `</div>`;
      }

      const win = window.open('', 'PrintOrderSheet', 'width=1000,height=800');
      if (win) {
          win.document.write(`<html><head><title>Job Sheet - ${formattedNo}</title>
          <style>
            body { font-family: sans-serif; padding: 40px; font-size: 11px; color: #1e293b; }
            .header { text-align: center; border-bottom: 4px solid #000; padding-bottom: 15px; margin-bottom: 25px; }
            .brand { font-size: 32px; font-weight: 900; }
            .title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-top: 5px; color:#64748b; letter-spacing:2px; }
            .grid { display: grid; grid-template-columns: 1fr 1fr 1fr 1fr; gap: 15px; margin-bottom: 20px; }
            .box { padding: 12px; border: 2px solid #1e293b; border-radius: 6px; }
            .label { font-size: 9px; text-transform: uppercase; color: #64748b; font-weight: bold; display:block; margin-bottom:3px; }
            .value { font-size: 14px; font-weight: bold; }
            table { width: 100%; border-collapse: collapse; margin-top: 15px; }
            th, td { border: 1px solid #1e293b; padding: 10px; text-align: center; }
            th { background: #f8fafc; font-weight: bold; text-transform: uppercase; font-size: 9px; }
            .section-title { font-size: 14px; font-weight: 900; border-bottom: 2px solid #1e293b; padding-bottom: 4px; margin-top: 30px; margin-bottom: 12px; text-transform: uppercase; letter-spacing:1px; }
            .notes-box { padding: 15px; border: 2px solid #1e293b; background: #f8fafc; border-radius: 8px; font-size: 13px; font-weight: bold; }
          </style>
          </head><body>
            <div class="header">
              <div class="brand">TINTURA SST</div>
              <div class="title">Manufacturing Job Execution Sheet</div>
            </div>
            <div class="grid">
              <div class="box"><span class="label">Job Reference</span><div class="value">${formattedNo}</div></div>
              <div class="box"><span class="label">Style ID</span><div class="value">${order.style_number}</div></div>
              <div class="box"><span class="label">Total Volume</span><div class="value">${order.quantity} PCS</div></div>
              <div class="box"><span class="label">Due Date</span><div class="value">${order.target_delivery_date}</div></div>
            </div>

            <div class="section-title">Job Summary & Meta</div>
            <div class="notes-box" style="margin-bottom:20px;">
               Manufacturing details for facility: Unit ID ${order.unit_id}. Styled as per linked database records.
            </div>

            <div class="section-title">Color / Size Distribution Matrix</div>
            <table>
              <thead>
                <tr><th style="text-align:left;">Color Group</th>${headers.map(h => `<th>${h}</th>`).join('')}<th>Total</th></tr>
              </thead>
              <tbody>${breakdownRows}</tbody>
            </table>

            <div class="section-title">Production Notes & Instructions</div>
            <div class="notes-box" style="min-height: 50px;">
              ${order.description || "No specific instructions provided."}
            </div>

            ${attachmentHtml}
            ${techPackHtml}
            <script>window.onload = () => { setTimeout(() => window.print(), 1000); };</script>
          </body></html>`);
          win.document.close();
      }
  };

  const handlePrintAccessoriesReceipt = (order: Order, reqs: MaterialRequest[]) => {
      const formattedNo = formatOrderNumber(order);
      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:center;">${req.unit || 'Nos'}</td><td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td></tr>`).join('');
          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:right;">${req.quantity_requested}</td><td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td><td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td><td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td></tr>`;
          }).join('');
          const headerHTML = `<div class="header"><div class="brand">TINTURA SST</div><div class="title">ACCESSORIES REQUIREMENT RECEIPT</div><div class="meta">ORDER NO: ${formattedNo} &nbsp;|&nbsp; STYLE: ${order.style_number} &nbsp;|&nbsp; DATE: ${new Date().toLocaleDateString()}</div></div>`;
          win.document.write(`<html><head><title>Accessories Receipt - ${formattedNo}</title><style>@media print { .page-break { page-break-before: always; } body { -webkit-print-color-adjust: exact; } } body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; } .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; } .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; } .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; } table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; } th, td { border: 1px solid #ccc; padding: 8px; } th { background: #f4f4f4; text-transform: uppercase; }</style></head><body>${headerHTML}<div class="page-title">Page 1: Request Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80">Unit</th><th width="100" style="text-align:right">Total Requested</th></tr></thead><tbody>${page1Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div><div class="page-break"></div>${headerHTML}<div class="page-title">Page 2: Approval & Balance Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80" style="text-align:right">Req</th><th width="80" style="text-align:right">Approved</th><th width="80" style="text-align:right">Balance</th><th width="100">Status</th></tr></thead><tbody>${page2Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div><script>window.onload = () => { setTimeout(() => window.print(), 500); };</script></body></html>`);
          win.document.close();
