                            <div className="flex justify-between items-start">
                              <div>
                                <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest block mb-1">{b.label}</span>
                                <span className="text-xs font-bold text-slate-500">Volume: {b.count} Pcs</span>
                              </div>
                              <div className="text-right">
                                <span className="text-xl font-black text-indigo-700">{b.calc}</span>
                                <span className="text-[8px] block font-black text-slate-400 uppercase">Estimated</span>
                              </div>
                            </div>

                            <div className="p-3 bg-white rounded-xl border border-slate-100">
                               <p className="text-xs font-bold text-slate-700 leading-relaxed italic">"{b.text || 'No specific notes.'}"</p>
                               {b.attachments.length > 0 && (
                                 <div className="mt-3 flex flex-wrap gap-2">
                                    {b.attachments.map((att, attIdx) => (
                                      <a key={attIdx} href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 px-2 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[9px] font-black border border-indigo-100 hover:bg-indigo-100 transition-all">
                                        {att.type === 'image' ? <ImageIcon size={10}/> : <FileText size={10}/>} {att.name}
                                      </a>
                                    ))}
                                 </div>
                               )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div><div className="flex justify-between items-center mb-4"><h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product breakdown matrix</h4>{isEditing && <button type="button" onClick={() => setUseNumericSizes(!useNumericSizes)} className="text-[10px] bg-slate-100 px-4 py-2 rounded-xl border border-slate-200 font-black uppercase"><ArrowLeftRight size={14} className="inline mr-2"/> Switch Size Format</button>}</div><div className="border border-slate-200 rounded-3xl overflow-hidden shadow-sm bg-white"><table className="w-full text-center text-sm border-collapse"><thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b"><tr><th className="p-4 text-left border-r">Color Variant</th>{getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}<th className="p-4 bg-slate-100">Sum</th>{isEditing && <th className="p-4 w-12"></th>}</tr></thead><tbody className="divide-y divide-slate-100">{(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (<tr key={idx} className="hover:bg-slate-50/50 transition-colors"><td className="p-4 text-left font-black text-slate-700 border-r">{isEditing ? <input className="w-full border rounded p-1 font-bold" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : row.color}</td>{['s','m','l','xl','xxl','xxxl'].map(key => (<td key={key} className="p-4 border-r">{isEditing ? <input type="number" className="w-16 border rounded p-1 text-center font-black" value={(row as any)[key]} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; (bd[idx] as any)[key] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : (order.size_breakdown?.[idx]?.[key as keyof SizeBreakdown] || 0)}</td>))}<td className="p-4 font-black text-slate-900 bg-slate-50/50 tabular-nums">{getRowTotal(row)}</td>{isEditing && <td className="p-4"><button onClick={() => setEditFormData({...editFormData, size_breakdown: (editFormData.size_breakdown || []).filter((_, i) => i !== idx)})} className="text-red-400 hover:text-red-600 transition-colors"><Trash2 size={20}/></button></td>}</tr>))}</tbody></table>{isEditing && <button onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }]})} className="w-full py-4 bg-slate-50 text-indigo-600 text-xs font-black uppercase border-t hover:bg-indigo-50 transition-colors">+ Add Color Variant</button>}</div></div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm"><span className="block text-[11px] text-slate-400 uppercase font-black mb-3">Master production notes</span>{isEditing ? <textarea className="w-full border border-slate-200 rounded-2xl p-4 h-48 font-medium" value={editFormData.description} onChange={e => setEditFormData({...editFormData, description: e.target.value})}/> : <p className="text-xl text-slate-800 font-black whitespace-pre-wrap leading-relaxed">{order.description || 'N/A'}</p>}</div><div className="p-6 bg-indigo-50/30 rounded-3xl border border-indigo-100 shadow-inner"><h4 className="font-black text-indigo-400 uppercase text-[10px] flex items-center gap-2 mb-4"><Paperclip size={14}/> Technical documents</h4><div className="space-y-3">{(isEditing ? editFormData.attachments : order.attachments)?.map((att, i) => (<div key={i} className="flex items-center justify-between p-4 bg-white rounded-xl border border-indigo-50 group hover:shadow-md transition-all"><a href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-4 flex-1">{att.type === 'image' ? <ImageIcon size={20} className="text-indigo-400" /> : <FileText size={20} className="text-indigo-400" />}<span className="text-sm font-black text-slate-700 truncate">{att.name}</span></a>{isEditing && <button onClick={() => setEditFormData({...editFormData, attachments: (editFormData.attachments || []).filter((_, idx) => idx !== i)})} className="text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={20}/></button>}</div>))}{isEditing && <div className="mt-4 border-2 border-dashed border-indigo-100 rounded-2xl p-6 text-center relative hover:bg-white transition-all cursor-pointer"><input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/><Upload size={32} className="mx-auto text-indigo-400"/><p className="text-[10px] font-black text-indigo-600 uppercase mt-2 tracking-widest">Add technical files</p></div>}</div></div></div>

          <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col"><h4 className="font-black text-indigo-900 uppercase text-[10px] flex items-center gap-2 mb-6"><Clock size={16}/> Lifecycle status log</h4><div className="space-y-6 max-h-[400px] overflow-y-auto pr-4">{modalLogs.map(log => (<div key={log.id} className="flex gap-4 border-l-4 border-indigo-100 pl-6 pb-2 transition-all hover:border-indigo-400"><div className="font-black text-[10px] text-slate-400 uppercase leading-none pt-1">{new Date(log.created_at).toLocaleDateString()}<br/><span className="text-indigo-400 opacity-60 font-bold">{new Date(log.created_at).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></div><div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-200"><p className="text-slate-700 font-bold leading-snug">{log.message}</p></div></div>))}</div></div>
        </div>
        <div className="p-6 border-t bg-slate-50 flex justify-between items-center"><button onClick={() => { if(confirm("Permanently delete this order?")) deleteOrder(order.id).then(() => {onRefresh(); onClose();}); }} className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all"><Trash2 size={24}/></button><div className="flex items-center gap-4">
          <button onClick={handlePrintMaterialForecast} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-600 rounded-xl font-black uppercase text-[10px] flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all">
            <Calculator size={16}/> Print Material Forecast
          </button>
          <button onClick={handlePrint} className="px-8 py-3 bg-white text-indigo-600 border-2 border-indigo-600 rounded-xl font-black uppercase text-xs flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all"><Printer size={16}/> Print Job Sheet</button><button onClick={onClose} className="px-10 py-3 bg-slate-800 text-white rounded-xl font-black uppercase text-xs hover:bg-slate-700 transition-all">Close</button>{isEditing && <button handleSave={handleSave} disabled={isUploading} className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black uppercase text-xs shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all">{isUploading ? <Loader2 className="animate-spin inline mr-2" size={16}/> : null}{isUploading ? 'Saving...' : 'Save Job'}</button>}</div></div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Printer, Maximize2, Minimize2, Move, LayoutGrid } from 'lucide-react';
import { Order, Style, StyleTemplate, Attachment, formatOrderNumber, SizeBreakdown } from '../types';
import { fetchStyleByNumber, fetchStyleTemplate } from '../services/db';

interface JobSheetPreviewModalProps {
  order: Order;
  onClose: () => void;
}

export const JobSheetPreviewModal: React.FC<JobSheetPreviewModalProps> = ({ order, onClose }) => {
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);
  const [template, setTemplate] = useState<StyleTemplate | null>(null);
  const [imageSizes, setImageSizes] = useState<Record<string, number>>({}); // Percent width
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      const styleRefPart = order.style_number.split(' - ')[0].trim();
      const [s, t] = await Promise.all([
        fetchStyleByNumber(styleRefPart),
        fetchStyleTemplate()
      ]);
      setLinkedStyle(s);
      setTemplate(t);
      setLoading(false);
    };
    load();
  }, [order.style_number]);

  const updateImgSize = (id: string, size: number) => {
    setImageSizes(prev => ({ ...prev, [id]: size }));
  };

  const handleFinalPrint = () => {
    const printWindow = window.open('', '_blank');
    if (!printWindow) return;

    const content = document.getElementById('printable-area')?.innerHTML;
    const styles = Array.from(document.querySelectorAll('style')).map(s => s.innerHTML).join('\n');

    printWindow.document.write(`
      <html>
        <head>
          <title>Job Sheet - ${formatOrderNumber(order)}</title>
          <style>${styles}</style>
          <style>
            @media print {
              .no-print { display: none !important; }
              body { padding: 0 !important; margin: 0 !important; }
              .preview-page { border: none !important; box-shadow: none !important; padding: 40px !important; }
            }
          </style>
        </head>
        <body>
          <div class="preview-page">${content}</div>
          <script>
            window.onload = () => {
              setTimeout(() => {
                window.print();
                window.close();
              }, 500);
            };
          </script>
        </body>
      </html>
    `);
    printWindow.document.close();
  };

  if (loading) return null;

  const headers = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];
  const keys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);

  const renderImageControl = (url: string, id: string) => {
    const currentSize = imageSizes[id] || 100;
    return (
      <div className="group relative border border-slate-200 rounded-lg overflow-hidden bg-white mb-4 no-break-inside">
        <div className="no-print absolute top-2 right-2 flex gap-1 z-10 opacity-0 group-hover:opacity-100 transition-opacity">
          {[33, 50, 100].map(s => (
            <button 
              key={s}
              onClick={() => updateImgSize(id, s)}
              className={`p-1.5 rounded text-[10px] font-bold ${currentSize === s ? 'bg-indigo-600 text-white' : 'bg-white/90 text-slate-700 hover:bg-white border border-slate-200 shadow-sm'}`}
            >
              {s}%
            </button>
          ))}
        </div>
        <div style={{ width: `${currentSize}%`, margin: '0 auto' }}>
          <img src={url} className="w-full h-auto block" alt="Technical Reference" />
        </div>
        <div className="p-2 border-t bg-slate-50 text-[10px] font-bold text-slate-400 uppercase tracking-tighter text-center">
          Ref: {id.split('-').pop()}
        </div>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 bg-slate-900/80 z-[100] flex flex-col backdrop-blur-sm overflow-hidden animate-fade-in">
      {/* Control Bar */}
      <div className="bg-slate-900 text-white px-8 py-4 flex items-center justify-between border-b border-white/10 shrink-0">
        <div className="flex items-center gap-4">
          <div className="p-2 bg-indigo-500 rounded-lg">
            <Printer size={20} />
          </div>
          <div>
            <h2 className="font-black text-lg uppercase tracking-tight">Print Layout Preview</h2>
            <p className="text-white/50 text-[10px] font-bold uppercase tracking-widest">Adjust image sizes by hovering over them</p>
          </div>
        </div>
        <div className="flex items-center gap-4">
          <button 
            onClick={onClose}
            className="px-6 py-2 text-slate-400 hover:text-white font-bold text-sm uppercase transition-colors"
          >
            Cancel
          </button>
          <button 
            onClick={handleFinalPrint}
            className="bg-indigo-600 hover:bg-indigo-700 text-white px-8 py-3 rounded-xl font-black shadow-xl shadow-indigo-500/20 flex items-center gap-2 transition-all active:scale-95"
          >
            <Printer size={18} /> Confirm & Print
          </button>
        </div>
      </div>

      {/* Preview Area */}
      <div className="flex-1 overflow-y-auto p-12 bg-slate-800">
        <div 
          id="printable-area" 
          className="preview-page max-w-[210mm] min-h-[297mm] mx-auto bg-white shadow-2xl p-[40px] text-slate-900 font-sans"
          style={{ fontSize: '10px' }}
        >
          {/* Header */}
          <div className="text-center border-b-[3px] border-black pb-4 mb-6">
            <h1 className="text-3xl font-black m-0 tracking-tighter">TINTURA SST</h1>
            <div className="text-[12px] font-bold text-slate-500 uppercase tracking-widest mt-1">Manufacturing Job Execution Sheet</div>
          </div>

          {/* Meta Grid */}
          <div className="grid grid-cols-4 gap-3 mb-6">
            <div className="border border-black p-3 rounded">
              <span className="text-[8px] font-black uppercase text-slate-400 block mb-1">Job ID</span>
              <div className="text-sm font-bold">{formatOrderNumber(order)}</div>
            </div>
            <div className="border border-black p-3 rounded">
              <span className="text-[8px] font-black uppercase text-slate-400 block mb-1">Style Reference</span>
              <div className="text-sm font-bold">{order.style_number}</div>
            </div>
            <div className="border border-black p-3 rounded">
              <span className="text-[8px] font-black uppercase text-slate-400 block mb-1">Volume</span>
              <div className="text-sm font-bold">{order.quantity} PCS</div>
            </div>
            <div className="border border-black p-3 rounded">
              <span className="text-[8px] font-black uppercase text-slate-400 block mb-1">Due Date</span>
              <div className="text-sm font-bold">{order.target_delivery_date}</div>
            </div>
          </div>

          {/* Matrix */}
          <div className="mb-6">
            <h3 className="text-xs font-black uppercase border-b border-black pb-1 mb-3 tracking-widest">Color & Size Matrix</h3>
            <table className="w-full border-collapse">
              <thead>
                <tr>
                  <th className="border border-black p-2 bg-slate-50 text-left">Variant</th>
                  {headers.map(h => <th key={h} className="border border-black p-2 bg-slate-50">{h}</th>)}
                  <th className="border border-black p-2 bg-slate-100">Total</th>
                </tr>
              </thead>
              <tbody>
                {order.size_breakdown?.map((row, idx) => (
                  <tr key={idx}>
                    <td className="border border-black p-2 font-bold">{row.color}</td>
                    {keys.map(k => <td key={k} className="border border-black p-2 text-center">{(row as any)[k]}</td>)}
                    <td className="border border-black p-2 text-center font-bold bg-slate-50">{getRowTotal(row)}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          {/* Notes */}
          <div className="mb-6">
            <h3 className="text-xs font-black uppercase border-b border-black pb-1 mb-3 tracking-widest">Manufacturing Notes</h3>
            <div className="p-4 border border-black rounded bg-slate-50 font-bold whitespace-pre-wrap text-[11px]">
              {order.description || "No specific instructions provided."}
            </div>
          </div>

          {/* Attachments Section */}
          {order.attachments && order.attachments.filter(a => a.type === 'image').length > 0 && (
            <div className="mb-8">
              <h3 className="text-xs font-black uppercase border-b border-black pb-1 mb-4 tracking-widest">Visual References (Order Level)</h3>
              <div className="space-y-4">
                {order.attachments.filter(a => a.type === 'image').map((att, i) => (
                  renderImageControl(att.url, `ord-att-${i}`)
                ))}
              </div>
            </div>
          )}

          {/* Pre-Production (New Page Forced) */}
          {template?.config.find(c => c.name.toLowerCase().includes('pre production')) && (
            <div className="page-break-before mt-10">
              <h3 className="bg-black text-white p-3 rounded font-black uppercase text-xs tracking-[0.2em] mb-4">Pre-Production Requirements</h3>
              {template.config.find(c => c.name.toLowerCase().includes('pre production'))?.fields.map(f => {
                const item = linkedStyle?.tech_pack[template.config.find(c => c.name.toLowerCase().includes('pre production'))!.name]?.[f];
                if (!item) return null;
                return (
                  <div key={f} className="mb-6 border-b border-slate-100 pb-4 no-break-inside">
                    <div className="text-[9px] font-bold text-slate-400 uppercase mb-2">{f}</div>
                    <div className="text-[12px] font-bold mb-3">{item.text || 'N/A'}</div>
                    <div className="space-y-2">
                      {item.attachments.filter(a => a.type === 'image').map((a, ai) => renderImageControl(a.url, `pp-${f}-${ai}`))}
                    </div>
                  </div>
                );
              })}
            </div>
          )}

          {/* Tech Pack Sections */}
          {template?.config.filter(c => c.name !== "General Info" && !c.name.toLowerCase().includes('pre production')).map(cat => (
            <div key={cat.name} className="mt-8">
              <h3 className="bg-slate-100 border-l-4 border-black p-2 font-black uppercase text-xs tracking-widest mb-4">{cat.name} Reference</h3>
              {cat.fields.map(f => {
                const item = linkedStyle?.tech_pack[cat.name]?.[f];
                if (!item) return null;
                return (
                  <div key={f} className="mb-6 border-b border-slate-100 pb-4 no-break-inside">
                    <div className="text-[8px] font-bold text-slate-400 uppercase mb-1">{f}</div>
                    {item.variants ? (
                      <div className="space-y-4 mt-2">
                        {item.variants.map((v, vi) => (
                          <div key={vi} className="bg-slate-50 p-3 rounded border border-slate-200">
                             <div className="flex gap-1 mb-2">
                               {v.colors.map(c => <span key={c} className="bg-slate-800 text-white px-2 py-0.5 rounded text-[8px] uppercase">{c}</span>)}
                             </div>
                             <div className="text-[11px] font-bold">{v.text}</div>
                             <div className="mt-2 space-y-2">
                               {v.attachments.filter(a => a.type === 'image').map((a, ai) => renderImageControl(a.url, `v-${f}-${vi}-${ai}`))}
                             </div>
                          </div>
                        ))}
                      </div>
                    ) : (
                      <div className="bg-slate-50 p-3 rounded border border-slate-200">
                        <div className="text-[11px] font-bold">{item.text}</div>
                        <div className="mt-2 space-y-2">
                          {item.attachments.filter(a => a.type === 'image').map((a, ai) => renderImageControl(a.url, `tp-${f}-${ai}`))}
                        </div>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>

      <style>{`
        .no-break-inside { page-break-inside: avoid; break-inside: avoid; }
        .page-break-before { page-break-before: always; break-before: page; }
        .preview-page { line-height: 1.4; }
        @media print {
          @page { margin: 10mm; size: A4; }
        }
      `}</style>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { fetchOrders, updateOrderStatus, generateBarcodes, fetchMaterialRequests, deleteMaterialRequest, triggerMaterialEmail, fetchOrderLogs, addOrderLog, fetchStyleByNumber, fetchStyleTemplate } from '../services/db';
import { Order, OrderStatus, getNextOrderStatus, SizeBreakdown, MaterialRequest, OrderLog, MaterialStatus, formatOrderNumber, Style, ConsumptionType, Attachment } from '../types';
import { StatusBadge, BulkActionToolbar } from '../components/Widgets';
import { ArrowRight, Printer, PackagePlus, Box, AlertTriangle, Eye, CheckCircle2, History, ListTodo, Archive, Clock, Search, Mail, Loader2, Info } from 'lucide-react';

import { OrderDetailsModal } from '../components/subunit/OrderDetailsModal';
import { TimelineModal } from '../components/subunit/TimelineModal';
import { CompletionModal } from '../components/subunit/CompletionModal';
import { BarcodeModal } from '../components/subunit/BarcodeModal';
import { MaterialHistoryModal } from '../components/subunit/MaterialHistoryModal';
import { MaterialRequestModal } from '../components/subunit/MaterialRequestModal';
import { JobSheetPreviewModal } from '../components/JobSheetPreviewModal';

const CURRENT_UNIT_ID = 2; // Sewing Unit A

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

export const SubunitDashboard: React.FC = () => {
  const [orders, setOrders] = useState<Order[]>([]);
  const [activeTab, setActiveTab] = useState<'active' | 'history'>('active');
  const [selectedOrders, setSelectedOrders] = useState<string[]>([]);
  const [loading, setLoading] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [emailLoading, setEmailLoading] = useState<string | null>(null);

  const [detailsModal, setDetailsModal] = useState<Order | null>(null);
  const [timelineModal, setTimelineModal] = useState<{orderId: string, orderNo: string} | null>(null);
  const [completionModal, setCompletionModal] = useState<Order | null>(null);
  const [barcodeModal, setBarcodeModal] = useState<{orderId: string, style: string} | null>(null);
  const [materialModal, setMaterialModal] = useState<string | null>(null);
  const [showMaterialHistory, setShowMaterialHistory] = useState(false);
  const [jobSheetPreview, setJobSheetPreview] = useState<Order | null>(null);

  const [timelineLogs, setTimelineLogs] = useState<OrderLog[]>([]);
  const [statusUpdateText, setStatusUpdateText] = useState("");
  const [completionForm, setCompletionForm] = useState<{ breakdown: SizeBreakdown[], actualBoxCount: number } | null>(null);
  const [materialHistory, setMaterialHistory] = useState<MaterialRequest[]>([]);
  const [isEditingRequest, setIsEditingRequest] = useState<{ id: string, originalData: MaterialRequest } | null>(null);

  const [useNumericSizes, setUseNumericSizes] = useState(false);

  const refreshOrders = () => {
    fetchOrders().then(data => {
        const subunitOrders = data.filter(o => o.unit_id === CURRENT_UNIT_ID);
        setOrders(subunitOrders);
    });
  };

  useEffect(() => { refreshOrders(); }, []);

  const displayedOrders = orders.filter(o => {
      const formattedNo = formatOrderNumber(o);
      const matchesTab = activeTab === 'active' ? o.status !== OrderStatus.COMPLETED : o.status === OrderStatus.COMPLETED;
      const matchesSearch = formattedNo.toLowerCase().includes(searchTerm.toLowerCase()) || o.style_number.toLowerCase().includes(searchTerm.toLowerCase());
      return matchesTab && matchesSearch;
  });

  const toggleSelect = (id: string) => {
    setSelectedOrders(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
  };

  const handleBulkStatusUpdate = async () => {
    setLoading(true);
    await Promise.all(selectedOrders.map(async (id) => {
      const order = orders.find(o => o.id === id);
      if (order && order.status !== OrderStatus.QC) {
        const next = getNextOrderStatus(order.status);
        if (next) await updateOrderStatus(id, next);
      }
    }));
    setSelectedOrders([]);
    setLoading(false);
    refreshOrders();
  };

  const handleSingleStatusUpdate = async (id: string, currentStatus: OrderStatus) => {
    if (currentStatus === OrderStatus.QC_APPROVED) {
        const order = orders.find(o => o.id === id);
        if (order) {
            setUseNumericSizes(order.size_format === 'numeric');
            const initialBreakdown = order.size_breakdown 
                ? order.size_breakdown.map(r => ({ color: r.color, s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }))
                : [{ color: 'Standard', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }];
            setCompletionForm({ breakdown: initialBreakdown, actualBoxCount: order.box_count || 0 });
            setCompletionModal(order);
        }
        return;
    }
    const next = getNextOrderStatus(currentStatus);
    if (next) {
        setLoading(true);
        await updateOrderStatus(id, next);
        setLoading(false);
        refreshOrders();
    }
  };

  const handleSendMaterialEmail = async (orderId: string) => {
    setEmailLoading(orderId);
    const result = await triggerMaterialEmail(orderId);
    setEmailLoading(null);
    alert(result.message);
  };

  const openTimeline = (orderId: string, orderNo: string) => {
      setTimelineModal({ orderId, orderNo });
      setTimelineLogs([]);
      setStatusUpdateText("");
      fetchOrderLogs(orderId).then(setTimelineLogs);
  };

  const submitManualStatusUpdate = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!timelineModal || !statusUpdateText.trim()) return;
      await addOrderLog(timelineModal.orderId, 'MANUAL_UPDATE', statusUpdateText);
      const logs = await fetchOrderLogs(timelineModal.orderId);
      setTimelineLogs(logs);
      setStatusUpdateText("");
  };

  const handleCompleteOrder = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!completionModal || !completionForm) return;
      setLoading(true);
      await updateOrderStatus(completionModal.id, OrderStatus.COMPLETED, undefined, { completion_breakdown: completionForm.breakdown, actual_box_count: completionForm.actualBoxCount });
      setCompletionModal(null);
      setCompletionForm(null);
      setLoading(false);
      refreshOrders();
  };

  const handleOpenMaterialHistory = async () => {
      const allRequests = await fetchMaterialRequests();
      const unitOrderIds = orders.map(o => o.id);
      setMaterialHistory(allRequests.filter(req => unitOrderIds.includes(req.order_id)));
      setShowMaterialHistory(true);
  };

  const handleDeleteRequest = async (id: string) => {
      if (!confirm("Are you sure?")) return;
      await deleteMaterialRequest(id);
      handleOpenMaterialHistory();
  };

  const handleEditRequest = (req: MaterialRequest) => {
      setIsEditingRequest({ id: req.id, originalData: req });
      setMaterialModal(req.order_id);
      setShowMaterialHistory(false);
  };

  const handleGenerateAndPrintBarcodes = async (qty: number, size: string) => {
    if (!barcodeModal) return;
    const newBarcodes = await generateBarcodes(barcodeModal.orderId, qty, barcodeModal.style, size);
    setBarcodeModal(null);
    const win = window.open('', 'PrintBarcodes', 'width=1000,height=800');
    if (win) {
        const labelsHtml = newBarcodes.map(b => `<div class="label"><div class="header">TINTURA SST</div><div class="meta"><strong>Style:</strong> ${b.style_number} &nbsp; <strong>Size:</strong> ${b.size}</div><svg class="barcode" jsbarcode-format="CODE128" jsbarcode-value="${b.barcode_serial}" jsbarcode-textmargin="0" jsbarcode-fontoptions="bold" jsbarcode-height="40" jsbarcode-width="2" jsbarcode-displayValue="true" jsbarcode-fontSize="11"></svg></div>`).join('');
        win.document.write(`<html><head><title>Print Labels</title><script src="https://cdn.jsdelivr.net/npm/jsbarcode@3.11.5/dist/JsBarcode.all.min.js"></script><style>@page { size: A4; margin: 10mm; } body { margin: 0; font-family: sans-serif; } .grid { display: grid; grid-template-columns: repeat(3, 1fr); grid-auto-rows: 35mm; column-gap: 5mm; row-gap: 2mm; } .label { border: 1px dashed #ddd; display: flex; flex-direction: column; align-items: center; justify-content: center; padding: 5px; overflow: hidden; text-align: center; background: white; } .header { font-size: 10px; font-weight: bold; text-transform: uppercase; margin: 2px; } .meta { font-size: 10px; margin-bottom: 2px; color: #333; } svg { max-width: 95%; height: auto; display: block; }</style></head><body><div class="grid">${labelsHtml}</div><script>window.onload = function() { JsBarcode(".barcode").init(); setTimeout(() => { window.print(); }, 500); }</script></body></html>`); 
        win.document.close();
    }
  };

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (order: Order, linkedStyle: Style): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = order.size_format === 'numeric' ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + ( (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0) ), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global Requirement",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const handlePrintMaterialForecast = async (order: Order) => {
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (!styleRefPart) return;

    const style = await fetchStyleByNumber(styleRefPart);
    if (!style) return;

    const detailedReqs = getDetailedRequirements(order, style);
    if (detailedReqs.length === 0) return alert("No projected requirements found in linked Tech Pack.");

    const formattedNo = formatOrderNumber(order);
    const win = window.open('', 'MaterialForecast', 'width=1000,height=800');
    if (win) {
      win.document.write(`
        <html><head><title>Material Forecast - ${formattedNo}</title>
        <style>
          body { font-family: sans-serif; padding: 30px; font-size: 11px; color: #1e293b; }
          .header { text-align: center; border-bottom: 3px solid #000; padding-bottom: 10px; margin-bottom: 20px; }
          .brand { font-size: 22px; font-weight: 900; }
          .title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-top: 5px; color: #64748b; letter-spacing: 1px; }
          .meta { margin-bottom: 20px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; background: #f8fafc; padding: 12px; border: 1px solid #e2e8f0; border-radius: 6px; }
          .meta-item { font-size: 12px; font-weight: bold; }
          .section { margin-bottom: 20px; border: 1px solid #e2e8f0; border-radius: 8px; overflow: hidden; page-break-inside: avoid; }
          .section-header { background: #4f46e5; color: #fff; padding: 8px 12px; font-weight: 900; font-size: 12px; display: flex; justify-content: space-between; align-items: center; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #e2e8f0; padding: 6px 10px; text-align: left; vertical-align: top; }
          th { background: #f1f5f9; font-size: 9px; text-transform: uppercase; color: #64748b; }
          .val { font-weight: 900; font-size: 13px; color: #4f46e5; }
          .img-grid { display: grid; grid-template-columns: repeat(4, 1fr); gap: 8px; margin-top: 5px; }
          .img-grid img { width: 100%; border-radius: 4px; border: 1px solid #e2e8f0; max-height: 120px; object-fit: contain; }
          .footer { margin-top: 30px; text-align: center; font-size: 9px; color: #94a3b8; border-top: 1px solid #e2e8f0; padding-top: 15px; }
        </style>
        </head><body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Projected Material Requirements Forecast</div>
          </div>
          <div class="meta">
            <div class="meta-item"><small style="color:#64748b; text-transform:uppercase; display:block;">Job No:</small>${formattedNo}</div>
            <div class="meta-item"><small style="color:#64748b; text-transform:uppercase; display:block;">Style:</small>${order.style_number}</div>
            <div class="meta-item"><small style="color:#64748b; text-transform:uppercase; display:block;">Batch:</small>${order.quantity} PCS</div>
            <div class="meta-item"><small style="color:#64748b; text-transform:uppercase; display:block;">Generated:</small>${new Date().toLocaleDateString()}</div>
          </div>
          ${detailedReqs.map(req => `
            <div class="section">
              <div class="section-header">
                <span>${req.name}</span>
                <span style="background:rgba(255,255,255,0.2); padding:2px 8px; border-radius:4px;">TOTAL: ${req.total}</span>
              </div>
              <table>
                <thead>
                  <tr>
                    <th width="140">Segment Scope</th>
                    <th width="70" style="text-align:center">Base Qty</th>
                    <th width="90" style="text-align:right">Calculated Req.</th>
                    <th>Reference & Visuals</th>
                  </tr>
                </thead>
                <tbody>
                  ${req.breakdown.map(b => `
                    <tr>
                      <td style="font-weight:bold; color:#334155;">${b.label}</td>
                      <td style="text-align:center; color:#64748b;">${b.count}</td>
                      <td style="text-align:right" class="val">${b.calc}</td>
                      <td>
                        <div style="font-size:12px; font-weight:bold; margin-bottom:5px;">${b.text || '---'}</div>
                        <div class="img-grid">${b.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}"/>`).join('')}</div>
                      </td>
                    </tr>
                  `).join('')}
                </tbody>
              </table>
            </div>
          `).join('')}
          <div class="footer">Document generated via Tintura SST ERP. All quantities are estimates based on technical ratios.</div>
          <script>window.onload = () => { window.print(); };</script>
        </body></html>
      `);
      win.document.close();
    }
  };

  const handlePrintAccessoriesReceipt = (order: Order, reqs: MaterialRequest[]) => {
      const formattedNo = formatOrderNumber(order);
      const win = window.open('', 'OrderReceipt', 'width=1000,height=800');
      if (win) {
          const page1Rows = reqs.map((req, idx) => `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:center;">${req.unit || 'Nos'}</td><td style="text-align:right; font-weight:bold;">${req.quantity_requested}</td></tr>`).join('');
          const page2Rows = reqs.map((req, idx) => {
              const balance = req.quantity_requested - req.quantity_approved;
              return `<tr><td style="text-align:center;">${idx + 1}</td><td>${req.material_content}</td><td style="text-align:right;">${req.quantity_requested}</td><td style="text-align:right; font-weight:bold; color:green;">${req.quantity_approved}</td><td style="text-align:right; font-weight:bold; color:${balance > 0 ? 'red' : 'black'};">${balance}</td><td style="text-align:center; font-size:10px; text-transform:uppercase;">${req.status.replace('_', ' ')}</td></tr>`;
          }).join('');
          const headerHTML = `<div class="header"><div class="brand">TINTURA SST</div><div class="title">ACCESSORIES REQUIREMENT RECEIPT</div><div class="meta">ORDER NO: ${formattedNo} &nbsp;|&nbsp; STYLE: ${order.style_number} &nbsp;|&nbsp; DATE: ${new Date().toLocaleDateString()}</div></div>`;
          win.document.write(`<html><head><title>Accessories Receipt - ${formattedNo}</title><style>@media print { .page-break { page-break-before: always; } body { -webkit-print-color-adjust: exact; } } body { font-family: 'Arial', sans-serif; padding: 40px; color: #333; } .header { text-align: center; border-bottom: 3px solid #000; margin-bottom: 25px; padding-bottom: 15px; } .brand { font-size: 24px; font-weight: 900; margin-bottom: 5px; letter-spacing: 1px; } .title { font-size: 20px; font-weight: bold; text-transform: uppercase; margin-bottom: 15px; } .meta { font-size: 16px; font-weight: 800; background: #eee; padding: 10px; border: 1px solid #000; text-align: center; } .page-title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-bottom: 10px; text-align:left; border-left: 5px solid #000; padding-left: 10px; } table { width: 100%; border-collapse: collapse; font-size: 12px; margin-bottom: 20px; } th, td { border: 1px solid #ccc; padding: 8px; } th { background: #f4f4f4; text-transform: uppercase; }</style></head><body>${headerHTML}<div class="page-title">Page 1: Request Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80">Unit</th><th width="100" style="text-align:right">Total Requested</th></tr></thead><tbody>${page1Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Verified By Production --</div><div class="page-break"></div>${headerHTML}<div class="page-title">Page 2: Approval & Balance Sheet</div><table><thead><tr><th width="50">S.No</th><th>Material Description</th><th width="80" style="text-align:right">Req</th><th width="80" style="text-align:right">Approved</th><th width="80" style="text-align:right">Balance</th><th width="100">Status</th></tr></thead><tbody>${page2Rows}</tbody></table><div style="text-align:center; font-size:10px; margin-top:20px;">-- Approved By Materials Dept --</div><script>window.onload = () => { setTimeout(() => window.print(), 500); };</script></body></html>`);
          win.document.close();
      }
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col xl:flex-row xl:justify-between xl:items-center gap-4">
        <div>
            <h2 className="text-3xl font-black text-slate-800 flex items-center gap-3">
              <div className="p-2 bg-indigo-600 text-white rounded-xl shadow-lg shadow-indigo-200">
                <Box size={28}/> 
              </div>
              Sub-Unit Operations
            </h2>
            <div className="mt-2 flex items-center gap-2">
              <div className="bg-indigo-50 text-indigo-800 text-xs font-bold px-3 py-1 rounded-full border border-indigo-100 uppercase tracking-widest">
                Unit ID: {CURRENT_UNIT_ID}
              </div>
              <div className="bg-slate-100 text-slate-500 text-[10px] font-bold px-3 py-1 rounded-full border border-slate-200 uppercase tracking-widest">
                Sewing Section A
              </div>
            </div>
        </div>
        <div className="flex flex-col md:flex-row gap-3 items-center">
            <div className="relative w-full md:w-80">
                <input type="text" placeholder="Search by Order # or Style..." className="pl-11 pr-4 py-3 border border-slate-300 rounded-xl text-sm focus:ring-2 focus:ring-indigo-500 outline-none w-full bg-white text-slate-900 shadow-sm transition-all" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
                <Search className="absolute left-4 top-3.5 text-slate-400" size={18} />
            </div>
            <button onClick={handleOpenMaterialHistory} className="bg-white border border-slate-200 text-slate-700 px-5 py-3 rounded-xl flex items-center gap-2 font-bold hover:bg-slate-50 shadow-sm transition-all active:scale-95"><Archive size={20} className="text-indigo-600"/><span>Req History</span></button>
            <div className="bg-white p-1.5 rounded-xl border border-slate-200 shadow-sm flex gap-1">
                <button onClick={() => setActiveTab('active')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'active' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><ListTodo size={18}/> Active</button>
                <button onClick={() => setActiveTab('history')} className={`flex items-center gap-2 px-6 py-2.5 rounded-lg text-sm font-bold transition-all ${activeTab === 'history' ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-500 hover:bg-slate-50'}`}><History size={18}/> Completed</button>
            </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-xl shadow-slate-200/50 border border-slate-200 overflow-hidden">
        {displayedOrders.length === 0 ? (
            <div className="p-20 text-center">
              <Info size={48} className="mx-auto text-slate-200 mb-4" />
              <p className="text-slate-400 text-lg font-medium">No production orders found in this section.</p>
            </div>
        ) : (
            <table className="w-full text-left">
            <thead className="bg-slate-50 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b">
                <tr><th className="p-5 w-12"></th><th className="p-5">Order Reference</th><th className="p-5">Style & Quantity</th><th className="p-5">Production Progress</th><th className="p-5 text-right">Actions</th></tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
                {displayedOrders.map(order => {
                const canAdvance = order.status !== OrderStatus.QC && order.status !== OrderStatus.COMPLETED;
                const isReadyToComplete = order.status === OrderStatus.QC_APPROVED;
                const isCompleted = order.status === OrderStatus.COMPLETED;
                const formattedOrderNo = formatOrderNumber(order);
                return (
                    <tr key={order.id} className={`hover:bg-slate-50/80 transition-colors group ${selectedOrders.includes(order.id) ? 'bg-indigo-50/50' : ''} cursor-pointer`} onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }}>
                    <td className="p-5" onClick={e => e.stopPropagation()}>
                        {!isCompleted && <input type="checkbox" disabled={!canAdvance || isReadyToComplete} checked={selectedOrders.includes(order.id)} onChange={() => toggleSelect(order.id)} className="w-5 h-5 text-indigo-600 rounded-lg border-slate-300 focus:ring-indigo-500 disabled:opacity-30 cursor-pointer" />}
                    </td>
                    <td className="p-5">
                        <div className="font-black text-xl text-slate-800 group-hover:text-indigo-600 transition-colors">{formattedOrderNo}</div>
                        <div className="text-xs font-bold text-slate-400 flex items-center gap-1.5 mt-1">
                          <Clock size={12}/> Due: {order.target_delivery_date}
                        </div>
                    </td>
                    <td className="p-5">
                        <div className="text-base font-bold text-slate-700">{order.style_number}</div>
                        <div className="text-xs font-black text-indigo-500 bg-indigo-50 px-2 py-0.5 rounded-md inline-block mt-1 uppercase tracking-tighter">Target: {order.quantity} pcs ({order.box_count || '---'} Boxes)</div>
                    </td>
                    <td className="p-5">
                        <StatusBadge status={order.status} />
                        {order.qc_notes && (
                          <div className="mt-2 p-2 bg-red-50 rounded-lg border border-red-100">
                            <div className="text-[10px] font-black text-red-600 uppercase flex items-center gap-1 mb-0.5"><AlertTriangle size={12}/> QC Feedback</div>
                            <div className="text-xs text-red-700 font-medium line-clamp-1">{order.qc_notes}</div>
                          </div>
                        )}
                    </td>
                    <td className="p-5 text-right flex justify-end gap-3 items-center flex-wrap" onClick={e => e.stopPropagation()}>
                        <button onClick={() => { setUseNumericSizes(order.size_format === 'numeric'); setDetailsModal(order); }} className="p-2.5 bg-white hover:bg-slate-100 text-slate-600 rounded-xl border border-slate-200 shadow-sm transition-all active:scale-90" title="View Detail"><Eye size={20}/></button>
                        <button onClick={() => handleSendMaterialEmail(order.id)} disabled={emailLoading === order.id} className="p-2.5 bg-orange-50 hover:bg-orange-100 text-orange-600 rounded-xl border border-orange-200 shadow-sm transition-all active:scale-90" title="Email Req List">{emailLoading === order.id ? <Loader2 size={20} className="animate-spin" /> : <Mail size={20}/>}</button>
                        {!isCompleted && (
                            <>
                                <button onClick={() => openTimeline(order.id, formattedOrderNo)} className="p-2.5 bg-teal-50 hover:bg-teal-100 text-teal-600 rounded-xl border border-teal-200 transition-all active:scale-90" title="Timeline"><Clock size={20}/></button>
                                <button onClick={() => setBarcodeModal({ orderId: order.id, style: order.style_number })} className="p-2.5 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-xl border border-slate-200 transition-all active:scale-90" title="Barcodes"><Printer size={20}/></button>
                                <button onClick={() => { setIsEditingRequest(null); setMaterialModal(order.id); }} className="p-2.5 bg-blue-50 hover:bg-blue-100 text-blue-600 rounded-xl border border-blue-200 transition-all active:scale-90" title="Requisition"><PackagePlus size={20}/></button>
                                {canAdvance && (
                                    <button onClick={() => handleSingleStatusUpdate(order.id, order.status)} className={`px-5 py-2.5 rounded-xl inline-flex items-center gap-2 shadow-lg font-black text-sm uppercase tracking-wider text-white transition-all active:scale-95 ${isReadyToComplete ? 'bg-green-600 hover:bg-green-700' : 'bg-indigo-600 hover:bg-indigo-700'}`}>
                                        {isReadyToComplete ? <><CheckCircle2 size={18} /><span>Finalize</span></> : <><ArrowRight size={18} /><span>Advance</span></>}
                                    </button>
                                )}
                            </>
                        )}
                    </td>
                    </tr>
                );
                })}
            </tbody>
            </table>
        )}
      </div>

      {activeTab === 'active' && <BulkActionToolbar selectedCount={selectedOrders.length} actions={[{ label: 'Advance Status', onClick: handleBulkStatusUpdate }]} />}

      {detailsModal && (
        <OrderDetailsModal 
          order={detailsModal} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onClose={() => setDetailsModal(null)} 
          onPrint={() => setJobSheetPreview(detailsModal)} 
          onPrintMaterials={() => handlePrintMaterialForecast(detailsModal)}
        />
      )}

      {timelineModal && (
        <TimelineModal 
          orderNo={timelineModal.orderNo} 
          logs={timelineLogs} 
          statusUpdateText={statusUpdateText} 
          setStatusUpdateText={setStatusUpdateText} 
          onSubmitLog={submitManualStatusUpdate} 
          onClose={() => setTimelineModal(null)} 
        />
      )}

      {completionModal && completionForm && (
        <CompletionModal 
          order={completionModal} 
          form={completionForm} 
          useNumericSizes={useNumericSizes} 
          onToggleSizeFormat={() => setUseNumericSizes(!useNumericSizes)} 
          onUpdateRow={(idx, field, val) => {
            const updated = [...completionForm.breakdown];
            updated[idx] = { ...updated[idx], [field]: val };
            setCompletionForm({ ...completionForm, breakdown: updated });
          }} 
          onUpdateBoxCount={(count) => setCompletionForm({ ...completionForm, actualBoxCount: count })} 
          onSubmit={handleCompleteOrder} 
          onClose={() => setCompletionModal(null)} 
        />
      )}

      {barcodeModal && (
        <BarcodeModal 
          orderId={barcodeModal.orderId} 
          style={barcodeModal.style} 
          onGenerate={handleGenerateAndPrintBarcodes} 
          onClose={() => setBarcodeModal(null)} 
          sizeOptions={useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL']} 
        />
      )}

      {showMaterialHistory && (
        <MaterialHistoryModal 
          history={materialHistory} 
          orders={orders} 
          onClose={() => setShowMaterialHistory(false)} 
          onAddNew={(orderId) => { setIsEditingRequest(null); setMaterialModal(orderId); setShowMaterialHistory(false); }} 
          onEdit={handleEditRequest} 
          onDelete={handleDeleteRequest} 
          onPrint={handlePrintAccessoriesReceipt} 
        />
      )}

      {materialModal && (
        <MaterialRequestModal 
          orderId={materialModal} 
          orderNo={orders.find(o => o.id === materialModal) ? formatOrderNumber(orders.find(o => o.id === materialModal)!) : ''} 
          orders={orders} 
          onClose={() => setMaterialModal(null)} 
          isEditingRequest={isEditingRequest} 
          useNumericSizes={useNumericSizes} 
          onRefresh={refreshOrders} 
        />
      )}

      {jobSheetPreview && (
        <JobSheetPreviewModal 
          order={jobSheetPreview}
          onClose={() => setJobSheetPreview(null)}
        />
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { X, Pencil, Trash2, Printer, Save, Loader2, Clock, Paperclip, Box, Image as ImageIcon, FileText, Download, ArrowLeftRight, Upload, BookOpen, Calculator, ExternalLink } from 'lucide-react';
import { Order, Unit, OrderLog, SizeBreakdown, Attachment, OrderStatus, formatOrderNumber, Style, StyleTemplate, ConsumptionType } from '../../types';
import { fetchOrderLogs, updateOrderDetails, deleteOrder, triggerOrderEmail, uploadOrderAttachment, fetchStyleByNumber, fetchStyleTemplate } from '../../services/db';
import { JobSheetPreviewModal } from '../JobSheetPreviewModal';

interface RequirementDetail {
  label: string;
  count: number;
  calc: number;
  text: string;
  attachments: Attachment[];
}

interface DetailedRequirement {
  name: string;
  total: number;
  breakdown: RequirementDetail[];
}

interface AdminOrderDetailsModalProps {
  order: Order;
  units: Unit[];
  onClose: () => void;
  onRefresh: () => void;
}

export const AdminOrderDetailsModal: React.FC<AdminOrderDetailsModalProps> = ({ order, units, onClose, onRefresh }) => {
  const [isEditing, setIsEditing] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const [editFormData, setEditFormData] = useState<Partial<Order>>({ ...order });
  const [modalLogs, setModalLogs] = useState<OrderLog[]>([]);
  const [useNumericSizes, setUseNumericSizes] = useState(order.size_format === 'numeric');
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [linkedStyle, setLinkedStyle] = useState<Style | null>(null);
  const [jobSheetPreview, setJobSheetPreview] = useState<Order | null>(null);

  useEffect(() => {
    fetchOrderLogs(order.id).then(setModalLogs);
    const styleRefPart = order.style_number.split(' - ')[0].trim();
    if (styleRefPart) {
        fetchStyleByNumber(styleRefPart).then(setLinkedStyle);
    }
  }, [order.id, order.style_number]);

  const getRowTotal = (row: SizeBreakdown) => (row.s || 0) + (row.m || 0) + (row.l || 0) + (row.xl || 0) + (row.xxl || 0) + (row.xxxl || 0);
  const getTotalQuantity = (bd: SizeBreakdown[]) => bd.reduce((acc, row) => acc + getRowTotal(row), 0);
  const getHeaderLabels = () => useNumericSizes ? ['65', '70', '75', '80', '85', '90'] : ['S', 'M', 'L', 'XL', 'XXL', '3XL'];

  const calculateRequirementValue = (qty: number, type: ConsumptionType, val: number) => {
    if (!val) return 0;
    return type === 'items_per_pc' ? qty * val : qty / val;
  };

  const getDetailedRequirements = (): DetailedRequirement[] => {
    if (!linkedStyle || !order.size_breakdown) return [];

    const detailedReqs: DetailedRequirement[] = [];
    const sizeKeys = ['s', 'm', 'l', 'xl', 'xxl', 'xxxl'] as const;
    const sizeLabels = getHeaderLabels();

    for (const catName in linkedStyle.tech_pack) {
      for (const fieldName in linkedStyle.tech_pack[catName]) {
        const item = linkedStyle.tech_pack[catName][fieldName];
        const req: DetailedRequirement = { name: fieldName, total: 0, breakdown: [] };

        if (item.variants) {
          for (const variant of item.variants) {
            const matchingRows = order.size_breakdown.filter(r => variant.colors.includes(r.color));
            if (matchingRows.length === 0) continue;

            if (variant.sizeVariants) {
              for (const sv of variant.sizeVariants) {
                const targetKeys = sizeKeys.filter((_, i) => sv.sizes.includes(sizeLabels[i]));
                const qty = matchingRows.reduce((sum, row) => sum + targetKeys.reduce((s, k) => s + (row[k] || 0), 0), 0);

                if (qty > 0) {
                  const rType = sv.consumption_type || variant.consumption_type || item.consumption_type || 'items_per_pc';
                  const rVal = sv.consumption_val !== undefined ? sv.consumption_val : (variant.consumption_val !== undefined ? variant.consumption_val : (item.consumption_val || 0));
                  const calc = calculateRequirementValue(qty, rType, rVal);

                  req.breakdown.push({
                    label: `${variant.colors.join('/')} - ${sv.sizes.join('/')}`,
                    count: qty,
                    calc: Math.ceil(calc * 100) / 100,
                    text: sv.text || variant.text || item.text,
                    attachments: sv.attachments.length > 0 ? sv.attachments : (variant.attachments.length > 0 ? variant.attachments : item.attachments)
                  });
                  req.total += calc;
                }
              }
            } else if (variant.consumption_type) {
              const qty = matchingRows.reduce((sum, row) => sum + getRowTotal(row), 0);
              const calc = calculateRequirementValue(qty, variant.consumption_type, variant.consumption_val || 0);
              req.breakdown.push({
                label: `Color: ${variant.colors.join('/')}`,
                count: qty,
                calc: Math.ceil(calc * 100) / 100,
                text: variant.text || item.text,
                attachments: variant.attachments.length > 0 ? variant.attachments : item.attachments
              });
              req.total += calc;
            }
          }
        } else if (item.consumption_type) {
          const calc = calculateRequirementValue(order.quantity, item.consumption_type, item.consumption_val || 0);
          req.breakdown.push({
            label: "Global (All Colors/Sizes)",
            count: order.quantity,
            calc: Math.ceil(calc * 100) / 100,
            text: item.text,
            attachments: item.attachments
          });
          req.total = calc;
        }

        if (req.total > 0) {
          req.total = Math.ceil(req.total * 100) / 100;
          detailedReqs.push(req);
        }
      }
    }
    return detailedReqs;
  };

  const handleSave = async () => {
    setIsUploading(true);
    try {
      const newAttachments: Attachment[] = [];
      for (const file of selectedFiles) {
        const url = await uploadOrderAttachment(file);
        if (url) newAttachments.push({ name: file.name, url, type: file.type.startsWith('image/') ? 'image' : 'document' });
      }
      const finalAttachments = [...(editFormData.attachments || []), ...newAttachments];
      const finalQty = getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]);
      const result = await updateOrderDetails(order.id, { ...editFormData, quantity: finalQty, attachments: finalAttachments, size_format: useNumericSizes ? 'numeric' : 'standard' });
      if (result.success) {
        await triggerOrderEmail(order.id, true);
        onRefresh();
        onClose();
      }
    } finally {
      setIsUploading(false);
    }
  };

  const handlePrintMaterialForecast = () => {
    const detailedReqs = getDetailedRequirements();
    if (detailedReqs.length === 0) return alert("No projected requirements found.");

    const formattedNo = formatOrderNumber(order);
    const win = window.open('', 'MaterialForecast', 'width=1000,height=800');
    if (win) {
      win.document.write(`
        <html><head><title>Forecast - ${formattedNo}</title>
        <style>
          body { font-family: sans-serif; padding: 30px; font-size: 11px; color: #1e293b; }
          .header { text-align: center; border-bottom: 3px solid #000; padding-bottom: 10px; margin-bottom: 20px; }
          .brand { font-size: 22px; font-weight: 900; }
          .title { font-size: 14px; font-weight: bold; text-transform: uppercase; margin-top: 5px; color:#64748b; letter-spacing:1px; }
          .meta { margin-bottom: 20px; display: grid; grid-template-columns: repeat(4, 1fr); gap: 10px; background: #f8fafc; padding: 12px; border: 1px solid #e2e8f0; border-radius: 6px; }
          .section { margin-bottom: 20px; border: 1px solid #cbd5e1; border-radius: 8px; overflow: hidden; page-break-inside: avoid; }
          .section-header { background: #334155; color: #fff; padding: 8px 12px; font-weight: bold; font-size: 12px; display: flex; justify-content: space-between; align-items: center; }
          table { width: 100%; border-collapse: collapse; }
          th, td { border: 1px solid #cbd5e1; padding: 6px 10px; text-align: left; vertical-align: top; }
          th { background: #f1f5f9; text-transform: uppercase; font-size: 9px; color: #64748b; }
          .qty-val { font-weight: 900; color: #4f46e5; font-size: 13px; }
          .img-grid { display: flex; flex-wrap: wrap; gap: 5px; margin-top: 5px; }
          .img-grid img { height: 60px; border-radius: 3px; border: 1px solid #ddd; }
          .footer { margin-top: 30px; text-align: center; font-size: 9px; color: #94a3b8; border-top: 1px solid #e2e8f0; padding-top: 15px; }
        </style>
        </head><body>
          <div class="header">
            <div class="brand">TINTURA SST</div>
            <div class="title">Projected Material Requirements Forecast</div>
          </div>
          <div class="meta">
            <div><strong>Order:</strong> ${formattedNo}</div>
            <div><strong>Style:</strong> ${order.style_number}</div>
            <div><strong>Batch:</strong> ${order.quantity} PCS</div>
            <div><strong>Date:</strong> ${new Date().toLocaleDateString()}</div>
          </div>
          ${detailedReqs.map(req => `
            <div class="section">
              <div class="section-header"><span>${req.name}</span><span style="background:rgba(255,255,255,0.2); padding:2px 8px; border-radius:4px;">TOTAL JOB REQ: ${req.total}</span></div>
              <table>
                <thead><tr><th>Segment Scope</th><th style="text-align:center">Base Qty</th><th style="text-align:right">Calculated Req.</th><th>Instructions & Visuals</th></tr></thead>
                <tbody>${req.breakdown.map(b => `
                  <tr>
                    <td><strong>${b.label}</strong></td>
                    <td style="text-align:center">${b.count}</td>
                    <td style="text-align:right" class="qty-val">${b.calc}</td>
                    <td>
                        <div style="font-weight:bold; margin-bottom:4px;">${b.text || '---'}</div>
                        <div class="img-grid">${b.attachments.filter(a => a.type === 'image').map(img => `<img src="${img.url}"/>`).join('')}</div>
                    </td>
                  </tr>`).join('')}
                </tbody>
              </table>
            </div>
          `).join('')}
          <div class="footer">Document generated via Tintura SST MES. Estimates are for internal production planning only.</div>
          <script>window.onload = () => { window.print(); };</script>
        </body></html>
      `);
      win.document.close();
    }
  };

  const detailedReqs = getDetailedRequirements();

  return (
    <div className="fixed inset-0 bg-slate-900/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm">
      <div className="bg-white rounded-2xl shadow-2xl w-full max-w-6xl overflow-hidden flex flex-col max-h-[95vh] animate-scale-up border border-slate-200">
        <div className="p-6 border-b flex justify-between items-start bg-white"><div><h3 className="text-3xl font-black text-slate-800 tracking-tight">{formatOrderNumber(order)}</h3></div><div className="flex items-center gap-3">{!isEditing && <button onClick={() => setIsEditing(true)} className="bg-indigo-50 text-indigo-700 border border-indigo-100 px-5 py-2.5 rounded-xl text-sm font-black hover:bg-indigo-600 hover:text-white transition-all"><Pencil size={18} /> Modify Order</button>}<button onClick={onClose} className="text-slate-300 hover:text-slate-600 p-2 hover:bg-slate-100 rounded-full"><X size={32}/></button></div></div>
        <div className="flex-1 overflow-y-auto p-8 space-y-8 bg-slate-50/20">
          <div className="bg-indigo-50 p-4 rounded-xl border border-indigo-100 flex items-center gap-3"><BookOpen size={20} className="text-indigo-600"/><div><p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest leading-none">Style DB Synchronized</p><p className="text-sm font-bold text-indigo-900 mt-1">Granular material forecasts calculated based on color and size specific ratios.</p></div></div>

          <div className="grid grid-cols-2 md:grid-cols-4 gap-6"><div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Volume</span><div className="text-2xl font-black text-slate-800">{isEditing ? getTotalQuantity(editFormData.size_breakdown as SizeBreakdown[]) : order.quantity} PCS</div></div><div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2">Delivery</span>{isEditing ? <input type="date" className="w-full border rounded p-2" value={editFormData.target_delivery_date} onChange={e => setEditFormData({...editFormData, target_delivery_date: e.target.value})}/> : <div className="text-lg font-black">{order.target_delivery_date}</div>}</div><div className="p-5 bg-white rounded-2xl border border-slate-100 shadow-sm"><span className="block text-[10px] text-slate-400 uppercase font-black mb-2"><Box size={10}/> Planned Boxes</span>{isEditing ? <input type="number" className="w-full border rounded p-2" value={editFormData.box_count} onChange={e => setEditFormData({...editFormData, box_count: parseInt(e.target.value) || 0})}/> : <div className="text-lg font-black">{order.box_count}</div>}</div><div className="p-5 bg-indigo-50 rounded-2xl border border-indigo-100 shadow-sm"><span className="block text-[10px] text-indigo-400 uppercase font-black mb-2">Unit</span>{isEditing ? <select className="w-full border rounded p-2 bg-white font-bold" value={editFormData.unit_id} onChange={e => setEditFormData({...editFormData, unit_id: parseInt(e.target.value)})}>{units.map(u => <option key={u.id} value={u.id}>{u.name}</option>)}</select> : <div className="text-lg font-black text-indigo-900">{units.find(u => u.id === order.unit_id)?.name}</div>}</div></div>

          {/* GRANULAR REQUIREMENTS FORECAST SECTION */}
          {detailedReqs.length > 0 && (
            <div className="space-y-4 animate-fade-in">
              <div className="flex items-center gap-3">
                <Calculator size={20} className="text-indigo-600"/>
                <h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Granular Material Forecast</h4>
              </div>
              <div className="grid grid-cols-1 gap-6">
                {detailedReqs.map((req, i) => (
                  <div key={i} className="bg-white rounded-3xl border border-indigo-100 shadow-sm overflow-hidden group">
                    <div className="p-5 bg-indigo-600 text-white flex items-center justify-between">
                      <span className="font-black uppercase tracking-widest text-sm">{req.name}</span>
                      <div className="flex items-center gap-4">
                         <span className="text-[10px] font-bold opacity-60 uppercase">Calculated Job Total</span>
                         <span className="text-xl font-black">{req.total}</span>
                      </div>
                    </div>
                    <div className="p-6">
                      <div className="grid grid-cols-1 xl:grid-cols-2 gap-4">
                        {req.breakdown.map((b, idx) => (
                          <div key={idx} className="p-4 bg-slate-50 rounded-2xl border border-slate-200 space-y-3 hover:border-indigo-300 transition-colors">
                            <div className="flex justify-between items-start">
                              <div>
                                <span className="text-[9px] font-black text-indigo-500 uppercase tracking-widest block mb-1">{b.label}</span>
                                <span className="text-xs font-bold text-slate-500">Volume: {b.count} Pcs</span>
                              </div>
                              <div className="text-right">
                                <span className="text-xl font-black text-indigo-700">{b.calc}</span>
                                <span className="text-[8px] block font-black text-slate-400 uppercase">Estimated</span>
                              </div>
                            </div>

                            <div className="p-3 bg-white rounded-xl border border-slate-100">
                               <p className="text-xs font-bold text-slate-700 leading-relaxed italic">"{b.text || 'No specific notes.'}"</p>
                               {b.attachments.length > 0 && (
                                 <div className="mt-3 flex flex-wrap gap-2">
                                    {b.attachments.map((att, attIdx) => (
                                      <a key={attIdx} href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-1.5 px-2 py-1 bg-indigo-50 text-indigo-600 rounded-lg text-[9px] font-black border border-indigo-100 hover:bg-indigo-100 transition-all">
                                        {att.type === 'image' ? <ImageIcon size={10}/> : <FileText size={10}/>} {att.name}
                                      </a>
                                    ))}
                                 </div>
                               )}
                            </div>
                          </div>
                        ))}
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}

          <div><div className="flex justify-between items-center mb-4"><h4 className="font-black text-slate-700 uppercase tracking-tight text-lg">Product breakdown matrix</h4>{isEditing && <button type="button" onClick={() => setUseNumericSizes(!useNumericSizes)} className="text-[10px] bg-slate-100 px-4 py-2 rounded-xl border border-slate-200 font-black uppercase"><ArrowLeftRight size={14} className="inline mr-2"/> Switch Size Format</button>}</div><div className="border border-slate-200 rounded-3xl overflow-hidden shadow-sm bg-white"><table className="w-full text-center text-sm border-collapse"><thead className="bg-slate-50 text-slate-500 font-black uppercase text-[10px] tracking-widest border-b"><tr><th className="p-4 text-left border-r">Color Variant</th>{getHeaderLabels().map(h => <th key={h} className="p-4 border-r">{h}</th>)}<th className="p-4 bg-slate-100">Sum</th>{isEditing && <th className="p-4 w-12"></th>}</tr></thead><tbody className="divide-y divide-slate-100">{(isEditing ? editFormData.size_breakdown : order.size_breakdown)?.map((row, idx) => (<tr key={idx} className="hover:bg-slate-50/50 transition-colors"><td className="p-4 text-left font-black text-slate-700 border-r">{isEditing ? <input className="w-full border rounded p-1 font-bold" value={row.color} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; bd[idx].color = e.target.value; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : row.color}</td>{['s','m','l','xl','xxl','xxxl'].map(key => (<td key={key} className="p-4 border-r">{isEditing ? <input type="number" className="w-16 border rounded p-1 text-center font-black" value={(row as any)[key]} onChange={e => { const bd = [...(editFormData.size_breakdown || [])]; (bd[idx] as any)[key] = parseInt(e.target.value) || 0; setEditFormData({...editFormData, size_breakdown: bd}); }}/> : (order.size_breakdown?.[idx]?.[key as keyof SizeBreakdown] || 0)}</td>))}<td className="p-4 font-black text-slate-900 bg-slate-50/50 tabular-nums">{getRowTotal(row)}</td>{isEditing && <td className="p-4"><button onClick={() => setEditFormData({...editFormData, size_breakdown: (editFormData.size_breakdown || []).filter((_, i) => i !== idx)})} className="text-red-400 hover:text-red-600 transition-colors"><Trash2 size={20}/></button></td>}</tr>))}</tbody></table>{isEditing && <button onClick={() => setEditFormData({...editFormData, size_breakdown: [...(editFormData.size_breakdown || []), { color: '', s: 0, m: 0, l: 0, xl: 0, xxl: 0, xxxl: 0 }]})} className="w-full py-4 bg-slate-50 text-indigo-600 text-xs font-black uppercase border-t hover:bg-indigo-50 transition-colors">+ Add Color Variant</button>}</div></div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-8"><div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm"><span className="block text-[11px] text-slate-400 uppercase font-black mb-3">Master production notes</span>{isEditing ? <textarea className="w-full border border-slate-200 rounded-2xl p-4 h-48 font-medium" value={editFormData.description} onChange={e => setEditFormData({...editFormData, description: e.target.value})}/> : <p className="text-xl text-slate-800 font-black whitespace-pre-wrap leading-relaxed">{order.description || 'N/A'}</p>}</div><div className="p-6 bg-indigo-50/30 rounded-3xl border border-indigo-100 shadow-inner"><h4 className="font-black text-indigo-400 uppercase text-[10px] flex items-center gap-2 mb-4"><Paperclip size={14}/> Technical documents</h4><div className="space-y-3">{(isEditing ? editFormData.attachments : order.attachments)?.map((att, i) => (<div key={i} className="flex items-center justify-between p-4 bg-white rounded-xl border border-indigo-50 group hover:shadow-md transition-all"><a href={att.url} target="_blank" rel="noreferrer" className="flex items-center gap-4 flex-1">{att.type === 'image' ? <ImageIcon size={20} className="text-indigo-400" /> : <FileText size={20} className="text-indigo-400" />}<span className="text-sm font-black text-slate-700 truncate">{att.name}</span></a>{isEditing && <button onClick={() => setEditFormData({...editFormData, attachments: (editFormData.attachments || []).filter((_, idx) => idx !== i)})} className="text-slate-300 hover:text-red-500 transition-colors"><Trash2 size={20}/></button>}</div>))}{isEditing && <div className="mt-4 border-2 border-dashed border-indigo-100 rounded-2xl p-6 text-center relative hover:bg-white transition-all cursor-pointer"><input type="file" multiple className="absolute inset-0 opacity-0 cursor-pointer" onChange={e => e.target.files && setSelectedFiles(prev => [...prev, ...Array.from(e.target.files!)])}/><Upload size={32} className="mx-auto text-indigo-400"/><p className="text-[10px] font-black text-indigo-600 uppercase mt-2 tracking-widest">Add technical files</p></div>}</div></div></div>

          <div className="p-6 bg-white rounded-3xl border border-slate-100 shadow-sm flex flex-col"><h4 className="font-black text-indigo-900 uppercase text-[10px] flex items-center gap-2 mb-6"><Clock size={16}/> Lifecycle status log</h4><div className="space-y-6 max-h-[400px] overflow-y-auto pr-4">{modalLogs.map(log => (<div key={log.id} className="flex gap-4 border-l-4 border-indigo-100 pl-6 pb-2 transition-all hover:border-indigo-400"><div className="font-black text-[10px] text-slate-400 uppercase leading-none pt-1">{new Date(log.created_at).toLocaleDateString()}<br/><span className="text-indigo-400 opacity-60 font-bold">{new Date(log.created_at).toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}</span></div><div className="flex-1 bg-slate-50 p-4 rounded-2xl border border-slate-200"><p className="text-slate-700 font-bold leading-snug">{log.message}</p></div></div>))}</div></div>
        </div>
        <div className="p-6 border-t bg-slate-50 flex justify-between items-center"><button onClick={() => { if(confirm("Permanently delete this order?")) deleteOrder(order.id).then(() => {onRefresh(); onClose();}); }} className="p-3 text-slate-300 hover:text-red-600 hover:bg-red-50 rounded-2xl transition-all"><Trash2 size={24}/></button><div className="flex items-center gap-4">
          <button onClick={handlePrintMaterialForecast} className="px-6 py-3 bg-white text-indigo-600 border border-indigo-600 rounded-xl font-black uppercase text-[10px] flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all">
            <Calculator size={16}/> Print Material Forecast
          </button>
          <button onClick={() => setJobSheetPreview(order)} className="px-8 py-3 bg-white text-indigo-600 border-2 border-indigo-600 rounded-xl font-black uppercase text-xs flex items-center gap-2 shadow-sm hover:bg-indigo-50 transition-all"><Printer size={16}/> Print Job Sheet</button><button onClick={onClose} className="px-10 py-3 bg-slate-800 text-white rounded-xl font-black uppercase text-xs hover:bg-slate-700 transition-all">Close</button>{isEditing && <button onClick={handleSave} disabled={isUploading} className="bg-indigo-600 text-white px-10 py-3 rounded-xl font-black uppercase text-xs shadow-lg shadow-indigo-200 hover:bg-indigo-700 active:scale-95 transition-all">{isUploading ? <Loader2 className="animate-spin inline mr-2" size={16}/> : null}{isUploading ? 'Saving...' : 'Save Job'}</button>}</div></div>
      </div>
      {jobSheetPreview && (
        <JobSheetPreviewModal 
          order={jobSheetPreview}
          onClose={() => setJobSheetPreview(null)}
        />
      )}
    </div>
  );
};
